import React, { useState, useEffect } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon,
  TagIcon 
} from './components/Icons';

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });
  const [view, setView] = useState<ViewState>({ type: 'workouts' });

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  const addWorkout = () => {
    const name = prompt('Workout Name?');
    if (!name) return;
    const newWorkout: Workout = {
      id: Date.now().toString(),
      name,
      exercises: []
    };
    setWorkouts([...workouts, newWorkout]);
  };

  const deleteWorkout = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure?')) return;
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  const addExercise = (workoutId: string) => {
    const name = prompt('Exercise Name?');
    if (!name) return;
    const muscle = prompt('Muscle Group (e.g. Chest, Back, Legs)?');
    const tags = muscle ? [muscle] : [];

    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: [...w.exercises, {
            id: Date.now().toString(),
            name,
            tags,
            entries: []
          }]
        };
      }
      return w;
    }));
  };

  const deleteExercise = (workoutId: string, exerciseId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.filter(ex => ex.id !== exerciseId)
        };
      }
      return w;
    }));
  };

  const addEntry = (workoutId: string, exerciseId: string) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              const lastEntry = ex.entries[ex.entries.length - 1];
              const newEntry: Entry = {
                id: Date.now().toString(),
                date: new Date().toISOString().split('T')[0],
                sets: lastEntry?.sets || 0,
                reps: lastEntry?.reps || 0,
                weight: lastEntry?.weight || 0
              };
              return { ...ex, entries: [...ex.entries, newEntry] };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const updateEntry = (workoutId: string, exerciseId: string, entryId: string, field: keyof Entry, value: string | number) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.map(ent => {
                  if (ent.id === entryId) {
                    return { ...ent, [field]: value };
                  }
                  return ent;
                })
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Remove this performance entry?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.filter(ent => ent.id !== entryId)
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const updateExerciseBasicInfo = (workoutId: string, exerciseId: string, updates: Partial<Pick<Exercise, 'name' | 'tags' | 'notes'>>) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return { ...ex, ...updates };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  // Rendering logic based on view
  const renderWorkouts = () => (
    <div className="max-w-md mx-auto min-h-screen pb-24">
      <header className="px-6 py-10">
        <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Workouts</h1>
        <p className="text-slate-500 mt-2">Manage your training routines</p>
      </header>

      <div className="px-6 space-y-4">
        {workouts.map(w => (
          <div 
            key={w.id}
            onClick={() => setView({ type: 'workout-detail', workoutId: w.id })}
            className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between active:bg-slate-50 transition-colors group cursor-pointer"
          >
            <div>
              <h3 className="font-semibold text-lg text-slate-800">{w.name}</h3>
              <p className="text-sm text-slate-500">{w.exercises.length} exercises</p>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={(e) => deleteWorkout(w.id, e)}
                className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
              >
                <TrashIcon />
              </button>
              <div className="text-indigo-600">
                <ChevronRightIcon />
              </div>
            </div>
          </div>
        ))}

        {workouts.length === 0 && (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-200">
            <p className="text-slate-400">No workouts yet</p>
          </div>
        )}
      </div>

      <div className="fixed bottom-8 right-8 z-50">
        <button 
          onClick={addWorkout}
          className="w-16 h-16 bg-indigo-600 rounded-2xl shadow-xl shadow-indigo-200 text-white flex items-center justify-center hover:bg-indigo-700 transition-all transform hover:scale-105 active:scale-95"
        >
          <PlusIcon />
        </button>
      </div>
    </div>
  );

  const renderWorkoutDetail = (workoutId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    if (!workout) return null;

    return (
      <div className="max-w-md mx-auto min-h-screen pb-24">
        <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50 z-10">
          <button 
            onClick={() => setView({ type: 'workouts' })}
            className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"
          >
            <ChevronLeftIcon />
          </button>
          <div>
            <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
          </div>
        </header>

        <div className="px-6 space-y-3">
          {workout.exercises.map(ex => {
            const lastEntry = ex.entries[ex.entries.length - 1];
            const isAnchor = ex.tags.includes('anchor');

            return (
              <div 
                key={ex.id}
                onClick={() => setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id })}
                className={`bg-white p-5 rounded-2xl border transition-all active:bg-slate-50 cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50/50 shadow-md' : 'border-slate-100 shadow-sm'}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                      {isAnchor && (
                        <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-2 mt-1.5">
                      {ex.tags.map(tag => tag !== 'anchor' && (
                        <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-lg">{tag}</span>
                      ))}
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteExercise(workoutId, ex.id, e)}
                    className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
                  >
                    <TrashIcon />
                  </button>
                </div>

                {lastEntry && (
                  <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2">
                    <span className="text-sm font-medium text-slate-900">
                      {lastEntry.sets}x{lastEntry.reps}
                    </span>
                    <span className="text-sm text-slate-500">at</span>
                    <span className="text-sm font-bold text-indigo-600">{lastEntry.weight}kg</span>
                  </div>
                )}
              </div>
            );
          })}

          <Button 
            variant="secondary" 
            fullWidth 
            onClick={() => addExercise(workoutId)}
            className="mt-6 border-dashed bg-transparent"
          >
            <PlusIcon /> <span className="ml-2">Add Exercise</span>
          </Button>
        </div>
      </div>
    );
  };

  const renderExerciseDetail = (workoutId: string, exerciseId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    const exercise = workout?.exercises.find(e => e.id === exerciseId);
    if (!exercise) return null;

    const lastEntry = exercise.entries[exercise.entries.length - 1];
    const isEditingInfo = false; // Internal flag for UI simulation if needed

    return (
      <div className="max-w-md mx-auto min-h-screen bg-white">
        {/* Header - Top 1/3 Content */}
        <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
          <header className="py-6 flex items-center justify-between -mx-2">
            <button 
              onClick={() => setView({ type: 'workout-detail', workoutId })}
              className="p-2 text-slate-600 hover:bg-white rounded-full transition-colors"
            >
              <ChevronLeftIcon />
            </button>
            <div className="flex gap-2">
              <Button 
                variant="ghost" 
                size="sm"
                onClick={() => {
                  const newName = prompt('Edit name?', exercise.name);
                  if (newName) updateExerciseBasicInfo(workoutId, exerciseId, { name: newName });
                }}
              >
                <EditIcon />
              </Button>
            </div>
          </header>

          <div className="space-y-4">
            <div>
              <h1 className="text-2xl font-bold text-slate-900">{exercise.name}</h1>
              <div className="flex flex-wrap gap-2 mt-2">
                {exercise.tags.map(tag => (
                  <span 
                    key={tag} 
                    className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600'}`}
                  >
                    <TagIcon /> {tag}
                  </span>
                ))}
              </div>
            </div>

            {lastEntry && (
              <div className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 bg-indigo-50 rounded-lg flex items-center justify-center text-indigo-600">
                  <CheckIcon />
                </div>
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Latest PR</p>
                  <p className="text-slate-800 font-semibold">{lastEntry.sets}x{lastEntry.reps} @ {lastEntry.weight}kg</p>
                </div>
              </div>
            )}

            <div className="flex items-start gap-3 text-slate-500">
              <div className="mt-1 flex-shrink-0 text-slate-300">
                <InfoIcon />
              </div>
              <div 
                className="text-sm italic cursor-pointer"
                onClick={() => {
                  const newNotes = prompt('Edit notes?', exercise.notes || '');
                  if (newNotes !== null) updateExerciseBasicInfo(workoutId, exerciseId, { notes: newNotes });
                }}
              >
                {exercise.notes || 'No notes added yet... tap to add.'}
              </div>
            </div>
          </div>
        </div>

        {/* Main Content - Performance Entries */}
        <div className="px-6 py-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-slate-800">History</h2>
            <Button size="sm" onClick={() => addEntry(workoutId, exerciseId)}>
              <PlusIcon /> <span className="ml-1.5">New Log</span>
            </Button>
          </div>

          <div className="overflow-x-auto -mx-6 px-6">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="text-[11px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="pb-3 pr-2">Date</th>
                  <th className="pb-3 px-2">Sets</th>
                  <th className="pb-3 px-2">Reps</th>
                  <th className="pb-3 px-2">Kg</th>
                  <th className="pb-3 pl-2"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {[...exercise.entries].reverse().map(ent => (
                  <tr key={ent.id} className="group">
                    <td className="py-4 pr-2 text-sm text-slate-500 font-medium whitespace-nowrap">
                      {new Date(ent.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                    </td>
                    <td className="py-3 px-1">
                      <input 
                        type="number" 
                        value={ent.sets}
                        onChange={(e) => updateEntry(workoutId, exerciseId, ent.id, 'sets', parseInt(e.target.value) || 0)}
                        className="w-12 bg-slate-50 text-slate-800 border-none rounded-lg p-2 text-center text-sm font-semibold focus:ring-2 focus:ring-indigo-100"
                      />
                    </td>
                    <td className="py-3 px-1">
                      <input 
                        type="number" 
                        value={ent.reps}
                        onChange={(e) => updateEntry(workoutId, exerciseId, ent.id, 'reps', parseInt(e.target.value) || 0)}
                        className="w-12 bg-slate-50 text-slate-800 border-none rounded-lg p-2 text-center text-sm font-semibold focus:ring-2 focus:ring-indigo-100"
                      />
                    </td>
                    <td className="py-3 px-1">
                      <input 
                        type="number" 
                        value={ent.weight}
                        onChange={(e) => updateEntry(workoutId, exerciseId, ent.id, 'weight', parseFloat(e.target.value) || 0)}
                        className="w-16 bg-slate-50 text-slate-800 border-none rounded-lg p-2 text-center text-sm font-semibold focus:ring-2 focus:ring-indigo-100"
                      />
                    </td>
                    <td className="py-4 pl-2 text-right">
                      <button 
                        onClick={() => deleteEntry(workoutId, exerciseId, ent.id)}
                        className="p-1.5 text-slate-200 hover:text-rose-500 transition-colors"
                      >
                        <TrashIcon />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {exercise.entries.length === 0 && (
            <div className="py-12 text-center text-slate-400 space-y-2">
              <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                <PlusIcon />
              </div>
              <p>No training logs yet.</p>
              <p className="text-xs">Start tracking your progress by adding a new log.</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen">
      {view.type === 'workouts' && renderWorkouts()}
      {view.type === 'workout-detail' && renderWorkoutDetail(view.workoutId)}
      {view.type === 'exercise-detail' && renderExerciseDetail(view.workoutId, view.exerciseId)}
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon,
  TagIcon 
} from './components/Icons';

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });
  const [view, setView] = useState<ViewState>({ type: 'workouts' });
  const [isEditingInfo, setIsEditingInfo] = useState(false);
  const [editFields, setEditFields] = useState<{ name: string; notes: string; tags: string[] }>({ name: '', notes: '', tags: [] });
  const [newTag, setNewTag] = useState('');

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  const addWorkout = () => {
    const name = prompt('Workout Name?');
    if (!name) return;
    const newWorkout: Workout = {
      id: Date.now().toString(),
      name,
      exercises: []
    };
    setWorkouts([...workouts, newWorkout]);
  };

  const deleteWorkout = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure?')) return;
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  const addExercise = (workoutId: string) => {
    const name = prompt('Exercise Name?');
    if (!name) return;
    const muscle = prompt('Muscle Group (e.g. Chest, Back, Legs)?');
    const tags = muscle ? [muscle] : [];

    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: [...w.exercises, {
            id: Date.now().toString(),
            name,
            tags,
            entries: []
          }]
        };
      }
      return w;
    }));
  };

  const deleteExercise = (workoutId: string, exerciseId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.filter(ex => ex.id !== exerciseId)
        };
      }
      return w;
    }));
  };

  const addEntry = (workoutId: string, exerciseId: string) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              const lastEntry = ex.entries[ex.entries.length - 1];
              const newEntry: Entry = {
                id: Date.now().toString(),
                date: new Date().toISOString().split('T')[0],
                sets: lastEntry?.sets || 0,
                reps: lastEntry?.reps || 0,
                weight: lastEntry?.weight || 0
              };
              return { ...ex, entries: [...ex.entries, newEntry] };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const updateEntry = (workoutId: string, exerciseId: string, entryId: string, field: keyof Entry, value: string | number) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.map(ent => {
                  if (ent.id === entryId) {
                    return { ...ent, [field]: value };
                  }
                  return ent;
                })
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Remove this performance entry?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.filter(ent => ent.id !== entryId)
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const updateExerciseBasicInfo = (workoutId: string, exerciseId: string, updates: Partial<Pick<Exercise, 'name' | 'tags' | 'notes'>>) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return { ...ex, ...updates };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const startEditingExercise = (exercise: Exercise) => {
    setEditFields({
      name: exercise.name,
      notes: exercise.notes || '',
      tags: [...exercise.tags]
    });
    setIsEditingInfo(true);
  };

  const saveExerciseEdit = (workoutId: string, exerciseId: string) => {
    updateExerciseBasicInfo(workoutId, exerciseId, {
      name: editFields.name,
      notes: editFields.notes,
      tags: editFields.tags
    });
    setIsEditingInfo(false);
  };

  const renderWorkouts = () => (
    <div className="max-w-md mx-auto min-h-screen pb-24">
      <header className="px-6 py-10">
        <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Workouts</h1>
        <p className="text-slate-500 mt-2">Manage your training routines</p>
      </header>

      <div className="px-6 space-y-4">
        {workouts.map(w => (
          <div 
            key={w.id}
            onClick={() => setView({ type: 'workout-detail', workoutId: w.id })}
            className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between active:bg-slate-50 transition-colors group cursor-pointer"
          >
            <div>
              <h3 className="font-semibold text-lg text-slate-800">{w.name}</h3>
              <p className="text-sm text-slate-500">{w.exercises.length} exercises</p>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={(e) => deleteWorkout(w.id, e)}
                className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
              >
                <TrashIcon />
              </button>
              <div className="text-indigo-600">
                <ChevronRightIcon />
              </div>
            </div>
          </div>
        ))}

        {workouts.length === 0 && (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-200">
            <p className="text-slate-400">No workouts yet</p>
          </div>
        )}
      </div>

      <div className="fixed bottom-8 right-8 z-50">
        <button 
          onClick={addWorkout}
          className="w-16 h-16 bg-indigo-600 rounded-2xl shadow-xl shadow-indigo-200 text-white flex items-center justify-center hover:bg-indigo-700 transition-all transform hover:scale-105 active:scale-95"
        >
          <PlusIcon />
        </button>
      </div>
    </div>
  );

  const renderWorkoutDetail = (workoutId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    if (!workout) return null;

    return (
      <div className="max-w-md mx-auto min-h-screen pb-24">
        <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50 z-10">
          <button 
            onClick={() => setView({ type: 'workouts' })}
            className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"
          >
            <ChevronLeftIcon />
          </button>
          <div>
            <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
          </div>
        </header>

        <div className="px-6 space-y-3">
          {workout.exercises.map(ex => {
            const lastEntry = ex.entries[ex.entries.length - 1];
            const isAnchor = ex.tags.includes('anchor');

            return (
              <div 
                key={ex.id}
                onClick={() => {
                    setIsEditingInfo(false);
                    setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id });
                }}
                className={`bg-white p-5 rounded-2xl border transition-all active:bg-slate-50 cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50/50 shadow-md' : 'border-slate-100 shadow-sm'}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                      {isAnchor && (
                        <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-2 mt-1.5">
                      {ex.tags.map(tag => tag !== 'anchor' && (
                        <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-lg">{tag}</span>
                      ))}
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteExercise(workoutId, ex.id, e)}
                    className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
                  >
                    <TrashIcon />
                  </button>
                </div>

                {lastEntry && (
                  <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2">
                    <span className="text-sm font-medium text-slate-900">
                      {lastEntry.sets}x{lastEntry.reps}
                    </span>
                    <span className="text-sm text-slate-500">at</span>
                    <span className="text-sm font-bold text-indigo-600">{lastEntry.weight}kg</span>
                  </div>
                )}
              </div>
            );
          })}

          <Button 
            variant="secondary" 
            fullWidth 
            onClick={() => addExercise(workoutId)}
            className="mt-6 border-dashed bg-transparent"
          >
            <PlusIcon /> <span className="ml-2">Add Exercise</span>
          </Button>
        </div>
      </div>
    );
  };

  const renderExerciseDetail = (workoutId: string, exerciseId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    const exercise = workout?.exercises.find(e => e.id === exerciseId);
    if (!exercise) return null;

    const lastEntry = exercise.entries[exercise.entries.length - 1];

    return (
      <div className="max-w-md mx-auto min-h-screen bg-white">
        {/* Header - Top 1/3 Content */}
        <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
          <header className="py-6 flex items-center justify-between -mx-2">
            <button 
              onClick={() => {
                  setIsEditingInfo(false);
                  setView({ type: 'workout-detail', workoutId });
              }}
              className="p-2 text-slate-600 hover:bg-white rounded-full transition-colors"
            >
              <ChevronLeftIcon />
            </button>
            <div className="flex gap-2">
              {isEditingInfo ? (
                <Button 
                  variant="primary" 
                  size="sm"
                  onClick={() => saveExerciseEdit(workoutId, exerciseId)}
                  className="bg-emerald-600 hover:bg-emerald-700"
                >
                  <CheckIcon /> <span className="ml-1.5">Done</span>
                </Button>
              ) : (
                <Button 
                  variant="ghost" 
                  size="sm"
                  onClick={() => startEditingExercise(exercise)}
                >
                  <EditIcon /> <span className="ml-1.5 text-xs">Edit</span>
                </Button>
              )}
            </div>
          </header>

          <div className="space-y-4">
            {isEditingInfo ? (
              <div className="space-y-4 animate-in fade-in slide-in-from-top-2 duration-200">
                <input 
                  type="text" 
                  value={editFields.name}
                  onChange={(e) => setEditFields({ ...editFields, name: e.target.value })}
                  placeholder="Exercise name"
                  className="w-full text-2xl font-bold bg-white border border-slate-200 rounded-xl px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                />

                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-1">Tags</label>
                  <div className="flex flex-wrap gap-2">
                    {editFields.tags.map((tag, idx) => (
                      <span 
                        key={idx} 
                        className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-700'}`}
                      >
                        {tag}
                        <button 
                          onClick={() => setEditFields({ ...editFields, tags: editFields.tags.filter((_, i) => i !== idx) })}
                          className="hover:text-rose-500"
                        >
                          ×
                        </button>
                      </span>
                    ))}
                    <div className="flex items-center bg-white border border-slate-200 rounded-lg px-2 py-1 text-xs">
                      <input 
                        type="text" 
                        value={newTag}
                        onChange={(e) => setNewTag(e.target.value)}
                        onKeyDown={(e) => {
                          if (e.key === 'Enter' && newTag.trim()) {
                            setEditFields({ ...editFields, tags: [...editFields.tags, newTag.trim()] });
                            setNewTag('');
                          }
                        }}
                        placeholder="Add tag..."
                        className="bg-transparent outline-none w-20"
                      />
                      <button 
                        onClick={() => {
                          if (newTag.trim()) {
                            setEditFields({ ...editFields, tags: [...editFields.tags, newTag.trim()] });
                            setNewTag('');
                          }
                        }}
                        className="ml-1 text-indigo-600 font-bold"
                      >
                        +
                      </button>
                    </div>
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-1">Notes</label>
                  <textarea 
                    value={editFields.notes}
                    onChange={(e) => setEditFields({ ...editFields, notes: e.target.value })}
                    placeholder="Tips, cues, or focus points..."
                    rows={2}
                    className="w-full text-sm bg-white border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>
              </div>
            ) : (
              <>
                <div>
                  <h1 className="text-2xl font-bold text-slate-900">{exercise.name}</h1>
                  <div className="flex flex-wrap gap-2 mt-2">
                    {exercise.tags.map(tag => (
                      <span 
                        key={tag} 
                        className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600'}`}
                      >
                        <TagIcon /> {tag}
                      </span>
                    ))}
                    {exercise.tags.length === 0 && (
                      <span className="text-xs text-slate-400 italic">No tags</span>
                    )}
                  </div>
                </div>

                {lastEntry && (
                  <div className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm flex items-center gap-4">
                    <div className="w-10 h-10 bg-indigo-50 rounded-lg flex items-center justify-center text-indigo-600">
                      <CheckIcon />
                    </div>
                    <div>
                      <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Latest PR</p>
                      <p className="text-slate-800 font-semibold">{lastEntry.sets}x{lastEntry.reps} @ {lastEntry.weight}kg</p>
                    </div>
                  </div>
                )}

                <div className="flex items-start gap-3 text-slate-500">
                  <div className="mt-1 flex-shrink-0 text-slate-300">
                    <InfoIcon />
                  </div>
                  <div 
                    className="text-sm italic cursor-pointer"
                    onClick={() => startEditingExercise(exercise)}
                  >
                    {exercise.notes || 'No notes added yet... tap edit to add.'}
                  </div>
                </div>
              </>
            )}
          </div>
        </div>

        {/* Main Content - Performance Entries */}
        <div className="px-6 py-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-slate-800">History</h2>
            {!isEditingInfo && (
                <Button size="sm" onClick={() => addEntry(workoutId, exerciseId)}>
                  <PlusIcon /> <span className="ml-1.5">New Log</span>
                </Button>
            )}
          </div>

          <div className="overflow-x-auto -mx-6 px-6">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="text-[11px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="pb-3 pr-2">Date</th>
                  <th className="pb-3 px-2">Sets</th>
                  <th className="pb-3 px-2">Reps</th>
                  <th className="pb-3 px-2">Kg</th>
                  <th className="pb-3 pl-2"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {[...exercise.entries].reverse().map(ent => (
                  <tr key={ent.id} className="group">
                    <td className="py-4 pr-2 text-sm text-slate-500 font-medium whitespace-nowrap">
                      {new Date(ent.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                    </td>
                    <td className="py-3 px-1">
                      <input 
                        type="number" 
                        value={ent.sets}
                        onChange={(e) => updateEntry(workoutId, exerciseId, ent.id, 'sets', parseInt(e.target.value) || 0)}
                        className="w-12 bg-slate-50 text-slate-800 border-none rounded-lg p-2 text-center text-sm font-semibold focus:ring-2 focus:ring-indigo-100"
                      />
                    </td>
                    <td className="py-3 px-1">
                      <input 
                        type="number" 
                        value={ent.reps}
                        onChange={(e) => updateEntry(workoutId, exerciseId, ent.id, 'reps', parseInt(e.target.value) || 0)}
                        className="w-12 bg-slate-50 text-slate-800 border-none rounded-lg p-2 text-center text-sm font-semibold focus:ring-2 focus:ring-indigo-100"
                      />
                    </td>
                    <td className="py-3 px-1">
                      <input 
                        type="number" 
                        value={ent.weight}
                        onChange={(e) => updateEntry(workoutId, exerciseId, ent.id, 'weight', parseFloat(e.target.value) || 0)}
                        className="w-16 bg-slate-50 text-slate-800 border-none rounded-lg p-2 text-center text-sm font-semibold focus:ring-2 focus:ring-indigo-100"
                      />
                    </td>
                    <td className="py-4 pl-2 text-right">
                      <button 
                        onClick={() => deleteEntry(workoutId, exerciseId, ent.id)}
                        className="p-1.5 text-slate-200 hover:text-rose-500 transition-colors"
                      >
                        <TrashIcon />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {exercise.entries.length === 0 && (
            <div className="py-12 text-center text-slate-400 space-y-2">
              <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                <PlusIcon />
              </div>
              <p>No training logs yet.</p>
              {!isEditingInfo && <p className="text-xs">Start tracking your progress by adding a new log.</p>}
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen">
      {view.type === 'workouts' && renderWorkouts()}
      {view.type === 'workout-detail' && renderWorkoutDetail(view.workoutId)}
      {view.type === 'exercise-detail' && renderExerciseDetail(view.workoutId, view.exerciseId)}
    </div>
  );
};

export default App;

