);

export const CalendarIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"></rect><line x1="16" y1="2" x2="16" y2="6"></line><line x1="8" y1="2" x2="8" y2="6"></line><line x1="3" y1="10" x2="21" y2="10"></line></svg>
);

import React, { useState, useEffect, useRef } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon,
  TagIcon,
  MoreIcon,
  XIcon,
  CalendarIcon
} from './components/Icons';

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });
  const [view, setView] = useState<ViewState>({ type: 'workouts' });

  // UI States
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [isAddingExercise, setIsAddingExercise] = useState<string | null>(null);
  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [newExerciseName, setNewExerciseName] = useState('');
  const [newExerciseMuscle, setNewExerciseMuscle] = useState('');

  // Exercise Detail States
  const [isEditingInfo, setIsEditingInfo] = useState(false);
  const [editFields, setEditFields] = useState<{ name: string; notes: string; tags: string[] }>({ name: '', notes: '', tags: [] });
  const [newTag, setNewTag] = useState('');

  // Entry Editing States
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [draftEntry, setDraftEntry] = useState<Entry | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  const addWorkout = () => {
    if (!newWorkoutName.trim()) return;
    const newWorkout: Workout = {
      id: Date.now().toString(),
      name: newWorkoutName,
      exercises: []
    };
    setWorkouts([...workouts, newWorkout]);
    setNewWorkoutName('');
    setIsAddingWorkout(false);
  };

  const deleteWorkout = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure?')) return;
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  const addExercise = (workoutId: string) => {
    if (!newExerciseName.trim()) return;
    const tags = newExerciseMuscle ? [newExerciseMuscle] : [];

    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: [...w.exercises, {
            id: Date.now().toString(),
            name: newExerciseName,
            tags,
            entries: []
          }]
        };
      }
      return w;
    }));
    setNewExerciseName('');
    setNewExerciseMuscle('');
    setIsAddingExercise(null);
  };

  const deleteExercise = (workoutId: string, exerciseId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.filter(ex => ex.id !== exerciseId)
        };
      }
      return w;
    }));
  };

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              const existingIdx = ex.entries.findIndex(e => e.id === entry.id);
              let newEntries;
              if (existingIdx >= 0) {
                newEntries = ex.entries.map(e => e.id === entry.id ? entry : e);
              } else {
                newEntries = [...ex.entries, entry];
              }
              // Sort by date (descending)
              newEntries.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
              return { ...ex, entries: newEntries };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Remove this performance entry?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.filter(ent => ent.id !== entryId)
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const updateExerciseBasicInfo = (workoutId: string, exerciseId: string, updates: Partial<Pick<Exercise, 'name' | 'tags' | 'notes'>>) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return { ...ex, ...updates };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const startEditingExercise = (exercise: Exercise) => {
    setEditFields({
      name: exercise.name,
      notes: exercise.notes || '',
      tags: [...exercise.tags]
    });
    setIsEditingInfo(true);
  };

  const saveExerciseEdit = (workoutId: string, exerciseId: string) => {
    updateExerciseBasicInfo(workoutId, exerciseId, {
      name: editFields.name,
      notes: editFields.notes,
      tags: editFields.tags
    });
    setIsEditingInfo(false);
  };

  // Rendering Components
  const Modal = ({ title, onClose, onAction, actionLabel, children }: any) => (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl animate-in zoom-in-95 duration-200">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full"><XIcon /></button>
        </div>
        <div className="space-y-4 mb-6">{children}</div>
        <Button fullWidth onClick={onAction}>{actionLabel}</Button>
      </div>
    </div>
  );

  const renderWorkouts = () => (
    <div className="max-w-md mx-auto min-h-screen pb-24">
      <header className="px-6 py-10">
        <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Workouts</h1>
        <p className="text-slate-500 mt-2">Manage your training routines</p>
      </header>

      <div className="px-6 space-y-4">
        {workouts.map(w => (
          <div 
            key={w.id}
            onClick={() => setView({ type: 'workout-detail', workoutId: w.id })}
            className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between active:bg-slate-50 transition-colors group cursor-pointer"
          >
            <div>
              <h3 className="font-semibold text-lg text-slate-800">{w.name}</h3>
              <p className="text-sm text-slate-500">{w.exercises.length} exercises</p>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={(e) => deleteWorkout(w.id, e)}
                className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
              >
                <TrashIcon />
              </button>
              <div className="text-indigo-600">
                <ChevronRightIcon />
              </div>
            </div>
          </div>
        ))}

        <Button 
          variant="secondary" 
          fullWidth 
          onClick={() => setIsAddingWorkout(true)}
          className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
        >
          <PlusIcon /> <span className="ml-2">Create New Workout</span>
        </Button>
      </div>

      {isAddingWorkout && (
        <Modal 
          title="New Workout" 
          onClose={() => setIsAddingWorkout(false)} 
          onAction={addWorkout}
          actionLabel="Create Workout"
        >
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Workout Name</label>
            <input 
              autoFocus
              type="text" 
              value={newWorkoutName}
              onChange={(e) => setNewWorkoutName(e.target.value)}
              placeholder="e.g. Push Day, Upper Body B"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
        </Modal>
      )}
    </div>
  );

  const renderWorkoutDetail = (workoutId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    if (!workout) return null;

    return (
      <div className="max-w-md mx-auto min-h-screen pb-24">
        <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50 z-10">
          <button 
            onClick={() => setView({ type: 'workouts' })}
            className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"
          >
            <ChevronLeftIcon />
          </button>
          <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
        </header>

        <div className="px-6 space-y-3">
          {workout.exercises.map(ex => {
            const lastEntry = ex.entries[0]; // Entries are sorted desc
            const isAnchor = ex.tags.includes('anchor');

            return (
              <div 
                key={ex.id}
                onClick={() => {
                    setIsEditingInfo(false);
                    setDraftEntry(null);
                    setEditingEntryId(null);
                    setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id });
                }}
                className={`bg-white p-5 rounded-2xl border transition-all active:bg-slate-50 cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50/50 shadow-md' : 'border-slate-100 shadow-sm'}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                      {isAnchor && (
                        <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-2 mt-1.5">
                      {ex.tags.map(tag => tag !== 'anchor' && (
                        <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-lg">{tag}</span>
                      ))}
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteExercise(workoutId, ex.id, e)}
                    className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
                  >
                    <TrashIcon />
                  </button>
                </div>

                {lastEntry && (
                  <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2">
                    <span className="text-sm font-medium text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                    <span className="text-sm text-slate-500">at</span>
                    <span className="text-sm font-bold text-indigo-600">{lastEntry.weight}kg</span>
                  </div>
                )}
              </div>
            );
          })}

          <Button 
            variant="secondary" 
            fullWidth 
            onClick={() => setIsAddingExercise(workoutId)}
            className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
          >
            <PlusIcon /> <span className="ml-2">Add Exercise</span>
          </Button>
        </div>

        {isAddingExercise && (
          <Modal 
            title="Add Exercise" 
            onClose={() => setIsAddingExercise(null)} 
            onAction={() => addExercise(workoutId)}
            actionLabel="Add to Workout"
          >
            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Name</label>
                <input 
                  autoFocus
                  type="text" 
                  value={newExerciseName}
                  onChange={(e) => setNewExerciseName(e.target.value)}
                  placeholder="e.g. Bench Press"
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Muscle Group</label>
                <input 
                  type="text" 
                  value={newExerciseMuscle}
                  onChange={(e) => setNewExerciseMuscle(e.target.value)}
                  placeholder="e.g. Chest"
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
                />
              </div>
            </div>
          </Modal>
        )}
      </div>
    );
  };

  const renderExerciseDetail = (workoutId: string, exerciseId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    const exercise = workout?.exercises.find(e => e.id === exerciseId);
    if (!exercise) return null;

    const latestEntry = exercise.entries[0]; // Sorted desc

    const handleNewLog = () => {
      setDraftEntry({
        id: 'draft-' + Date.now(),
        date: new Date().toISOString().split('T')[0],
        sets: latestEntry?.sets || 0,
        reps: latestEntry?.reps || 0,
        weight: latestEntry?.weight || 0
      });
      setEditingEntryId(null);
    };

    const handleSaveDraft = () => {
      if (!draftEntry) return;
      commitEntry(workoutId, exerciseId, { ...draftEntry, id: Date.now().toString() });
      setDraftEntry(null);
    };

    const RowInputs = ({ entry, onChange }: { entry: Entry, onChange: (field: keyof Entry, val: any) => void }) => (
      <>
        <td className="py-2 pr-2">
          <input 
            type="date" 
            value={entry.date}
            onChange={(e) => onChange('date', e.target.value)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-xs font-medium text-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.sets}
            onChange={(e) => onChange('sets', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-2 text-center text-sm font-bold text-indigo-700 outline-none"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.reps}
            onChange={(e) => onChange('reps', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-2 text-center text-sm font-bold text-indigo-700 outline-none"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.weight}
            onChange={(e) => onChange('weight', parseFloat(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-2 text-center text-sm font-bold text-indigo-700 outline-none"
          />
        </td>
      </>
    );

    return (
      <div className="max-w-md mx-auto min-h-screen bg-white">
        <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
          <header className="py-6 flex items-center justify-between -mx-2">
            <button 
              onClick={() => setView({ type: 'workout-detail', workoutId })}
              className="p-2 text-slate-600 hover:bg-white rounded-full transition-colors"
            >
              <ChevronLeftIcon />
            </button>
            <div className="flex gap-2">
              {isEditingInfo ? (
                <Button 
                  variant="primary" 
                  size="sm"
                  onClick={() => saveExerciseEdit(workoutId, exerciseId)}
                  className="bg-emerald-600 hover:bg-emerald-700"
                >
                  <CheckIcon /> <span className="ml-1.5">Done</span>
                </Button>
              ) : (
                <Button 
                  variant="ghost" 
                  size="sm"
                  onClick={() => startEditingExercise(exercise)}
                >
                  <EditIcon /> <span className="ml-1.5 text-xs">Edit</span>
                </Button>
              )}
            </div>
          </header>

          <div className="space-y-4">
            {isEditingInfo ? (
              <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                <input 
                  type="text" 
                  value={editFields.name}
                  onChange={(e) => setEditFields({ ...editFields, name: e.target.value })}
                  placeholder="Exercise name"
                  className="w-full text-2xl font-bold bg-white border border-slate-200 rounded-xl px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                />

                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-1">Tags</label>
                  <div className="flex flex-wrap gap-2">
                    {editFields.tags.map((tag, idx) => (
                      <span key={idx} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-700'}`}>
                        {tag}
                        <button onClick={() => setEditFields({ ...editFields, tags: editFields.tags.filter((_, i) => i !== idx) })} className="hover:text-rose-500">×</button>
                      </span>
                    ))}
                    <div className="flex items-center bg-white border border-slate-200 rounded-lg px-2 py-1 text-xs">
                      <input 
                        type="text" value={newTag} onChange={(e) => setNewTag(e.target.value)}
                        onKeyDown={(e) => {
                          if (e.key === 'Enter' && newTag.trim()) {
                            setEditFields({ ...editFields, tags: [...editFields.tags, newTag.trim()] });
                            setNewTag('');
                          }
                        }}
                        placeholder="Add tag..." className="bg-transparent outline-none w-20"
                      />
                      <button onClick={() => { if (newTag.trim()) { setEditFields({ ...editFields, tags: [...editFields.tags, newTag.trim()] }); setNewTag(''); } }} className="ml-1 text-indigo-600 font-bold">+</button>
                    </div>
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-1">Notes</label>
                  <textarea 
                    value={editFields.notes}
                    onChange={(e) => setEditFields({ ...editFields, notes: e.target.value })}
                    placeholder="Tips, cues, or focus points..."
                    rows={2}
                    className="w-full text-sm bg-white border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>
              </div>
            ) : (
              <>
                <div>
                  <h1 className="text-2xl font-bold text-slate-900 leading-tight">{exercise.name}</h1>
                  <div className="flex flex-wrap gap-2 mt-2">
                    {exercise.tags.map(tag => (
                      <span key={tag} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600'}`}>
                        <TagIcon /> {tag}
                      </span>
                    ))}
                  </div>
                </div>

                {latestEntry && (
                  <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
                    <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600"><CheckIcon /></div>
                    <div>
                      <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Latest Performance</p>
                      <p className="text-slate-800 font-bold text-lg">{latestEntry.sets}x{latestEntry.reps} <span className="text-slate-400 font-medium">@</span> {latestEntry.weight}kg</p>
                    </div>
                  </div>
                )}

                <div className="flex items-start gap-3 text-slate-500">
                  <div className="mt-1 flex-shrink-0 text-slate-300"><InfoIcon /></div>
                  <div className="text-sm italic cursor-pointer" onClick={() => startEditingExercise(exercise)}>
                    {exercise.notes || 'Tap edit to add notes or tips...'}
                  </div>
                </div>
              </>
            )}
          </div>
        </div>

        <div className="px-6 py-8">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold text-slate-900">History</h2>
            <Button size="sm" onClick={handleNewLog} disabled={!!draftEntry}>
              <PlusIcon /> <span className="ml-1.5">New Log</span>
            </Button>
          </div>

          <div className="overflow-x-auto -mx-6 px-6">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="text-[11px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="pb-4 pr-2 w-1/4">Date</th>
                  <th className="pb-4 px-2 text-center">Sets</th>
                  <th className="pb-4 px-2 text-center">Reps</th>
                  <th className="pb-4 px-2 text-center">Kg</th>
                  <th className="pb-4 pl-2 text-right"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {/* Draft Row */}
                {draftEntry && (
                  <tr className="bg-indigo-50/30 animate-in slide-in-from-left-2">
                    <RowInputs 
                      entry={draftEntry} 
                      onChange={(field, val) => setDraftEntry({ ...draftEntry, [field]: val })} 
                    />
                    <td className="py-3 pl-2 text-right">
                      <div className="flex gap-1 justify-end">
                        <button onClick={handleSaveDraft} className="p-2 bg-emerald-100 text-emerald-700 rounded-lg"><CheckIcon /></button>
                        <button onClick={() => setDraftEntry(null)} className="p-2 bg-slate-100 text-slate-400 rounded-lg"><XIcon /></button>
                      </div>
                    </td>
                  </tr>
                )}

                {/* History Rows */}
                {exercise.entries.map(ent => (
                  <tr key={ent.id} className="group relative">
                    {editingEntryId === ent.id ? (
                      <>
                        <RowInputs 
                          entry={ent} 
                          onChange={(field, val) => {
                            setWorkouts(workouts.map(w => {
                              if (w.id === workoutId) {
                                return {
                                  ...w,
                                  exercises: w.exercises.map(ex => {
                                    if (ex.id === exerciseId) {
                                      return {
                                        ...ex,
                                        entries: ex.entries.map(e => e.id === ent.id ? { ...e, [field]: val } : e)
                                      };
                                    }
                                    return ex;
                                  })
                                };
                              }
                              return w;
                            }));
                          }} 
                        />
                        <td className="py-3 pl-2 text-right">
                          <button onClick={() => setEditingEntryId(null)} className="p-2 bg-indigo-600 text-white rounded-lg shadow-sm"><CheckIcon /></button>
                        </td>
                      </>
                    ) : (
                      <>
                        <td className="py-5 pr-2">
                          <div className="flex items-center gap-1.5 text-sm text-slate-500 font-medium">
                            <span className="text-slate-300"><CalendarIcon /></span>
                            {new Date(ent.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                          </div>
                        </td>
                        <td className="py-5 px-2 text-center text-slate-800 font-semibold">{ent.sets}</td>
                        <td className="py-5 px-2 text-center text-slate-800 font-semibold">{ent.reps}</td>
                        <td className="py-5 px-2 text-center text-slate-900 font-bold">{ent.weight}<span className="text-[10px] text-slate-400 ml-0.5">kg</span></td>
                        <td className="py-5 pl-2 text-right relative">
                          <button 
                            onClick={(e) => { e.stopPropagation(); setActiveMenuId(activeMenuId === ent.id ? null : ent.id); }}
                            className={`p-2 rounded-lg transition-colors ${activeMenuId === ent.id ? 'bg-slate-100 text-slate-900' : 'text-slate-300 hover:text-slate-600'}`}
                          >
                            <MoreIcon />
                          </button>

                          {activeMenuId === ent.id && (
                            <>
                              <div className="fixed inset-0 z-40" onClick={() => setActiveMenuId(null)} />
                              <div className="absolute right-2 top-12 z-50 bg-white shadow-xl border border-slate-100 rounded-xl overflow-hidden w-28 animate-in fade-in zoom-in-95 duration-150">
                                <button 
                                  onClick={() => { setEditingEntryId(ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                                >
                                  <EditIcon /> Edit
                                </button>
                                <button 
                                  onClick={() => { deleteEntry(workoutId, exerciseId, ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-rose-600 hover:bg-rose-50 flex items-center gap-2"
                                >
                                  <TrashIcon /> Delete
                                </button>
                              </div>
                            </>
                          )}
                        </td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {exercise.entries.length === 0 && !draftEntry && (
            <div className="py-16 text-center text-slate-400 space-y-4">
              <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto"><PlusIcon /></div>
              <div>
                <p className="font-semibold text-slate-600">No history yet</p>
                <p className="text-sm">Log your first performance to track progress.</p>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && renderWorkouts()}
      {view.type === 'workout-detail' && renderWorkoutDetail(view.workoutId)}
      {view.type === 'exercise-detail' && renderExerciseDetail(view.workoutId, view.exerciseId)}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon,
  TagIcon,
  MoreIcon,
  XIcon,
  CalendarIcon
} from './components/Icons';

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });

  // Global Tags State
  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    const saved = localStorage.getItem('availableTags');
    if (saved) return JSON.parse(saved);

    // Extract unique tags from initial data
    const tags = new Set<string>();
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => ex.tags.forEach(t => tags.add(t))));
    return Array.from(tags);
  });

  // UI States
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [exerciseModal, setExerciseModal] = useState<{
    isOpen: boolean;
    workoutId: string;
    exerciseId?: string; // If present, we are editing
    name: string;
    notes: string;
    tags: string[];
  } | null>(null);

  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [newCustomTag, setNewCustomTag] = useState('');

  // Entry Editing States
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [draftEntry, setDraftEntry] = useState<Entry | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  useEffect(() => {
    localStorage.setItem('availableTags', JSON.stringify(availableTags));
  }, [availableTags]);

  const addWorkout = () => {
    if (!newWorkoutName.trim()) return;
    const newWorkout: Workout = {
      id: Date.now().toString(),
      name: newWorkoutName,
      exercises: []
    };
    setWorkouts([...workouts, newWorkout]);
    setNewWorkoutName('');
    setIsAddingWorkout(false);
  };

  const deleteWorkout = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure you want to delete this workout?')) return;
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  const saveExerciseFromModal = () => {
    if (!exerciseModal || !exerciseModal.name.trim()) return;

    if (exerciseModal.exerciseId) {
      // Editing
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: w.exercises.map(ex => {
              if (ex.id === exerciseModal.exerciseId) {
                return { 
                  ...ex, 
                  name: exerciseModal.name, 
                  notes: exerciseModal.notes, 
                  tags: exerciseModal.tags 
                };
              }
              return ex;
            })
          };
        }
        return w;
      }));
    } else {
      // Adding
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: [...w.exercises, {
              id: Date.now().toString(),
              name: exerciseModal.name,
              notes: exerciseModal.notes,
              tags: exerciseModal.tags,
              entries: []
            }]
          };
        }
        return w;
      }));
    }
    setExerciseModal(null);
  };

  const deleteExercise = (workoutId: string, exerciseId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.filter(ex => ex.id !== exerciseId)
        };
      }
      return w;
    }));
    if (view.type === 'exercise-detail') {
      setView({ type: 'workout-detail', workoutId });
    }
  };

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              const existingIdx = ex.entries.findIndex(e => e.id === entry.id);
              let newEntries;
              if (existingIdx >= 0) {
                newEntries = ex.entries.map(e => e.id === entry.id ? entry : e);
              } else {
                newEntries = [...ex.entries, entry];
              }
              newEntries.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
              return { ...ex, entries: newEntries };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Remove this performance entry?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.filter(ent => ent.id !== entryId)
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const addNewGlobalTag = () => {
    const tag = newCustomTag.trim();
    if (tag && !availableTags.includes(tag)) {
      setAvailableTags([...availableTags, tag]);
      if (exerciseModal) {
        setExerciseModal({
          ...exerciseModal,
          tags: [...exerciseModal.tags, tag]
        });
      }
      setNewCustomTag('');
    }
  };

  const Modal = ({ title, onClose, onAction, actionLabel, children }: any) => (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl animate-in zoom-in-95 duration-200 overflow-y-auto max-h-[90vh]">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full"><XIcon /></button>
        </div>
        <div className="space-y-4 mb-8">{children}</div>
        <div className="flex gap-3 sticky bottom-0 bg-white pt-2">
          <Button variant="secondary" className="flex-1" onClick={onClose}>Cancel</Button>
          <Button className="flex-1" onClick={onAction}>{actionLabel}</Button>
        </div>
      </div>
    </div>
  );

  const renderWorkouts = () => (
    <div className="max-w-md mx-auto min-h-screen pb-24">
      <header className="px-6 py-10">
        <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Workouts</h1>
        <p className="text-slate-500 mt-2">Manage your training routines</p>
      </header>

      <div className="px-6 space-y-4">
        {workouts.map(w => (
          <div 
            key={w.id}
            onClick={() => setView({ type: 'workout-detail', workoutId: w.id })}
            className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between active:bg-slate-50 transition-colors cursor-pointer"
          >
            <div>
              <h3 className="font-semibold text-lg text-slate-800">{w.name}</h3>
              <p className="text-sm text-slate-500">{w.exercises.length} exercises</p>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={(e) => deleteWorkout(w.id, e)}
                className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
              >
                <TrashIcon />
              </button>
              <div className="text-indigo-600">
                <ChevronRightIcon />
              </div>
            </div>
          </div>
        ))}

        <Button 
          variant="secondary" 
          fullWidth 
          onClick={() => setIsAddingWorkout(true)}
          className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
        >
          <PlusIcon /> <span className="ml-2">Create New Workout</span>
        </Button>
      </div>

      {isAddingWorkout && (
        <Modal 
          title="New Workout" 
          onClose={() => setIsAddingWorkout(false)} 
          onAction={addWorkout}
          actionLabel="Create"
        >
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Workout Name</label>
            <input 
              autoFocus
              type="text" 
              value={newWorkoutName}
              onChange={(e) => setNewWorkoutName(e.target.value)}
              placeholder="e.g. Push Day"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
        </Modal>
      )}
    </div>
  );

  const renderWorkoutDetail = (workoutId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    if (!workout) return null;

    return (
      <div className="max-w-md mx-auto min-h-screen pb-24">
        <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50 z-10">
          <button 
            onClick={() => setView({ type: 'workouts' })}
            className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"
          >
            <ChevronLeftIcon />
          </button>
          <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
        </header>

        <div className="px-6 space-y-3">
          {workout.exercises.map(ex => {
            const lastEntry = ex.entries[0];
            const isAnchor = ex.tags.includes('anchor');

            return (
              <div 
                key={ex.id}
                onClick={() => setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id })}
                className={`bg-white p-5 rounded-2xl border transition-all active:bg-slate-50 cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50/50 shadow-md' : 'border-slate-100 shadow-sm'}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                      {isAnchor && (
                        <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-2 mt-1.5">
                      {ex.tags.map(tag => tag !== 'anchor' && (
                        <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-lg">{tag}</span>
                      ))}
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteExercise(workoutId, ex.id, e)}
                    className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
                  >
                    <TrashIcon />
                  </button>
                </div>

                {lastEntry && (
                  <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2">
                    <span className="text-sm font-medium text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                    <span className="text-sm text-slate-500">at</span>
                    <span className="text-sm font-bold text-indigo-600">{lastEntry.weight}kg</span>
                  </div>
                )}
              </div>
            );
          })}

          <Button 
            variant="secondary" 
            fullWidth 
            onClick={() => setExerciseModal({
              isOpen: true,
              workoutId,
              name: '',
              notes: '',
              tags: []
            })}
            className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
          >
            <PlusIcon /> <span className="ml-2">Add Exercise</span>
          </Button>
        </div>
      </div>
    );
  };

  const renderExerciseDetail = (workoutId: string, exerciseId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    const exercise = workout?.exercises.find(e => e.id === exerciseId);
    if (!exercise) return null;

    const latestEntry = exercise.entries[0];

    const handleNewLog = () => {
      setDraftEntry({
        id: 'draft-' + Date.now(),
        date: new Date().toISOString().split('T')[0],
        sets: latestEntry?.sets || 0,
        reps: latestEntry?.reps || 0,
        weight: latestEntry?.weight || 0
      });
      setEditingEntryId(null);
    };

    const handleSaveDraft = () => {
      if (!draftEntry) return;
      commitEntry(workoutId, exerciseId, { ...draftEntry, id: Date.now().toString() });
      setDraftEntry(null);
    };

    const RowInputs = ({ entry, onChange }: { entry: Entry, onChange: (field: keyof Entry, val: any) => void }) => (
      <>
        <td className="py-2 pr-2">
          <input 
            type="date" 
            value={entry.date}
            onChange={(e) => onChange('date', e.target.value)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-xs font-medium text-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.sets}
            onChange={(e) => onChange('sets', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-2 text-center text-sm font-bold text-indigo-700 outline-none"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.reps}
            onChange={(e) => onChange('reps', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-2 text-center text-sm font-bold text-indigo-700 outline-none"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.weight}
            onChange={(e) => onChange('weight', parseFloat(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-2 text-center text-sm font-bold text-indigo-700 outline-none"
          />
        </td>
      </>
    );

    return (
      <div className="max-w-md mx-auto min-h-screen bg-white">
        <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
          <header className="py-6 flex items-center justify-between -mx-2">
            <button 
              onClick={() => setView({ type: 'workout-detail', workoutId })}
              className="p-2 text-slate-600 hover:bg-white rounded-full transition-colors"
            >
              <ChevronLeftIcon />
            </button>
            <div className="flex gap-2">
              <Button 
                variant="ghost" 
                size="sm"
                onClick={() => setExerciseModal({
                  isOpen: true,
                  workoutId,
                  exerciseId: exercise.id,
                  name: exercise.name,
                  notes: exercise.notes || '',
                  tags: exercise.tags
                })}
              >
                <EditIcon /> <span className="ml-1.5 text-xs">Edit</span>
              </Button>
            </div>
          </header>

          <div className="space-y-4">
            <div>
              <h1 className="text-2xl font-bold text-slate-900 leading-tight">{exercise.name}</h1>
              <div className="flex flex-wrap gap-2 mt-2">
                {exercise.tags.map(tag => (
                  <span key={tag} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600'}`}>
                    <TagIcon /> {tag}
                  </span>
                ))}
              </div>
            </div>

            {latestEntry && (
              <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600"><CheckIcon /></div>
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Latest Performance</p>
                  <p className="text-slate-800 font-bold text-lg">{latestEntry.sets}x{latestEntry.reps} <span className="text-slate-400 font-medium">@</span> {latestEntry.weight}kg</p>
                </div>
              </div>
            )}

            <div className="flex items-start gap-3 text-slate-500">
              <div className="mt-1 flex-shrink-0 text-slate-300"><InfoIcon /></div>
              <div className="text-sm italic">
                {exercise.notes || 'No notes added.'}
              </div>
            </div>
          </div>
        </div>

        <div className="px-6 py-8">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold text-slate-900">History</h2>
            <Button size="sm" onClick={handleNewLog} disabled={!!draftEntry}>
              <PlusIcon /> <span className="ml-1.5">New Log</span>
            </Button>
          </div>

          <div className="overflow-x-auto -mx-6 px-6">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="text-[11px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="pb-4 pr-2 w-1/4">Date</th>
                  <th className="pb-4 px-2 text-center">Sets</th>
                  <th className="pb-4 px-2 text-center">Reps</th>
                  <th className="pb-4 px-2 text-center">Kg</th>
                  <th className="pb-4 pl-2 text-right"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {draftEntry && (
                  <tr className="bg-indigo-50/30">
                    <RowInputs 
                      entry={draftEntry} 
                      onChange={(field, val) => setDraftEntry({ ...draftEntry, [field]: val })} 
                    />
                    <td className="py-3 pl-2 text-right">
                      <div className="flex gap-1 justify-end">
                        <button onClick={handleSaveDraft} className="p-2 bg-emerald-100 text-emerald-700 rounded-lg"><CheckIcon /></button>
                        <button onClick={() => setDraftEntry(null)} className="p-2 bg-slate-100 text-slate-400 rounded-lg"><XIcon /></button>
                      </div>
                    </td>
                  </tr>
                )}

                {exercise.entries.map(ent => (
                  <tr key={ent.id} className="group relative">
                    {editingEntryId === ent.id ? (
                      <>
                        <RowInputs 
                          entry={ent} 
                          onChange={(field, val) => {
                            setWorkouts(workouts.map(w => {
                              if (w.id === workoutId) {
                                return {
                                  ...w,
                                  exercises: w.exercises.map(ex => {
                                    if (ex.id === exerciseId) {
                                      return {
                                        ...ex,
                                        entries: ex.entries.map(e => e.id === ent.id ? { ...e, [field]: val } : e)
                                      };
                                    }
                                    return ex;
                                  })
                                };
                              }
                              return w;
                            }));
                          }} 
                        />
                        <td className="py-3 pl-2 text-right">
                          <button onClick={() => setEditingEntryId(null)} className="p-2 bg-indigo-600 text-white rounded-lg"><CheckIcon /></button>
                        </td>
                      </>
                    ) : (
                      <>
                        <td className="py-5 pr-2">
                          <div className="flex items-center gap-1.5 text-sm text-slate-500 font-medium">
                            <span className="text-slate-300"><CalendarIcon /></span>
                            {new Date(ent.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                          </div>
                        </td>
                        <td className="py-5 px-2 text-center text-slate-800 font-semibold">{ent.sets}</td>
                        <td className="py-5 px-2 text-center text-slate-800 font-semibold">{ent.reps}</td>
                        <td className="py-5 px-2 text-center text-slate-900 font-bold">{ent.weight}<span className="text-[10px] text-slate-400 ml-0.5">kg</span></td>
                        <td className="py-5 pl-2 text-right relative">
                          <button 
                            onClick={(e) => { e.stopPropagation(); setActiveMenuId(activeMenuId === ent.id ? null : ent.id); }}
                            className={`p-2 rounded-lg transition-colors ${activeMenuId === ent.id ? 'bg-slate-100 text-slate-900' : 'text-slate-300 hover:text-slate-600'}`}
                          >
                            <MoreIcon />
                          </button>

                          {activeMenuId === ent.id && (
                            <>
                              <div className="fixed inset-0 z-40" onClick={() => setActiveMenuId(null)} />
                              <div className="absolute right-2 top-12 z-50 bg-white shadow-xl border border-slate-100 rounded-xl overflow-hidden w-28">
                                <button 
                                  onClick={() => { setEditingEntryId(ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                                >
                                  <EditIcon /> Edit
                                </button>
                                <button 
                                  onClick={() => { deleteEntry(workoutId, exerciseId, ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-rose-600 hover:bg-rose-50 flex items-center gap-2"
                                >
                                  <TrashIcon /> Delete
                                </button>
                              </div>
                            </>
                          )}
                        </td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {exercise.entries.length === 0 && !draftEntry && (
            <div className="py-16 text-center text-slate-400">
              <p>No history yet.</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && renderWorkouts()}
      {view.type === 'workout-detail' && renderWorkoutDetail(view.workoutId)}
      {view.type === 'exercise-detail' && renderExerciseDetail(view.workoutId, view.exerciseId)}

      {/* Shared Exercise Modal (Add/Edit) */}
      {exerciseModal && (
        <Modal 
          title={exerciseModal.exerciseId ? "Edit Exercise" : "Add Exercise"} 
          onClose={() => setExerciseModal(null)} 
          onAction={saveExerciseFromModal}
          actionLabel={exerciseModal.exerciseId ? "Save Changes" : "Add Exercise"}
        >
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Name</label>
              <input 
                autoFocus
                type="text" 
                value={exerciseModal.name}
                onChange={(e) => setExerciseModal({ ...exerciseModal, name: e.target.value })}
                placeholder="Exercise Name"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Tags</label>
              <div className="flex flex-wrap gap-2 mb-3">
                {exerciseModal.tags.map((tag, idx) => (
                  <span key={idx} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-700'}`}>
                    {tag}
                    <button onClick={() => setExerciseModal({ ...exerciseModal, tags: exerciseModal.tags.filter((_, i) => i !== idx) })} className="hover:text-rose-500 font-bold">×</button>
                  </span>
                ))}
              </div>

              {/* Tag Selector Dropdown */}
              <div className="space-y-3">
                <select 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm text-slate-600 focus:ring-2 focus:ring-indigo-500 outline-none"
                  onChange={(e) => {
                    const selected = e.target.value;
                    if (selected && !exerciseModal.tags.includes(selected)) {
                      setExerciseModal({ ...exerciseModal, tags: [...exerciseModal.tags, selected] });
                    }
                    e.target.value = ''; // Reset
                  }}
                >
                  <option value="">Select existing tag...</option>
                  {availableTags.filter(t => !exerciseModal.tags.includes(t)).map(t => (
                    <option key={t} value={t}>{t}</option>
                  ))}
                </select>

                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={newCustomTag}
                    onChange={(e) => setNewCustomTag(e.target.value)}
                    placeholder="New custom tag..."
                    className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                  <button 
                    onClick={addNewGlobalTag}
                    className="w-10 h-10 bg-slate-100 text-slate-600 rounded-xl flex items-center justify-center hover:bg-slate-200"
                  >
                    <PlusIcon />
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Notes</label>
              <textarea 
                value={exerciseModal.notes}
                onChange={(e) => setExerciseModal({ ...exerciseModal, notes: e.target.value })}
                placeholder="Tips, cues, or focus points..."
                rows={3}
                className="w-full text-sm bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
              />
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon,
  TagIcon,
  MoreIcon,
  XIcon,
  CalendarIcon
} from './components/Icons';

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });

  // Global Tags State
  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    const saved = localStorage.getItem('availableTags');
    if (saved) return JSON.parse(saved);

    // Extract unique tags from initial data
    const tags = new Set<string>();
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => ex.tags.forEach(t => tags.add(t))));
    return Array.from(tags);
  });

  // UI States
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [exerciseModal, setExerciseModal] = useState<{
    isOpen: boolean;
    workoutId: string;
    exerciseId?: string; // If present, we are editing
    name: string;
    notes: string;
    tags: string[];
  } | null>(null);

  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [newCustomTag, setNewCustomTag] = useState('');

  // Entry Editing States
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [draftEntry, setDraftEntry] = useState<Entry | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  useEffect(() => {
    localStorage.setItem('availableTags', JSON.stringify(availableTags));
  }, [availableTags]);

  const addWorkout = () => {
    if (!newWorkoutName.trim()) return;
    const newWorkout: Workout = {
      id: Date.now().toString(),
      name: newWorkoutName,
      exercises: []
    };
    setWorkouts([...workouts, newWorkout]);
    setNewWorkoutName('');
    setIsAddingWorkout(false);
  };

  const deleteWorkout = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure you want to delete this workout?')) return;
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  const saveExerciseFromModal = () => {
    if (!exerciseModal || !exerciseModal.name.trim()) return;

    if (exerciseModal.exerciseId) {
      // Editing
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: w.exercises.map(ex => {
              if (ex.id === exerciseModal.exerciseId) {
                return { 
                  ...ex, 
                  name: exerciseModal.name, 
                  notes: exerciseModal.notes, 
                  tags: exerciseModal.tags 
                };
              }
              return ex;
            })
          };
        }
        return w;
      }));
    } else {
      // Adding
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: [...w.exercises, {
              id: Date.now().toString(),
              name: exerciseModal.name,
              notes: exerciseModal.notes,
              tags: exerciseModal.tags,
              entries: []
            }]
          };
        }
        return w;
      }));
    }
    setExerciseModal(null);
  };

  const deleteExercise = (workoutId: string, exerciseId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.filter(ex => ex.id !== exerciseId)
        };
      }
      return w;
    }));
    if (view.type === 'exercise-detail') {
      setView({ type: 'workout-detail', workoutId });
    }
  };

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              const existingIdx = ex.entries.findIndex(e => e.id === entry.id);
              let newEntries;
              if (existingIdx >= 0) {
                newEntries = ex.entries.map(e => e.id === entry.id ? entry : e);
              } else {
                newEntries = [...ex.entries, entry];
              }
              newEntries.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
              return { ...ex, entries: newEntries };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Remove this performance entry?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.filter(ent => ent.id !== entryId)
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const addNewGlobalTag = () => {
    const tag = newCustomTag.trim();
    if (tag && !availableTags.includes(tag)) {
      setAvailableTags([...availableTags, tag]);
      if (exerciseModal) {
        setExerciseModal({
          ...exerciseModal,
          tags: [...exerciseModal.tags, tag]
        });
      }
      setNewCustomTag('');
    }
  };

  const Modal = ({ title, onClose, onAction, actionLabel, children }: any) => (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl animate-in zoom-in-95 duration-200 overflow-y-auto max-h-[90vh]">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full"><XIcon /></button>
        </div>
        <div className="space-y-4 mb-8">{children}</div>
        <div className="flex gap-3 sticky bottom-0 bg-white pt-2">
          <Button variant="secondary" className="flex-1" onClick={onClose}>Cancel</Button>
          <Button className="flex-1" onClick={onAction}>{actionLabel}</Button>
        </div>
      </div>
    </div>
  );

  const renderWorkouts = () => (
    <div className="max-w-md mx-auto min-h-screen pb-24">
      <header className="px-6 py-10">
        <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Workouts</h1>
        <p className="text-slate-500 mt-2">Manage your training routines</p>
      </header>

      <div className="px-6 space-y-4">
        {workouts.map(w => (
          <div 
            key={w.id}
            onClick={() => setView({ type: 'workout-detail', workoutId: w.id })}
            className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between active:bg-slate-50 transition-colors cursor-pointer"
          >
            <div>
              <h3 className="font-semibold text-lg text-slate-800">{w.name}</h3>
              <p className="text-sm text-slate-500">{w.exercises.length} exercises</p>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={(e) => deleteWorkout(w.id, e)}
                className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
              >
                <TrashIcon />
              </button>
              <div className="text-indigo-600">
                <ChevronRightIcon />
              </div>
            </div>
          </div>
        ))}

        <Button 
          variant="secondary" 
          fullWidth 
          onClick={() => setIsAddingWorkout(true)}
          className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
        >
          <PlusIcon /> <span className="ml-2">Create New Workout</span>
        </Button>
      </div>

      {isAddingWorkout && (
        <Modal 
          title="New Workout" 
          onClose={() => setIsAddingWorkout(false)} 
          onAction={addWorkout}
          actionLabel="Create"
        >
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Workout Name</label>
            <input 
              autoFocus
              type="text" 
              value={newWorkoutName}
              onChange={(e) => setNewWorkoutName(e.target.value)}
              placeholder="e.g. Push Day"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
        </Modal>
      )}
    </div>
  );

  const renderWorkoutDetail = (workoutId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    if (!workout) return null;

    return (
      <div className="max-w-md mx-auto min-h-screen pb-24">
        <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50 z-10">
          <button 
            onClick={() => setView({ type: 'workouts' })}
            className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"
          >
            <ChevronLeftIcon />
          </button>
          <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
        </header>

        <div className="px-6 space-y-3">
          {workout.exercises.map(ex => {
            const lastEntry = ex.entries[0];
            const isAnchor = ex.tags.includes('anchor');

            return (
              <div 
                key={ex.id}
                onClick={() => setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id })}
                className={`bg-white p-5 rounded-2xl border transition-all active:bg-slate-50 cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50/50 shadow-md' : 'border-slate-100 shadow-sm'}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                      {isAnchor && (
                        <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-2 mt-1.5">
                      {ex.tags.map(tag => tag !== 'anchor' && (
                        <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-lg">{tag}</span>
                      ))}
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteExercise(workoutId, ex.id, e)}
                    className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
                  >
                    <TrashIcon />
                  </button>
                </div>

                {lastEntry && (
                  <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2">
                    <span className="text-sm font-medium text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                    <span className="text-sm text-slate-500">at</span>
                    <span className="text-sm font-bold text-indigo-600">{lastEntry.weight}kg</span>
                  </div>
                )}
              </div>
            );
          })}

          <Button 
            variant="secondary" 
            fullWidth 
            onClick={() => setExerciseModal({
              isOpen: true,
              workoutId,
              name: '',
              notes: '',
              tags: []
            })}
            className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
          >
            <PlusIcon /> <span className="ml-2">Add Exercise</span>
          </Button>
        </div>
      </div>
    );
  };

  const renderExerciseDetail = (workoutId: string, exerciseId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    const exercise = workout?.exercises.find(e => e.id === exerciseId);
    if (!exercise) return null;

    const latestEntry = exercise.entries[0];

    const handleNewLog = () => {
      setDraftEntry({
        id: 'draft-' + Date.now(),
        date: new Date().toISOString().split('T')[0],
        sets: latestEntry?.sets || 0,
        reps: latestEntry?.reps || 0,
        weight: latestEntry?.weight || 0
      });
      setEditingEntryId(null);
    };

    const handleSaveDraft = () => {
      if (!draftEntry) return;
      commitEntry(workoutId, exerciseId, { ...draftEntry, id: Date.now().toString() });
      setDraftEntry(null);
    };

    const RowInputs = ({ entry, onChange }: { entry: Entry, onChange: (field: keyof Entry, val: any) => void }) => (
      <>
        <td className="py-2 pr-2">
          <input 
            type="date" 
            value={entry.date}
            onChange={(e) => onChange('date', e.target.value)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1 text-[10px] font-medium text-slate-800 focus:ring-1 focus:ring-indigo-500 outline-none h-9"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.sets}
            onChange={(e) => onChange('sets', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-9"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.reps}
            onChange={(e) => onChange('reps', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-9"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.weight}
            onChange={(e) => onChange('weight', parseFloat(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-9"
          />
        </td>
      </>
    );

    return (
      <div className="max-w-md mx-auto min-h-screen bg-white">
        <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
          <header className="py-6 flex items-center justify-between -mx-2">
            <button 
              onClick={() => setView({ type: 'workout-detail', workoutId })}
              className="p-2 text-slate-600 hover:bg-white rounded-full transition-colors"
            >
              <ChevronLeftIcon />
            </button>
            <div className="flex gap-2">
              <Button 
                variant="ghost" 
                size="sm"
                onClick={() => setExerciseModal({
                  isOpen: true,
                  workoutId,
                  exerciseId: exercise.id,
                  name: exercise.name,
                  notes: exercise.notes || '',
                  tags: exercise.tags
                })}
              >
                <EditIcon /> <span className="ml-1.5 text-xs">Edit</span>
              </Button>
            </div>
          </header>

          <div className="space-y-4">
            <div>
              <h1 className="text-2xl font-bold text-slate-900 leading-tight">{exercise.name}</h1>
              <div className="flex flex-wrap gap-2 mt-2">
                {exercise.tags.map(tag => (
                  <span key={tag} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600'}`}>
                    <TagIcon /> {tag}
                  </span>
                ))}
              </div>
            </div>

            {latestEntry && (
              <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600"><CheckIcon /></div>
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Latest Performance</p>
                  <p className="text-slate-800 font-bold text-lg">{latestEntry.sets}x{latestEntry.reps} <span className="text-slate-400 font-medium">@</span> {latestEntry.weight}kg</p>
                </div>
              </div>
            )}

            <div className="flex items-start gap-3 text-slate-500">
              <div className="mt-1 flex-shrink-0 text-slate-300"><InfoIcon /></div>
              <div className="text-sm italic">
                {exercise.notes || 'No notes.'}
              </div>
            </div>
          </div>
        </div>

        <div className="px-6 py-8">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold text-slate-900">History</h2>
            <Button size="sm" onClick={handleNewLog} disabled={!!draftEntry}>
              <PlusIcon /> <span className="ml-1.5">New Log</span>
            </Button>
          </div>

          <div className="overflow-x-auto -mx-6 px-6">
            <table className="w-full text-left border-collapse table-fixed">
              <thead>
                <tr className="text-[11px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="pb-4 pr-2 w-[80px]">Date</th>
                  <th className="pb-4 px-1 text-center w-[50px]">Sets</th>
                  <th className="pb-4 px-1 text-center w-[50px]">Reps</th>
                  <th className="pb-4 px-1 text-center">Kg</th>
                  <th className="pb-4 pl-2 text-right w-[85px]"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {draftEntry && (
                  <tr className="bg-indigo-50/30">
                    <RowInputs 
                      entry={draftEntry} 
                      onChange={(field, val) => setDraftEntry({ ...draftEntry, [field]: val })} 
                    />
                    <td className="py-3 pl-2 text-right">
                      <div className="flex gap-1 justify-end">
                        <button onClick={handleSaveDraft} className="p-2 bg-emerald-100 text-emerald-700 rounded-lg"><CheckIcon /></button>
                        <button onClick={() => setDraftEntry(null)} className="p-2 bg-slate-100 text-slate-400 rounded-lg"><XIcon /></button>
                      </div>
                    </td>
                  </tr>
                )}

                {exercise.entries.map(ent => (
                  <tr key={ent.id} className="group relative">
                    {editingEntryId === ent.id ? (
                      <>
                        <RowInputs 
                          entry={ent} 
                          onChange={(field, val) => {
                            setWorkouts(workouts.map(w => {
                              if (w.id === workoutId) {
                                return {
                                  ...w,
                                  exercises: w.exercises.map(ex => {
                                    if (ex.id === exerciseId) {
                                      return {
                                        ...ex,
                                        entries: ex.entries.map(e => e.id === ent.id ? { ...e, [field]: val } : e)
                                      };
                                    }
                                    return ex;
                                  })
                                };
                              }
                              return w;
                            }));
                          }} 
                        />
                        <td className="py-3 pl-2 text-right">
                          <button onClick={() => setEditingEntryId(null)} className="p-2 bg-indigo-600 text-white rounded-lg"><CheckIcon /></button>
                        </td>
                      </>
                    ) : (
                      <>
                        <td className="py-5 pr-2">
                          <div className="flex items-center gap-1 text-[11px] text-slate-500 font-medium">
                            {new Date(ent.date).toLocaleDateString(undefined, { month: '2-digit', day: '2-digit', year: 'numeric' })}
                          </div>
                        </td>
                        <td className="py-5 px-1 text-center text-slate-800 font-semibold">{ent.sets}</td>
                        <td className="py-5 px-1 text-center text-slate-800 font-semibold">{ent.reps}</td>
                        <td className="py-5 px-1 text-center text-slate-900 font-bold truncate">
                          {ent.weight}<span className="text-[10px] text-slate-400 ml-0.5 font-normal">kg</span>
                        </td>
                        <td className="py-5 pl-2 text-right relative">
                          <button 
                            onClick={(e) => { e.stopPropagation(); setActiveMenuId(activeMenuId === ent.id ? null : ent.id); }}
                            className={`p-2 rounded-lg transition-colors ${activeMenuId === ent.id ? 'bg-slate-100 text-slate-900' : 'text-slate-300 hover:text-slate-600'}`}
                          >
                            <MoreIcon />
                          </button>

                          {activeMenuId === ent.id && (
                            <>
                              <div className="fixed inset-0 z-40" onClick={() => setActiveMenuId(null)} />
                              <div className="absolute right-2 top-12 z-50 bg-white shadow-xl border border-slate-100 rounded-xl overflow-hidden w-28">
                                <button 
                                  onClick={() => { setEditingEntryId(ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                                >
                                  <EditIcon /> Edit
                                </button>
                                <button 
                                  onClick={() => { deleteEntry(workoutId, exerciseId, ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-rose-600 hover:bg-rose-50 flex items-center gap-2"
                                >
                                  <TrashIcon /> Delete
                                </button>
                              </div>
                            </>
                          )}
                        </td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {exercise.entries.length === 0 && !draftEntry && (
            <div className="py-16 text-center text-slate-400">
              <p>No history yet.</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && renderWorkouts()}
      {view.type === 'workout-detail' && renderWorkoutDetail(view.workoutId)}
      {view.type === 'exercise-detail' && renderExerciseDetail(view.workoutId, view.exerciseId)}

      {/* Shared Exercise Modal (Add/Edit) */}
      {exerciseModal && (
        <Modal 
          title={exerciseModal.exerciseId ? "Edit Exercise" : "Add Exercise"} 
          onClose={() => setExerciseModal(null)} 
          onAction={saveExerciseFromModal}
          actionLabel={exerciseModal.exerciseId ? "Save Changes" : "Add Exercise"}
        >
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Name</label>
              <input 
                autoFocus
                type="text" 
                value={exerciseModal.name}
                onChange={(e) => setExerciseModal({ ...exerciseModal, name: e.target.value })}
                placeholder="Exercise Name"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Tags</label>
              <div className="flex flex-wrap gap-2 mb-3">
                {exerciseModal.tags.map((tag, idx) => (
                  <span key={idx} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-700'}`}>
                    {tag}
                    <button onClick={() => setExerciseModal({ ...exerciseModal, tags: exerciseModal.tags.filter((_, i) => i !== idx) })} className="hover:text-rose-500 font-bold">×</button>
                  </span>
                ))}
              </div>

              {/* Tag Selector Dropdown */}
              <div className="space-y-3">
                <select 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm text-slate-600 focus:ring-2 focus:ring-indigo-500 outline-none"
                  onChange={(e) => {
                    const selected = e.target.value;
                    if (selected && !exerciseModal.tags.includes(selected)) {
                      setExerciseModal({ ...exerciseModal, tags: [...exerciseModal.tags, selected] });
                    }
                    e.target.value = ''; // Reset
                  }}
                >
                  <option value="">Select existing tag...</option>
                  {availableTags.filter(t => !exerciseModal.tags.includes(t)).map(t => (
                    <option key={t} value={t}>{t}</option>
                  ))}
                </select>

                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={newCustomTag}
                    onChange={(e) => setNewCustomTag(e.target.value)}
                    placeholder="New custom tag..."
                    className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                  <button 
                    onClick={addNewGlobalTag}
                    className="w-10 h-10 bg-slate-100 text-slate-600 rounded-xl flex items-center justify-center hover:bg-slate-200"
                  >
                    <PlusIcon />
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Notes</label>
              <textarea 
                value={exerciseModal.notes}
                onChange={(e) => setExerciseModal({ ...exerciseModal, notes: e.target.value })}
                placeholder="Tips, cues, or focus points..."
                rows={3}
                className="w-full text-sm bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
              />
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon,
  TagIcon,
  MoreIcon,
  XIcon,
  CalendarIcon
} from './components/Icons';

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });

  // Global Tags State
  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    const saved = localStorage.getItem('availableTags');
    if (saved) return JSON.parse(saved);

    // Extract unique tags from initial data
    const tags = new Set<string>();
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => ex.tags.forEach(t => tags.add(t))));
    return Array.from(tags);
  });

  // UI States
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [exerciseModal, setExerciseModal] = useState<{
    isOpen: boolean;
    workoutId: string;
    exerciseId?: string; // If present, we are editing
    name: string;
    notes: string;
    tags: string[];
  } | null>(null);

  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [newCustomTag, setNewCustomTag] = useState('');

  // Entry Editing States
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [draftEntry, setDraftEntry] = useState<Entry | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  useEffect(() => {
    localStorage.setItem('availableTags', JSON.stringify(availableTags));
  }, [availableTags]);

  const addWorkout = () => {
    if (!newWorkoutName.trim()) return;
    const newWorkout: Workout = {
      id: Date.now().toString(),
      name: newWorkoutName,
      exercises: []
    };
    setWorkouts([...workouts, newWorkout]);
    setNewWorkoutName('');
    setIsAddingWorkout(false);
  };

  const deleteWorkout = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure you want to delete this workout?')) return;
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  const saveExerciseFromModal = () => {
    if (!exerciseModal || !exerciseModal.name.trim()) return;

    if (exerciseModal.exerciseId) {
      // Editing
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: w.exercises.map(ex => {
              if (ex.id === exerciseModal.exerciseId) {
                return { 
                  ...ex, 
                  name: exerciseModal.name, 
                  notes: exerciseModal.notes, 
                  tags: exerciseModal.tags 
                };
              }
              return ex;
            })
          };
        }
        return w;
      }));
    } else {
      // Adding
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: [...w.exercises, {
              id: Date.now().toString(),
              name: exerciseModal.name,
              notes: exerciseModal.notes,
              tags: exerciseModal.tags,
              entries: []
            }]
          };
        }
        return w;
      }));
    }
    setExerciseModal(null);
  };

  const deleteExercise = (workoutId: string, exerciseId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.filter(ex => ex.id !== exerciseId)
        };
      }
      return w;
    }));
    if (view.type === 'exercise-detail') {
      setView({ type: 'workout-detail', workoutId });
    }
  };

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              const existingIdx = ex.entries.findIndex(e => e.id === entry.id);
              let newEntries;
              if (existingIdx >= 0) {
                newEntries = ex.entries.map(e => e.id === entry.id ? entry : e);
              } else {
                newEntries = [...ex.entries, entry];
              }
              newEntries.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
              return { ...ex, entries: newEntries };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Remove this performance entry?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.filter(ent => ent.id !== entryId)
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const addNewGlobalTag = () => {
    const tag = newCustomTag.trim();
    if (tag && !availableTags.includes(tag)) {
      setAvailableTags([...availableTags, tag]);
      if (exerciseModal) {
        setExerciseModal({
          ...exerciseModal,
          tags: [...exerciseModal.tags, tag]
        });
      }
      setNewCustomTag('');
    }
  };

  const Modal = ({ title, onClose, onAction, actionLabel, children }: any) => (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[85vh]">
        {/* Fixed Header */}
        <div className="flex justify-between items-center px-6 pt-6 pb-4 flex-shrink-0">
          <h3 className="text-xl font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full transition-colors">
            <XIcon />
          </button>
        </div>

        {/* Scrollable Content */}
        <div className="px-6 py-2 overflow-y-auto flex-grow space-y-4 scrollbar-hide">
          {children}
        </div>

        {/* Fixed Footer */}
        <div className="px-6 pb-6 pt-4 flex gap-3 border-t border-slate-50 flex-shrink-0">
          <Button variant="secondary" className="flex-1" onClick={onClose}>Cancel</Button>
          <Button className="flex-1" onClick={onAction}>{actionLabel}</Button>
        </div>
      </div>
    </div>
  );

  const renderWorkouts = () => (
    <div className="max-w-md mx-auto min-h-screen pb-24">
      <header className="px-6 py-10">
        <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Workouts</h1>
        <p className="text-slate-500 mt-2">Manage your training routines</p>
      </header>

      <div className="px-6 space-y-4">
        {workouts.map(w => (
          <div 
            key={w.id}
            onClick={() => setView({ type: 'workout-detail', workoutId: w.id })}
            className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between active:bg-slate-50 transition-colors cursor-pointer"
          >
            <div>
              <h3 className="font-semibold text-lg text-slate-800">{w.name}</h3>
              <p className="text-sm text-slate-500">{w.exercises.length} exercises</p>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={(e) => deleteWorkout(w.id, e)}
                className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
              >
                <TrashIcon />
              </button>
              <div className="text-indigo-600">
                <ChevronRightIcon />
              </div>
            </div>
          </div>
        ))}

        <Button 
          variant="secondary" 
          fullWidth 
          onClick={() => setIsAddingWorkout(true)}
          className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
        >
          <PlusIcon /> <span className="ml-2">Create New Workout</span>
        </Button>
      </div>

      {isAddingWorkout && (
        <Modal 
          title="New Workout" 
          onClose={() => setIsAddingWorkout(false)} 
          onAction={addWorkout}
          actionLabel="Create"
        >
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Workout Name</label>
            <input 
              autoFocus
              type="text" 
              value={newWorkoutName}
              onChange={(e) => setNewWorkoutName(e.target.value)}
              placeholder="e.g. Push Day"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
        </Modal>
      )}
    </div>
  );

  const renderWorkoutDetail = (workoutId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    if (!workout) return null;

    return (
      <div className="max-w-md mx-auto min-h-screen pb-24">
        <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50 z-10">
          <button 
            onClick={() => setView({ type: 'workouts' })}
            className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"
          >
            <ChevronLeftIcon />
          </button>
          <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
        </header>

        <div className="px-6 space-y-3">
          {workout.exercises.map(ex => {
            const lastEntry = ex.entries[0];
            const isAnchor = ex.tags.includes('anchor');

            return (
              <div 
                key={ex.id}
                onClick={() => setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id })}
                className={`bg-white p-5 rounded-2xl border transition-all active:bg-slate-50 cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50/50 shadow-md' : 'border-slate-100 shadow-sm'}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                      {isAnchor && (
                        <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-2 mt-1.5">
                      {ex.tags.map(tag => tag !== 'anchor' && (
                        <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-lg">{tag}</span>
                      ))}
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteExercise(workoutId, ex.id, e)}
                    className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
                  >
                    <TrashIcon />
                  </button>
                </div>

                {lastEntry && (
                  <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2">
                    <span className="text-sm font-medium text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                    <span className="text-sm text-slate-500">at</span>
                    <span className="text-sm font-bold text-indigo-600">{lastEntry.weight}kg</span>
                  </div>
                )}
              </div>
            );
          })}

          <Button 
            variant="secondary" 
            fullWidth 
            onClick={() => setExerciseModal({
              isOpen: true,
              workoutId,
              name: '',
              notes: '',
              tags: []
            })}
            className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
          >
            <PlusIcon /> <span className="ml-2">Add Exercise</span>
          </Button>
        </div>
      </div>
    );
  };

  const renderExerciseDetail = (workoutId: string, exerciseId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    const exercise = workout?.exercises.find(e => e.id === exerciseId);
    if (!exercise) return null;

    const latestEntry = exercise.entries[0];

    const handleNewLog = () => {
      setDraftEntry({
        id: 'draft-' + Date.now(),
        date: new Date().toISOString().split('T')[0],
        sets: latestEntry?.sets || 0,
        reps: latestEntry?.reps || 0,
        weight: latestEntry?.weight || 0
      });
      setEditingEntryId(null);
    };

    const handleSaveDraft = () => {
      if (!draftEntry) return;
      commitEntry(workoutId, exerciseId, { ...draftEntry, id: Date.now().toString() });
      setDraftEntry(null);
    };

    const RowInputs = ({ entry, onChange }: { entry: Entry, onChange: (field: keyof Entry, val: any) => void }) => (
      <>
        <td className="py-2 pr-2">
          <input 
            type="date" 
            value={entry.date}
            onChange={(e) => onChange('date', e.target.value)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1 text-[10px] font-medium text-slate-800 focus:ring-1 focus:ring-indigo-500 outline-none h-9"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.sets}
            onChange={(e) => onChange('sets', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-9"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.reps}
            onChange={(e) => onChange('reps', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-9"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.weight}
            onChange={(e) => onChange('weight', parseFloat(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-9"
          />
        </td>
      </>
    );

    return (
      <div className="max-w-md mx-auto min-h-screen bg-white">
        <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
          <header className="py-6 flex items-center justify-between -mx-2">
            <button 
              onClick={() => setView({ type: 'workout-detail', workoutId })}
              className="p-2 text-slate-600 hover:bg-white rounded-full transition-colors"
            >
              <ChevronLeftIcon />
            </button>
            <div className="flex gap-2">
              <Button 
                variant="ghost" 
                size="sm"
                onClick={() => setExerciseModal({
                  isOpen: true,
                  workoutId,
                  exerciseId: exercise.id,
                  name: exercise.name,
                  notes: exercise.notes || '',
                  tags: exercise.tags
                })}
              >
                <EditIcon /> <span className="ml-1.5 text-xs">Edit</span>
              </Button>
            </div>
          </header>

          <div className="space-y-4">
            <div>
              <h1 className="text-2xl font-bold text-slate-900 leading-tight">{exercise.name}</h1>
              <div className="flex flex-wrap gap-2 mt-2">
                {exercise.tags.map(tag => (
                  <span key={tag} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600'}`}>
                    <TagIcon /> {tag}
                  </span>
                ))}
              </div>
            </div>

            {latestEntry && (
              <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600"><CheckIcon /></div>
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Latest Performance</p>
                  <p className="text-slate-800 font-bold text-lg">{latestEntry.sets}x{latestEntry.reps} <span className="text-slate-400 font-medium">@</span> {latestEntry.weight}kg</p>
                </div>
              </div>
            )}

            <div className="flex items-start gap-3 text-slate-500">
              <div className="mt-1 flex-shrink-0 text-slate-300"><InfoIcon /></div>
              <div className="text-sm italic">
                {exercise.notes || 'No notes.'}
              </div>
            </div>
          </div>
        </div>

        <div className="px-6 py-8">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold text-slate-900">History</h2>
            <Button size="sm" onClick={handleNewLog} disabled={!!draftEntry}>
              <PlusIcon /> <span className="ml-1.5">New Log</span>
            </Button>
          </div>

          <div className="overflow-x-auto -mx-6 px-6">
            <table className="w-full text-left border-collapse table-fixed">
              <thead>
                <tr className="text-[11px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="pb-4 pr-2 w-[70px]">Date</th>
                  <th className="pb-4 px-1 text-center w-[45px]">Sets</th>
                  <th className="pb-4 px-1 text-center w-[45px]">Reps</th>
                  <th className="pb-4 px-1 text-center">Kg</th>
                  <th className="pb-4 pl-2 text-right w-[85px]"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {draftEntry && (
                  <tr className="bg-indigo-50/30">
                    <RowInputs 
                      entry={draftEntry} 
                      onChange={(field, val) => setDraftEntry({ ...draftEntry, [field]: val })} 
                    />
                    <td className="py-3 pl-2 text-right">
                      <div className="flex gap-1 justify-end">
                        <button onClick={handleSaveDraft} className="p-2 bg-emerald-100 text-emerald-700 rounded-lg"><CheckIcon /></button>
                        <button onClick={() => setDraftEntry(null)} className="p-2 bg-slate-100 text-slate-400 rounded-lg"><XIcon /></button>
                      </div>
                    </td>
                  </tr>
                )}

                {exercise.entries.map(ent => (
                  <tr key={ent.id} className="group relative">
                    {editingEntryId === ent.id ? (
                      <>
                        <RowInputs 
                          entry={ent} 
                          onChange={(field, val) => {
                            setWorkouts(workouts.map(w => {
                              if (w.id === workoutId) {
                                return {
                                  ...w,
                                  exercises: w.exercises.map(ex => {
                                    if (ex.id === exerciseId) {
                                      return {
                                        ...ex,
                                        entries: ex.entries.map(e => e.id === ent.id ? { ...e, [field]: val } : e)
                                      };
                                    }
                                    return ex;
                                  })
                                };
                              }
                              return w;
                            }));
                          }} 
                        />
                        <td className="py-3 pl-2 text-right">
                          <button onClick={() => setEditingEntryId(null)} className="p-2 bg-indigo-600 text-white rounded-lg"><CheckIcon /></button>
                        </td>
                      </>
                    ) : (
                      <>
                        <td className="py-5 pr-2">
                          <div className="flex items-center gap-1 text-[10px] text-slate-500 font-medium">
                            {new Date(ent.date).toLocaleDateString(undefined, { month: '2-digit', day: '2-digit', year: 'numeric' })}
                          </div>
                        </td>
                        <td className="py-5 px-1 text-center text-slate-800 font-semibold">{ent.sets}</td>
                        <td className="py-5 px-1 text-center text-slate-800 font-semibold">{ent.reps}</td>
                        <td className="py-5 px-1 text-center text-slate-900 font-bold truncate">
                          {ent.weight}<span className="text-[10px] text-slate-400 ml-0.5 font-normal">kg</span>
                        </td>
                        <td className="py-5 pl-2 text-right relative">
                          <button 
                            onClick={(e) => { e.stopPropagation(); setActiveMenuId(activeMenuId === ent.id ? null : ent.id); }}
                            className={`p-2 rounded-lg transition-colors ${activeMenuId === ent.id ? 'bg-slate-100 text-slate-900' : 'text-slate-300 hover:text-slate-600'}`}
                          >
                            <MoreIcon />
                          </button>

                          {activeMenuId === ent.id && (
                            <>
                              <div className="fixed inset-0 z-40" onClick={() => setActiveMenuId(null)} />
                              <div className="absolute right-2 top-12 z-50 bg-white shadow-xl border border-slate-100 rounded-xl overflow-hidden w-28">
                                <button 
                                  onClick={() => { setEditingEntryId(ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                                >
                                  <EditIcon /> Edit
                                </button>
                                <button 
                                  onClick={() => { deleteEntry(workoutId, exerciseId, ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-rose-600 hover:bg-rose-50 flex items-center gap-2"
                                >
                                  <TrashIcon /> Delete
                                </button>
                              </div>
                            </>
                          )}
                        </td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {exercise.entries.length === 0 && !draftEntry && (
            <div className="py-16 text-center text-slate-400">
              <p>No history yet.</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && renderWorkouts()}
      {view.type === 'workout-detail' && renderWorkoutDetail(view.workoutId)}
      {view.type === 'exercise-detail' && renderExerciseDetail(view.workoutId, view.exerciseId)}

      {/* Shared Exercise Modal (Add/Edit) */}
      {exerciseModal && (
        <Modal 
          title={exerciseModal.exerciseId ? "Edit Exercise" : "Add Exercise"} 
          onClose={() => setExerciseModal(null)} 
          onAction={saveExerciseFromModal}
          actionLabel={exerciseModal.exerciseId ? "Save Changes" : "Add Exercise"}
        >
          <div className="space-y-5">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Name</label>
              <input 
                autoFocus
                type="text" 
                value={exerciseModal.name}
                onChange={(e) => setExerciseModal({ ...exerciseModal, name: e.target.value })}
                placeholder="Exercise Name"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Tags</label>
              <div className="flex flex-wrap gap-2 mb-3">
                {exerciseModal.tags.map((tag, idx) => (
                  <span key={idx} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-700'}`}>
                    {tag}
                    <button onClick={() => setExerciseModal({ ...exerciseModal, tags: exerciseModal.tags.filter((_, i) => i !== idx) })} className="hover:text-rose-500 font-bold">×</button>
                  </span>
                ))}
              </div>

              {/* Tag Selector Dropdown */}
              <div className="space-y-3">
                <select 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm text-slate-600 focus:ring-2 focus:ring-indigo-500 outline-none"
                  onChange={(e) => {
                    const selected = e.target.value;
                    if (selected && !exerciseModal.tags.includes(selected)) {
                      setExerciseModal({ ...exerciseModal, tags: [...exerciseModal.tags, selected] });
                    }
                    e.target.value = ''; // Reset
                  }}
                >
                  <option value="">Select existing tag...</option>
                  {availableTags.filter(t => !exerciseModal.tags.includes(t)).map(t => (
                    <option key={t} value={t}>{t}</option>
                  ))}
                </select>

                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={newCustomTag}
                    onChange={(e) => setNewCustomTag(e.target.value)}
                    placeholder="New custom tag..."
                    className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                  <button 
                    onClick={addNewGlobalTag}
                    className="w-10 h-10 bg-slate-100 text-slate-600 rounded-xl flex items-center justify-center hover:bg-slate-200"
                  >
                    <PlusIcon />
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Notes</label>
              <textarea 
                value={exerciseModal.notes}
                onChange={(e) => setExerciseModal({ ...exerciseModal, notes: e.target.value })}
                placeholder="Tips, cues, or focus points..."
                rows={4}
                className="w-full text-sm bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
              />
            </div>
            {/* Added some extra bottom space inside scroll area */}
            <div className="h-4"></div>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon,
  TagIcon,
  MoreIcon,
  XIcon,
  CalendarIcon
} from './components/Icons';

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });

  // Global Tags State
  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    const saved = localStorage.getItem('availableTags');
    if (saved) return JSON.parse(saved);

    // Extract unique tags from initial data
    const tags = new Set<string>();
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => ex.tags.forEach(t => tags.add(t))));
    return Array.from(tags);
  });

  // UI States
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [exerciseModal, setExerciseModal] = useState<{
    isOpen: boolean;
    workoutId: string;
    exerciseId?: string; // If present, we are editing
    name: string;
    notes: string;
    tags: string[];
  } | null>(null);

  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [newCustomTag, setNewCustomTag] = useState('');

  // Entry Editing States
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [draftEntry, setDraftEntry] = useState<Entry | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  useEffect(() => {
    localStorage.setItem('availableTags', JSON.stringify(availableTags));
  }, [availableTags]);

  const addWorkout = () => {
    if (!newWorkoutName.trim()) return;
    const newWorkout: Workout = {
      id: Date.now().toString(),
      name: newWorkoutName,
      exercises: []
    };
    setWorkouts([...workouts, newWorkout]);
    setNewWorkoutName('');
    setIsAddingWorkout(false);
  };

  const deleteWorkout = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure you want to delete this workout?')) return;
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  const saveExerciseFromModal = () => {
    if (!exerciseModal || !exerciseModal.name.trim()) return;

    if (exerciseModal.exerciseId) {
      // Editing
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: w.exercises.map(ex => {
              if (ex.id === exerciseModal.exerciseId) {
                return { 
                  ...ex, 
                  name: exerciseModal.name, 
                  notes: exerciseModal.notes, 
                  tags: exerciseModal.tags 
                };
              }
              return ex;
            })
          };
        }
        return w;
      }));
    } else {
      // Adding
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: [...w.exercises, {
              id: Date.now().toString(),
              name: exerciseModal.name,
              notes: exerciseModal.notes,
              tags: exerciseModal.tags,
              entries: []
            }]
          };
        }
        return w;
      }));
    }
    setExerciseModal(null);
  };

  const deleteExercise = (workoutId: string, exerciseId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.filter(ex => ex.id !== exerciseId)
        };
      }
      return w;
    }));
    if (view.type === 'exercise-detail') {
      setView({ type: 'workout-detail', workoutId });
    }
  };

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              const existingIdx = ex.entries.findIndex(e => e.id === entry.id);
              let newEntries;
              if (existingIdx >= 0) {
                newEntries = ex.entries.map(e => e.id === entry.id ? entry : e);
              } else {
                newEntries = [...ex.entries, entry];
              }
              newEntries.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
              return { ...ex, entries: newEntries };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Remove this performance entry?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.filter(ent => ent.id !== entryId)
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const addNewGlobalTag = () => {
    const tag = newCustomTag.trim();
    if (tag && !availableTags.includes(tag)) {
      setAvailableTags([...availableTags, tag]);
      if (exerciseModal) {
        setExerciseModal({
          ...exerciseModal,
          tags: [...exerciseModal.tags, tag]
        });
      }
      setNewCustomTag('');
    }
  };

  const Modal = ({ title, onClose, onAction, actionLabel, children }: any) => (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[85vh]">
        {/* Fixed Header */}
        <div className="flex justify-between items-center px-6 pt-6 pb-4 flex-shrink-0">
          <h3 className="text-xl font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full transition-colors">
            <XIcon />
          </button>
        </div>

        {/* Scrollable Content */}
        <div className="px-6 py-2 overflow-y-auto flex-grow space-y-4 scrollbar-hide">
          {children}
        </div>

        {/* Fixed Footer */}
        <div className="px-6 pb-6 pt-4 flex gap-3 border-t border-slate-50 flex-shrink-0">
          <Button variant="secondary" className="flex-1" onClick={onClose}>Cancel</Button>
          <Button className="flex-1" onClick={onAction}>{actionLabel}</Button>
        </div>
      </div>
    </div>
  );

  const renderWorkouts = () => (
    <div className="max-w-md mx-auto min-h-screen pb-24">
      <header className="px-6 py-10">
        <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Workouts</h1>
        <p className="text-slate-500 mt-2">Manage your training routines</p>
      </header>

      <div className="px-6 space-y-4">
        {workouts.map(w => (
          <div 
            key={w.id}
            onClick={() => setView({ type: 'workout-detail', workoutId: w.id })}
            className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between active:bg-slate-50 transition-colors cursor-pointer"
          >
            <div>
              <h3 className="font-semibold text-lg text-slate-800">{w.name}</h3>
              <p className="text-sm text-slate-500">{w.exercises.length} exercises</p>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={(e) => deleteWorkout(w.id, e)}
                className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
              >
                <TrashIcon />
              </button>
              <div className="text-indigo-600">
                <ChevronRightIcon />
              </div>
            </div>
          </div>
        ))}

        <Button 
          variant="secondary" 
          fullWidth 
          onClick={() => setIsAddingWorkout(true)}
          className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
        >
          <PlusIcon /> <span className="ml-2">Create New Workout</span>
        </Button>
      </div>

      {isAddingWorkout && (
        <Modal 
          title="New Workout" 
          onClose={() => setIsAddingWorkout(false)} 
          onAction={addWorkout}
          actionLabel="Create"
        >
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Workout Name</label>
            <input 
              autoFocus
              type="text" 
              value={newWorkoutName}
              onChange={(e) => setNewWorkoutName(e.target.value)}
              placeholder="e.g. Push Day"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
        </Modal>
      )}
    </div>
  );

  const renderWorkoutDetail = (workoutId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    if (!workout) return null;

    return (
      <div className="max-w-md mx-auto min-h-screen pb-24">
        <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50 z-10">
          <button 
            onClick={() => setView({ type: 'workouts' })}
            className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"
          >
            <ChevronLeftIcon />
          </button>
          <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
        </header>

        <div className="px-6 space-y-3">
          {workout.exercises.map(ex => {
            const lastEntry = ex.entries[0];
            const isAnchor = ex.tags.includes('anchor');

            return (
              <div 
                key={ex.id}
                onClick={() => setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id })}
                className={`bg-white p-5 rounded-2xl border transition-all active:bg-slate-50 cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50/50 shadow-md' : 'border-slate-100 shadow-sm'}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                      {isAnchor && (
                        <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-2 mt-1.5">
                      {ex.tags.map(tag => tag !== 'anchor' && (
                        <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-lg">{tag}</span>
                      ))}
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteExercise(workoutId, ex.id, e)}
                    className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
                  >
                    <TrashIcon />
                  </button>
                </div>

                {lastEntry && (
                  <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2">
                    <span className="text-sm font-medium text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                    <span className="text-sm text-slate-500">at</span>
                    <span className="text-sm font-bold text-indigo-600">{lastEntry.weight}kg</span>
                  </div>
                )}
              </div>
            );
          })}

          <Button 
            variant="secondary" 
            fullWidth 
            onClick={() => setExerciseModal({
              isOpen: true,
              workoutId,
              name: '',
              notes: '',
              tags: []
            })}
            className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
          >
            <PlusIcon /> <span className="ml-2">Add Exercise</span>
          </Button>
        </div>
      </div>
    );
  };

  const renderExerciseDetail = (workoutId: string, exerciseId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    const exercise = workout?.exercises.find(e => e.id === exerciseId);
    if (!exercise) return null;

    const latestEntry = exercise.entries[0];

    const handleNewLog = () => {
      setDraftEntry({
        id: 'draft-' + Date.now(),
        date: new Date().toISOString().split('T')[0],
        sets: latestEntry?.sets || 0,
        reps: latestEntry?.reps || 0,
        weight: latestEntry?.weight || 0
      });
      setEditingEntryId(null);
    };

    const handleSaveDraft = () => {
      if (!draftEntry) return;
      commitEntry(workoutId, exerciseId, { ...draftEntry, id: Date.now().toString() });
      setDraftEntry(null);
    };

    const RowInputs = ({ entry, onChange }: { entry: Entry, onChange: (field: keyof Entry, val: any) => void }) => (
      <>
        <td className="py-2 pr-2">
          <input 
            type="date" 
            value={entry.date}
            onChange={(e) => onChange('date', e.target.value)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1 text-[10px] font-medium text-slate-800 focus:ring-1 focus:ring-indigo-500 outline-none h-9"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.sets}
            onChange={(e) => onChange('sets', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-9"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.reps}
            onChange={(e) => onChange('reps', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-9"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.weight}
            onChange={(e) => onChange('weight', parseFloat(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-lg p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-9"
          />
        </td>
      </>
    );

    return (
      <div className="max-w-md mx-auto min-h-screen bg-white pb-32">
        <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
          <header className="py-6 flex items-center justify-between -mx-2">
            <button 
              onClick={() => setView({ type: 'workout-detail', workoutId })}
              className="p-2 text-slate-600 hover:bg-white rounded-full transition-colors"
            >
              <ChevronLeftIcon />
            </button>
            <div className="flex gap-2">
              <Button 
                variant="ghost" 
                size="sm"
                onClick={() => setExerciseModal({
                  isOpen: true,
                  workoutId,
                  exerciseId: exercise.id,
                  name: exercise.name,
                  notes: exercise.notes || '',
                  tags: exercise.tags
                })}
              >
                <EditIcon /> <span className="ml-1.5 text-xs">Edit</span>
              </Button>
            </div>
          </header>

          <div className="space-y-4">
            <div>
              <h1 className="text-2xl font-bold text-slate-900 leading-tight">{exercise.name}</h1>
              <div className="flex flex-wrap gap-2 mt-2">
                {exercise.tags.map(tag => (
                  <span key={tag} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600'}`}>
                    <TagIcon /> {tag}
                  </span>
                ))}
              </div>
            </div>

            {latestEntry && (
              <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600"><CheckIcon /></div>
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Latest Performance</p>
                  <p className="text-slate-800 font-bold text-lg">{latestEntry.sets}x{latestEntry.reps} <span className="text-slate-400 font-medium">@</span> {latestEntry.weight}kg</p>
                </div>
              </div>
            )}

            <div className="flex items-start gap-3 text-slate-500">
              <div className="mt-1 flex-shrink-0 text-slate-300"><InfoIcon /></div>
              <div className="text-sm italic">
                {exercise.notes || 'No notes.'}
              </div>
            </div>
          </div>
        </div>

        <div className="px-6 py-8">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold text-slate-900">History</h2>
            <Button size="sm" onClick={handleNewLog} disabled={!!draftEntry}>
              <PlusIcon /> <span className="ml-1.5">New Log</span>
            </Button>
          </div>

          <div className="relative">
            <table className="w-full text-left border-collapse table-fixed">
              <thead>
                <tr className="text-[11px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="pb-4 pr-2 w-[70px]">Date</th>
                  <th className="pb-4 px-1 text-center w-[45px]">Sets</th>
                  <th className="pb-4 px-1 text-center w-[45px]">Reps</th>
                  <th className="pb-4 px-1 text-center">Kg</th>
                  <th className="pb-4 pl-2 text-right w-[85px]"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {draftEntry && (
                  <tr className="bg-indigo-50/30">
                    <RowInputs 
                      entry={draftEntry} 
                      onChange={(field, val) => setDraftEntry({ ...draftEntry, [field]: val })} 
                    />
                    <td className="py-3 pl-2 text-right">
                      <div className="flex gap-1 justify-end">
                        <button onClick={handleSaveDraft} className="p-2 bg-emerald-100 text-emerald-700 rounded-lg"><CheckIcon /></button>
                        <button onClick={() => setDraftEntry(null)} className="p-2 bg-slate-100 text-slate-400 rounded-lg"><XIcon /></button>
                      </div>
                    </td>
                  </tr>
                )}

                {exercise.entries.map(ent => (
                  <tr key={ent.id} className="group relative">
                    {editingEntryId === ent.id ? (
                      <>
                        <RowInputs 
                          entry={ent} 
                          onChange={(field, val) => {
                            setWorkouts(workouts.map(w => {
                              if (w.id === workoutId) {
                                return {
                                  ...w,
                                  exercises: w.exercises.map(ex => {
                                    if (ex.id === exerciseId) {
                                      return {
                                        ...ex,
                                        entries: ex.entries.map(e => e.id === ent.id ? { ...e, [field]: val } : e)
                                      };
                                    }
                                    return ex;
                                  })
                                };
                              }
                              return w;
                            }));
                          }} 
                        />
                        <td className="py-3 pl-2 text-right">
                          <button onClick={() => setEditingEntryId(null)} className="p-2 bg-indigo-600 text-white rounded-lg"><CheckIcon /></button>
                        </td>
                      </>
                    ) : (
                      <>
                        <td className="py-5 pr-2">
                          <div className="flex items-center gap-1 text-[10px] text-slate-500 font-medium">
                            {new Date(ent.date).toLocaleDateString(undefined, { month: '2-digit', day: '2-digit', year: 'numeric' })}
                          </div>
                        </td>
                        <td className="py-5 px-1 text-center text-slate-800 font-semibold">{ent.sets}</td>
                        <td className="py-5 px-1 text-center text-slate-800 font-semibold">{ent.reps}</td>
                        <td className="py-5 px-1 text-center text-slate-900 font-bold truncate">
                          {ent.weight}<span className="text-[10px] text-slate-400 ml-0.5 font-normal">kg</span>
                        </td>
                        <td className="py-5 pl-2 text-right relative">
                          <button 
                            onClick={(e) => { e.stopPropagation(); setActiveMenuId(activeMenuId === ent.id ? null : ent.id); }}
                            className={`p-2 rounded-lg transition-colors ${activeMenuId === ent.id ? 'bg-slate-100 text-slate-900' : 'text-slate-300 hover:text-slate-600'}`}
                          >
                            <MoreIcon />
                          </button>

                          {activeMenuId === ent.id && (
                            <>
                              <div className="fixed inset-0 z-40" onClick={() => setActiveMenuId(null)} />
                              <div className="absolute right-0 top-12 z-[60] bg-white shadow-xl border border-slate-100 rounded-xl overflow-hidden w-28">
                                <button 
                                  onClick={() => { setEditingEntryId(ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                                >
                                  <EditIcon /> Edit
                                </button>
                                <button 
                                  onClick={() => { deleteEntry(workoutId, exerciseId, ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3 text-left text-sm font-medium text-rose-600 hover:bg-rose-50 flex items-center gap-2"
                                >
                                  <TrashIcon /> Delete
                                </button>
                              </div>
                            </>
                          )}
                        </td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {exercise.entries.length === 0 && !draftEntry && (
            <div className="py-16 text-center text-slate-400">
              <p>No history yet.</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && renderWorkouts()}
      {view.type === 'workout-detail' && renderWorkoutDetail(view.workoutId)}
      {view.type === 'exercise-detail' && renderExerciseDetail(view.workoutId, view.exerciseId)}

      {/* Shared Exercise Modal (Add/Edit) */}
      {exerciseModal && (
        <Modal 
          title={exerciseModal.exerciseId ? "Edit Exercise" : "Add Exercise"} 
          onClose={() => setExerciseModal(null)} 
          onAction={saveExerciseFromModal}
          actionLabel={exerciseModal.exerciseId ? "Save Changes" : "Add Exercise"}
        >
          <div className="space-y-5">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Name</label>
              <input 
                autoFocus
                type="text" 
                value={exerciseModal.name}
                onChange={(e) => setExerciseModal({ ...exerciseModal, name: e.target.value })}
                placeholder="Exercise Name"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Tags</label>
              <div className="flex flex-wrap gap-2 mb-3">
                {exerciseModal.tags.map((tag, idx) => (
                  <span key={idx} className={`px-2 py-1 text-xs font-medium rounded-lg flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-700'}`}>
                    {tag}
                    <button onClick={() => setExerciseModal({ ...exerciseModal, tags: exerciseModal.tags.filter((_, i) => i !== idx) })} className="hover:text-rose-500 font-bold">×</button>
                  </span>
                ))}
              </div>

              {/* Tag Selector Dropdown */}
              <div className="space-y-3">
                <select 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm text-slate-600 focus:ring-2 focus:ring-indigo-500 outline-none"
                  onChange={(e) => {
                    const selected = e.target.value;
                    if (selected && !exerciseModal.tags.includes(selected)) {
                      setExerciseModal({ ...exerciseModal, tags: [...exerciseModal.tags, selected] });
                    }
                    e.target.value = ''; // Reset
                  }}
                >
                  <option value="">Select existing tag...</option>
                  {availableTags.filter(t => !exerciseModal.tags.includes(t)).map(t => (
                    <option key={t} value={t}>{t}</option>
                  ))}
                </select>

                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={newCustomTag}
                    onChange={(e) => setNewCustomTag(e.target.value)}
                    placeholder="New custom tag..."
                    className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                  <button 
                    onClick={addNewGlobalTag}
                    className="w-10 h-10 bg-slate-100 text-slate-600 rounded-xl flex items-center justify-center hover:bg-slate-200"
                  >
                    <PlusIcon />
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Notes</label>
              <textarea 
                value={exerciseModal.notes}
                onChange={(e) => setExerciseModal({ ...exerciseModal, notes: e.target.value })}
                placeholder="Tips, cues, or focus points..."
                rows={4}
                className="w-full text-sm bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
              />
            </div>
            {/* Added some extra bottom space inside scroll area */}
            <div className="h-4"></div>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

