import React, { useState, useEffect } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon,
  TagIcon,
  MoreIcon,
  XIcon,
  CalendarIcon,
  TrendingUpIcon,
  ActivityIcon
} from './components/Icons';

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });

  // Global Tags State
  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    const saved = localStorage.getItem('availableTags');
    if (saved) return JSON.parse(saved);

    // Extract unique tags from initial data
    const tags = new Set<string>();
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => ex.tags.forEach(t => tags.add(t))));
    return Array.from(tags);
  });

  // UI States
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [exerciseModal, setExerciseModal] = useState<{
    isOpen: boolean;
    workoutId: string;
    exerciseId?: string; // If present, we are editing
    name: string;
    notes: string;
    tags: string[];
  } | null>(null);

  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [newCustomTag, setNewCustomTag] = useState('');

  // Entry Editing States
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [draftEntry, setDraftEntry] = useState<Entry | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  useEffect(() => {
    localStorage.setItem('availableTags', JSON.stringify(availableTags));
  }, [availableTags]);

  const addWorkout = () => {
    if (!newWorkoutName.trim()) return;
    const newWorkout: Workout = {
      id: Date.now().toString(),
      name: newWorkoutName,
      exercises: []
    };
    setWorkouts([...workouts, newWorkout]);
    setNewWorkoutName('');
    setIsAddingWorkout(false);
  };

  const deleteWorkout = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure you want to delete this workout?')) return;
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  const saveExerciseFromModal = () => {
    if (!exerciseModal || !exerciseModal.name.trim()) return;

    if (exerciseModal.exerciseId) {
      // Editing
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: w.exercises.map(ex => {
              if (ex.id === exerciseModal.exerciseId) {
                return { 
                  ...ex, 
                  name: exerciseModal.name, 
                  notes: exerciseModal.notes, 
                  tags: exerciseModal.tags 
                };
              }
              return ex;
            })
          };
        }
        return w;
      }));
    } else {
      // Adding
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: [...w.exercises, {
              id: Date.now().toString(),
              name: exerciseModal.name,
              notes: exerciseModal.notes,
              tags: exerciseModal.tags,
              entries: []
            }]
          };
        }
        return w;
      }));
    }
    setExerciseModal(null);
  };

  const deleteExercise = (workoutId: string, exerciseId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.filter(ex => ex.id !== exerciseId)
        };
      }
      return w;
    }));
    if (view.type === 'exercise-detail') {
      setView({ type: 'workout-detail', workoutId });
    }
  };

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              const existingIdx = ex.entries.findIndex(e => e.id === entry.id);
              let newEntries;
              if (existingIdx >= 0) {
                newEntries = ex.entries.map(e => e.id === entry.id ? entry : e);
              } else {
                newEntries = [...ex.entries, entry];
              }
              newEntries.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
              return { ...ex, entries: newEntries };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Remove this performance entry?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              return {
                ...ex,
                entries: ex.entries.filter(ent => ent.id !== entryId)
              };
            }
            return ex;
          })
        };
      }
      return w;
    }));
  };

  const addNewGlobalTag = () => {
    const tag = newCustomTag.trim();
    if (tag && !availableTags.includes(tag)) {
      setAvailableTags([...availableTags, tag]);
      if (exerciseModal) {
        setExerciseModal({
          ...exerciseModal,
          tags: [...exerciseModal.tags, tag]
        });
      }
      setNewCustomTag('');
    }
  };

  const Modal = ({ title, onClose, onAction, actionLabel, children }: any) => (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[85vh]">
        {/* Fixed Header */}
        <div className="flex justify-between items-center px-6 pt-6 pb-4 flex-shrink-0">
          <h3 className="text-xl font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full transition-colors">
            <XIcon />
          </button>
        </div>

        {/* Scrollable Content */}
        <div className="px-6 py-2 overflow-y-auto flex-grow space-y-4 scrollbar-hide">
          {children}
        </div>

        {/* Fixed Footer */}
        <div className="px-6 pb-6 pt-4 flex gap-3 border-t border-slate-50 flex-shrink-0">
          <Button variant="secondary" className="flex-1" onClick={onClose}>Cancel</Button>
          <Button className="flex-1" onClick={onAction}>{actionLabel}</Button>
        </div>
      </div>
    </div>
  );

  const renderWorkouts = () => (
    <div className="max-w-md mx-auto min-h-screen pb-24">
      <header className="px-6 py-10">
        <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Workouts</h1>
        <p className="text-slate-500 mt-2">Manage your training routines</p>
      </header>

      <div className="px-6 space-y-4">
        {workouts.map(w => (
          <div 
            key={w.id}
            onClick={() => setView({ type: 'workout-detail', workoutId: w.id })}
            className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between active:bg-slate-50 transition-colors cursor-pointer"
          >
            <div>
              <h3 className="font-semibold text-lg text-slate-800">{w.name}</h3>
              <p className="text-sm text-slate-500">{w.exercises.length} exercises</p>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={(e) => deleteWorkout(w.id, e)}
                className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
              >
                <TrashIcon />
              </button>
              <div className="text-indigo-600">
                <ChevronRightIcon />
              </div>
            </div>
          </div>
        ))}

        <Button 
          variant="secondary" 
          fullWidth 
          onClick={() => setIsAddingWorkout(true)}
          className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
        >
          <PlusIcon /> <span className="ml-2">Create New Workout</span>
        </Button>
      </div>

      {isAddingWorkout && (
        <Modal 
          title="New Workout" 
          onClose={() => setIsAddingWorkout(false)} 
          onAction={addWorkout}
          actionLabel="Create"
        >
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Workout Name</label>
            <input 
              autoFocus
              type="text" 
              value={newWorkoutName}
              onChange={(e) => setNewWorkoutName(e.target.value)}
              placeholder="e.g. Push Day"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
        </Modal>
      )}
    </div>
  );

  const renderWorkoutDetail = (workoutId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    if (!workout) return null;

    return (
      <div className="max-w-md mx-auto min-h-screen pb-24">
        <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50 z-10">
          <button 
            onClick={() => setView({ type: 'workouts' })}
            className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"
          >
            <ChevronLeftIcon />
          </button>
          <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
        </header>

        <div className="px-6 space-y-3">
          {workout.exercises.map(ex => {
            const lastEntry = ex.entries[0];
            const isAnchor = ex.tags.includes('anchor');

            return (
              <div 
                key={ex.id}
                onClick={() => setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id })}
                className={`bg-white p-5 rounded-2xl border transition-all active:bg-slate-50 cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50/50 shadow-md' : 'border-slate-100 shadow-sm'}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                      {isAnchor && (
                        <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-2 mt-1.5">
                      {ex.tags.map(tag => tag !== 'anchor' && (
                        <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-lg">{tag}</span>
                      ))}
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteExercise(workoutId, ex.id, e)}
                    className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
                  >
                    <TrashIcon />
                  </button>
                </div>

                {lastEntry && (
                  <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2">
                    <span className="text-sm font-medium text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                    <span className="text-sm text-slate-500">at</span>
                    <span className="text-sm font-bold text-indigo-600">{lastEntry.weight}kg</span>
                  </div>
                )}
              </div>
            );
          })}

          <Button 
            variant="secondary" 
            fullWidth 
            onClick={() => setExerciseModal({
              isOpen: true,
              workoutId,
              name: '',
              notes: '',
              tags: []
            })}
            className="mt-6 border-dashed bg-transparent py-6 rounded-2xl"
          >
            <PlusIcon /> <span className="ml-2">Add Exercise</span>
          </Button>
        </div>
      </div>
    );
  };

  const renderExerciseDetail = (workoutId: string, exerciseId: string) => {
    const workout = workouts.find(w => w.id === workoutId);
    const exercise = workout?.exercises.find(e => e.id === exerciseId);
    if (!exercise) return null;

    const latestEntry = exercise.entries[0];

    const handleNewLog = () => {
      setDraftEntry({
        id: 'draft-' + Date.now(),
        date: new Date().toISOString().split('T')[0],
        sets: latestEntry?.sets || 0,
        reps: latestEntry?.reps || 0,
        weight: latestEntry?.weight || 0
      });
      setEditingEntryId(null);
      setActiveMenuId(null);
    };

    const handleSaveDraft = () => {
      if (!draftEntry) return;
      commitEntry(workoutId, exerciseId, { ...draftEntry, id: Date.now().toString() });
      setDraftEntry(null);
    };

    const RowInputs = ({ entry, onChange }: { entry: Entry, onChange: (field: keyof Entry, val: any) => void }) => (
      <>
        <td className="py-2 pr-2">
          <input 
            type="date" 
            value={entry.date}
            onChange={(e) => onChange('date', e.target.value)}
            className="w-full bg-indigo-50 border-none rounded-xl p-1 text-[10px] font-bold text-indigo-900 focus:ring-1 focus:ring-indigo-500 outline-none h-10"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.sets}
            onChange={(e) => onChange('sets', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-xl p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-10"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.reps}
            onChange={(e) => onChange('reps', parseInt(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-xl p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-10"
          />
        </td>
        <td className="py-2 px-1">
          <input 
            type="number" 
            value={entry.weight}
            onChange={(e) => onChange('weight', parseFloat(e.target.value) || 0)}
            className="w-full bg-indigo-50 border-none rounded-xl p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-10"
          />
        </td>
      </>
    );

    return (
      <div className="max-w-md mx-auto min-h-screen bg-white">
        {/* Modern Exercise Header Section */}
        <div className="bg-gradient-to-b from-slate-50 to-white px-6 pb-10 border-b border-slate-100">
          <header className="py-6 flex items-center justify-between -mx-2">
            <button 
              onClick={() => setView({ type: 'workout-detail', workoutId })}
              className="p-2 text-slate-500 hover:bg-white hover:shadow-sm rounded-full transition-all"
            >
              <ChevronLeftIcon />
            </button>
            <div className="flex gap-2">
              <Button 
                variant="ghost" 
                size="sm"
                className="hover:shadow-sm bg-white/50"
                onClick={() => setExerciseModal({
                  isOpen: true,
                  workoutId,
                  exerciseId: exercise.id,
                  name: exercise.name,
                  notes: exercise.notes || '',
                  tags: exercise.tags
                })}
              >
                <EditIcon /> <span className="ml-1.5 text-xs font-semibold">Edit</span>
              </Button>
            </div>
          </header>

          <div className="space-y-6">
            <div>
              <h1 className="text-2xl font-bold text-slate-900 leading-tight tracking-tight">{exercise.name}</h1>
              <div className="flex flex-wrap gap-2 mt-3">
                {exercise.tags.map(tag => (
                  <span key={tag} className={`px-2.5 py-1 text-[11px] font-bold rounded-lg flex items-center gap-1.5 shadow-sm ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600 uppercase tracking-tight'}`}>
                    <TagIcon /> {tag}
                  </span>
                ))}
              </div>
            </div>

            {/* Elevated Performance Card */}
            {latestEntry ? (
              <div className="relative overflow-hidden group">
                <div className="absolute inset-0 bg-indigo-600 rounded-2xl opacity-5 translate-y-1"></div>
                <div className="relative bg-white p-5 rounded-2xl border border-indigo-100 shadow-[0_8px_30px_rgb(0,0,0,0.04)] flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 shadow-inner">
                      <TrendingUpIcon />
                    </div>
                    <div>
                      <p className="text-[10px] text-slate-400 uppercase font-black tracking-[0.1em] mb-0.5">Performance</p>
                      <div className="flex items-baseline gap-2">
                        <span className="text-slate-900 font-extrabold text-2xl tracking-tighter">{latestEntry.sets}<span className="text-slate-300 text-lg mx-1">×</span>{latestEntry.reps}</span>
                        <span className="text-indigo-600 font-black text-2xl tracking-tighter">{latestEntry.weight}<span className="text-xs uppercase ml-0.5 font-bold">kg</span></span>
                      </div>
                    </div>
                  </div>
                  <div className="text-[10px] font-bold text-indigo-400/60 rotate-90 origin-right whitespace-nowrap">LATEST LOG</div>
                </div>
              </div>
            ) : (
              <div className="bg-slate-50 p-5 rounded-2xl border border-dashed border-slate-200 flex items-center gap-4 opacity-70">
                <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-slate-300"><ActivityIcon /></div>
                <div>
                   <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">No Performance Yet</p>
                   <p className="text-slate-500 text-sm font-medium italic">Log your first session below</p>
                </div>
              </div>
            )}

            <div className="flex items-start gap-3 bg-white/40 p-3 rounded-xl border border-slate-100">
              <div className="mt-0.5 flex-shrink-0 text-slate-300"><InfoIcon /></div>
              <div className="text-xs font-medium text-slate-500 leading-relaxed italic">
                {exercise.notes || 'Add cues or focus points in edit mode.'}
              </div>
            </div>
          </div>
        </div>

        {/* Modern History Section */}
        <div className="px-6 py-10 pb-40 min-h-[60vh]">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold text-slate-900 tracking-tight">Activity Log</h2>
            <Button 
              size="sm" 
              onClick={handleNewLog} 
              disabled={!!draftEntry}
              className="shadow-indigo-100 shadow-lg px-4"
            >
              <PlusIcon /> <span className="ml-1.5 font-bold">Log Session</span>
            </Button>
          </div>

          <div className="relative">
            <table className="w-full text-left border-collapse table-fixed">
              <thead>
                <tr className="text-[11px] font-black text-slate-400 uppercase tracking-[0.1em] border-b border-slate-50">
                  <th className="pb-4 pr-2 w-[75px]">Date</th>
                  <th className="pb-4 px-1 text-center w-[45px]">Sets</th>
                  <th className="pb-4 px-1 text-center w-[45px]">Reps</th>
                  <th className="pb-4 px-1 text-center">Kg</th>
                  <th className="pb-4 pl-2 text-right w-[85px]"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {draftEntry && (
                  <tr className="bg-indigo-50/40 animate-in fade-in slide-in-from-top-4 duration-300">
                    <RowInputs 
                      entry={draftEntry} 
                      onChange={(field, val) => setDraftEntry({ ...draftEntry, [field]: val })} 
                    />
                    <td className="py-3 pl-2 text-right">
                      <div className="flex gap-1 justify-end">
                        <button onClick={handleSaveDraft} className="p-2.5 bg-emerald-500 text-white rounded-xl shadow-lg shadow-emerald-100 active:scale-95 transition-all"><CheckIcon /></button>
                        <button onClick={() => setDraftEntry(null)} className="p-2.5 bg-slate-100 text-slate-400 rounded-xl active:scale-95 transition-all"><XIcon /></button>
                      </div>
                    </td>
                  </tr>
                )}

                {exercise.entries.map(ent => (
                  <tr key={ent.id} className="group relative hover:bg-slate-50/50 transition-colors">
                    {editingEntryId === ent.id ? (
                      <>
                        <RowInputs 
                          entry={ent} 
                          onChange={(field, val) => {
                            setWorkouts(workouts.map(w => {
                              if (w.id === workoutId) {
                                return {
                                  ...w,
                                  exercises: w.exercises.map(ex => {
                                    if (ex.id === exerciseId) {
                                      return {
                                        ...ex,
                                        entries: ex.entries.map(e => e.id === ent.id ? { ...e, [field]: val } : e)
                                      };
                                    }
                                    return ex;
                                  })
                                };
                              }
                              return w;
                            }));
                          }} 
                        />
                        <td className="py-3 pl-2 text-right">
                          <button onClick={() => setEditingEntryId(null)} className="p-2.5 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-100 active:scale-95 transition-all"><CheckIcon /></button>
                        </td>
                      </>
                    ) : (
                      <>
                        <td className="py-6 pr-2">
                          <div className="flex flex-col">
                            <span className="text-[11px] font-bold text-slate-800">
                              {new Date(ent.date).toLocaleDateString(undefined, { month: '2-digit', day: '2-digit' })}
                            </span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">
                              {new Date(ent.date).getFullYear()}
                            </span>
                          </div>
                        </td>
                        <td className="py-6 px-1 text-center text-slate-600 font-bold">{ent.sets}</td>
                        <td className="py-6 px-1 text-center text-slate-600 font-bold">{ent.reps}</td>
                        <td className="py-6 px-1 text-center text-indigo-600 font-black truncate">
                          {ent.weight}<span className="text-[9px] text-indigo-300 ml-0.5 font-bold tracking-tighter">KG</span>
                        </td>
                        <td className="py-6 pl-2 text-right relative">
                          <button 
                            onClick={(e) => { e.stopPropagation(); setActiveMenuId(activeMenuId === ent.id ? null : ent.id); }}
                            className={`p-2 rounded-xl transition-all ${activeMenuId === ent.id ? 'bg-slate-200 text-slate-900 scale-105 shadow-sm' : 'text-slate-300 hover:text-slate-600 hover:bg-slate-100'}`}
                          >
                            <MoreIcon />
                          </button>

                          {activeMenuId === ent.id && (
                            <>
                              <div className="fixed inset-0 z-[55]" onClick={() => setActiveMenuId(null)} />
                              <div className="absolute right-0 top-14 z-[60] bg-white shadow-[0_10px_40px_rgba(0,0,0,0.1)] border border-slate-100 rounded-2xl overflow-hidden w-32 animate-in fade-in slide-in-from-top-2 duration-150">
                                <button 
                                  onClick={() => { setEditingEntryId(ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3.5 text-left text-sm font-bold text-slate-700 hover:bg-slate-50 flex items-center gap-3 transition-colors"
                                >
                                  <span className="text-slate-300"><EditIcon /></span> Edit
                                </button>
                                <button 
                                  onClick={() => { deleteEntry(workoutId, exerciseId, ent.id); setActiveMenuId(null); }}
                                  className="w-full px-4 py-3.5 text-left text-sm font-bold text-rose-600 hover:bg-rose-50 flex items-center gap-3 transition-colors"
                                >
                                  <span className="text-rose-300"><TrashIcon /></span> Delete
                                </button>
                              </div>
                            </>
                          )}
                        </td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {exercise.entries.length === 0 && !draftEntry && (
            <div className="py-24 text-center space-y-4">
              <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto text-slate-200">
                <ActivityIcon />
              </div>
              <div>
                <p className="font-bold text-slate-400 tracking-tight">No sessions logged</p>
                <p className="text-xs text-slate-400 mt-1 max-w-[200px] mx-auto leading-relaxed">Your journey begins with the first rep. Tap 'Log Session' to track progress.</p>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 selection:bg-indigo-100">
      {view.type === 'workouts' && renderWorkouts()}
      {view.type === 'workout-detail' && renderWorkoutDetail(view.workoutId)}
      {view.type === 'exercise-detail' && renderExerciseDetail(view.workoutId, view.exerciseId)}

      {/* Shared Exercise Modal (Add/Edit) */}
      {exerciseModal && (
        <Modal 
          title={exerciseModal.exerciseId ? "Exercise Details" : "New Exercise"} 
          onClose={() => setExerciseModal(null)} 
          onAction={saveExerciseFromModal}
          actionLabel={exerciseModal.exerciseId ? "Save Changes" : "Add Exercise"}
        >
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-1">Identity</label>
              <input 
                autoFocus
                type="text" 
                value={exerciseModal.name}
                onChange={(e) => setExerciseModal({ ...exerciseModal, name: e.target.value })}
                placeholder="Exercise Name"
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 font-bold text-slate-800 placeholder:text-slate-300 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500/50 outline-none transition-all"
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-1">Classification</label>
              <div className="flex flex-wrap gap-2 mb-4">
                {exerciseModal.tags.map((tag, idx) => (
                  <span key={idx} className={`px-3 py-1.5 text-[11px] font-bold rounded-xl flex items-center gap-1.5 shadow-sm transition-all ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-600 border border-slate-200'}`}>
                    {tag}
                    <button onClick={() => setExerciseModal({ ...exerciseModal, tags: exerciseModal.tags.filter((_, i) => i !== idx) })} className="hover:text-rose-500 font-black ml-1">×</button>
                  </span>
                ))}
              </div>

              {/* Tag Selector Dropdown */}
              <div className="space-y-3">
                <div className="relative">
                   <select 
                    className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold text-slate-600 focus:ring-4 focus:ring-indigo-500/10 outline-none appearance-none transition-all"
                    onChange={(e) => {
                      const selected = e.target.value;
                      if (selected && !exerciseModal.tags.includes(selected)) {
                        setExerciseModal({ ...exerciseModal, tags: [...exerciseModal.tags, selected] });
                      }
                      e.target.value = ''; // Reset
                    }}
                  >
                    <option value="">Choose Existing Tag...</option>
                    {availableTags.filter(t => !exerciseModal.tags.includes(t)).map(t => (
                      <option key={t} value={t}>{t}</option>
                    ))}
                  </select>
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-300">
                    <ChevronRightIcon />
                  </div>
                </div>

                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={newCustomTag}
                    onChange={(e) => setNewCustomTag(e.target.value)}
                    placeholder="Create custom tag..."
                    className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-bold placeholder:font-normal focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                  />
                  <button 
                    onClick={addNewGlobalTag}
                    className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center hover:bg-indigo-100 active:scale-90 transition-all shadow-sm"
                  >
                    <PlusIcon />
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-1">Intelligence</label>
              <textarea 
                value={exerciseModal.notes}
                onChange={(e) => setExerciseModal({ ...exerciseModal, notes: e.target.value })}
                placeholder="Training cues, setup tips, or mindset notes..."
                rows={4}
                className="w-full text-sm font-medium bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 focus:ring-4 focus:ring-indigo-500/10 outline-none resize-none transition-all leading-relaxed"
              />
            </div>
            {/* Added some extra bottom space inside scroll area */}
            <div className="h-4"></div>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon,
  TagIcon,
  MoreIcon,
  XIcon,
  CalendarIcon,
  TrendingUpIcon,
  ActivityIcon
} from './components/Icons';

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });

  // Global Tags State
  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    const saved = localStorage.getItem('availableTags');
    if (saved) return JSON.parse(saved);

    // Extract unique tags from initial data
    const tags = new Set<string>();
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => ex.tags.forEach(t => tags.add(t))));
    return Array.from(tags);
  });

  // UI States
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [exerciseModal, setExerciseModal] = useState<{
    isOpen: boolean;
    workoutId: string;
    exerciseId?: string; // If present, we are editing
    name: string;
    notes: string;
    tags: string[];
  } | null>(null);

  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [newCustomTag, setNewCustomTag] = useState('');

  // Entry Editing States
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [draftEntry, setDraftEntry] = useState<Entry | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  useEffect(() => {
    localStorage.setItem('availableTags', JSON.stringify(availableTags));
  }, [availableTags]);

  const addWorkout = () => {
    if (!newWorkoutName.trim()) return;
    const newWorkout: Workout = {
      id: Date.now().toString(),
      name: newWorkoutName,
      exercises: []
    };
    setWorkouts([...workouts, newWorkout]);
    setNewWorkoutName('');
    setIsAddingWorkout(false);
  };

  const deleteWorkout = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure you want to delete this workout?')) return;
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  const saveExerciseFromModal = () => {
    if (!exerciseModal || !exerciseModal.name.trim()) return;

    if (exerciseModal.exerciseId) {
      // Editing
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: w.exercises.map(ex => {
              if (ex.id === exerciseModal.exerciseId) {
                return { 
                  ...ex, 
                  name: exerciseModal.name, 
                  notes: exerciseModal.notes, 
                  tags: exerciseModal.tags 
                };
              }
              return ex;
            })
          };
        }
        return w;
      }));
    } else {
      // Adding
      setWorkouts(workouts.map(w => {
        if (w.id === exerciseModal.workoutId) {
          return {
            ...w,
            exercises: [...w.exercises, {
              id: Date.now().toString(),
              name: exerciseModal.name,
              notes: exerciseModal.notes,
              tags: exerciseModal.tags,
              entries: []
            }]
          };
        }
        return w;
      }));
    }
    setExerciseModal(null);
  };

  const deleteExercise = (workoutId: string, exerciseId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.filter(ex => ex.id !== exerciseId)
        };
      }
      return w;
    }));
    if (view.type === 'exercise-detail') {
      setView({ type: 'workout-detail', workoutId });
    }
  };

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(workouts.map(w => {
      if (w.id === workoutId) {
        return {
          ...w,
          exercises: w.exercises.map(ex => {
            if (ex.id === exerciseId) {
              const existingIdx = ex.entries.findIndex(e => e.id === entry.id);
              let newEntries;
              if (existingIdx >= 0) {
                newEntries = ex.entries.map(e => e.id === entry.id ? entry : e);
              } else {
                newEntries = [...ex.entries, entry];
              }
              newEntries.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
              return { ...ex, entries: newEntries };
            }
            return ex;
          })
        };
      }
      return w;
