                <tr key={ent.id} className="group relative transition-colors">
                  {editingEntryId === ent.id ? (
                    <>
                      <RowInputs entry={ent} onChange={(field, val) => setWorkouts(workouts.map(w => w.id === workoutId ? { ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: ex.entries.map(e => e.id === ent.id ? { ...e, [field]: val } : e) } : ex) } : w))} />
                      <td className="py-3 pl-2 text-right"><button onClick={() => setEditingEntryId(null)} className="p-2.5 bg-indigo-600 text-white rounded-xl active:scale-95 transition-all"><CheckIcon /></button></td>
