                        )}
                      </td>
                    </>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
          {exercise.entries.length === 0 && !draftEntry && (
            <div className="py-24 text-center space-y-4">
              <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto text-slate-200"><ActivityIcon /></div>
              <p className="font-bold text-slate-400 tracking-tight">No sessions logged</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 selection:bg-indigo-100">
      {view.type === 'workouts' && <WorkoutsView />}
      {view.type === 'workout-detail' && <WorkoutDetailView workoutId={view.workoutId} />}
      {view.type === 'exercise-detail' && <ExerciseDetailView workoutId={view.workoutId} exerciseId={view.exerciseId} />}

      {isAddingWorkout && (
        <Modal title="New Workout" onClose={() => setIsAddingWorkout(false)} onAction={addWorkout} actionLabel="Create">
          <input autoFocus type="text" value={newWorkoutName} onChange={(e) => setNewWorkoutName(e.target.value)} placeholder="e.g. Push Day" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-indigo-500" />
        </Modal>
      )}

      {exerciseModal && (
        <Modal title={exerciseModal.exerciseId ? "Exercise Details" : "New Exercise"} onClose={() => setExerciseModal(null)} onAction={saveExerciseFromModal} actionLabel={exerciseModal.exerciseId ? "Save Changes" : "Add Exercise"}>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Identity</label>
              <input autoFocus type="text" value={exerciseModal.name} onChange={(e) => setExerciseModal({ ...exerciseModal, name: e.target.value })} placeholder="Exercise Name" className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 font-bold outline-none focus:ring-4 focus:ring-indigo-500/10" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Classification</label>
              <div className="flex flex-wrap gap-2 mb-4">
                {exerciseModal.tags.map((tag, idx) => (
                  <span key={idx} className={`px-3 py-1.5 text-[11px] font-bold rounded-xl flex items-center gap-1.5 ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-600 border border-slate-200'}`}>{tag}<button onClick={() => setExerciseModal({ ...exerciseModal, tags: exerciseModal.tags.filter((_, i) => i !== idx) })} className="ml-1">×</button></span>
                ))}
              </div>
              <div className="space-y-3">
                <select className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold outline-none" onChange={(e) => { const selected = e.target.value; if (selected && !exerciseModal.tags.includes(selected)) setExerciseModal({ ...exerciseModal, tags: [...exerciseModal.tags, selected] }); e.target.value = ''; }}>
                  <option value="">Choose Existing Tag...</option>
                  {availableTags.filter(t => !exerciseModal.tags.includes(t)).map(t => <option key={t} value={t}>{t}</option>)}
                </select>
                <div className="flex gap-2">
                  <input type="text" value={newCustomTag} onChange={(e) => setNewCustomTag(e.target.value)} placeholder="Create tag..." className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm outline-none" />
                  <button onClick={addNewGlobalTag} className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center"><PlusIcon /></button>
                </div>
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Intelligence</label>
              <textarea value={exerciseModal.notes} onChange={(e) => setExerciseModal({ ...exerciseModal, notes: e.target.value })} placeholder="Setup tips..." rows={4} className="w-full text-sm bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 outline-none resize-none" />
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, memo } from 'react';
