                  </>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
});

/**
 * Main Shell
 */

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [exerciseModal, setExerciseModal] = useState<any>(null);

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  const deleteWorkout = useCallback((id: string) => {
    if (!confirm('Delete this workout?')) return;
    setWorkouts(prev => prev.filter(w => w.id !== id));
  }, []);

  const deleteExercise = useCallback((workoutId: string, exerciseId: string) => {
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { ...w, exercises: w.exercises.filter(ex => ex.id !== exerciseId) } : w));
  }, []);

  const commitEntry = useCallback((workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => {
        if (ex.id !== exerciseId) return ex;
        const entries = [...ex.entries, entry].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
        return { ...ex, entries };
      })
    } : w));
  }, []);

  const updateEntryField = useCallback((exerciseId: string, entryId: string, field: keyof Entry, val: any) => {
    setWorkouts(prev => prev.map(w => ({
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? {
        ...ex, entries: ex.entries.map(e => e.id === entryId ? { ...e, [field]: val } : e)
      } : ex)
    })));
  }, []);

  const deleteEntry = useCallback((workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Delete this log?')) return;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: ex.entries.filter(e => e.id !== entryId) } : ex)
    } : w));
  }, []);

  const handleSaveExercise = () => {
    if (!exerciseModal.name.trim()) return;
    const { workoutId, exerciseId, name, notes, tags } = exerciseModal;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: exerciseId 
        ? w.exercises.map(ex => ex.id === exerciseId ? { ...ex, name, notes, tags } : ex)
        : [...w.exercises, { id: Date.now().toString(), name, notes, tags, entries: [] }]
    } : w));
    setExerciseModal(null);
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && (
        <WorkoutsView workouts={workouts} setView={setView} deleteWorkout={deleteWorkout} setIsAddingWorkout={setIsAddingWorkout} />
      )}
      {view.type === 'workout-detail' && (
        <WorkoutDetailView workoutId={view.workoutId} workouts={workouts} setView={setView} deleteExercise={deleteExercise} setExerciseModal={setExerciseModal} />
      )}
      {view.type === 'exercise-detail' && (
        <ExerciseDetailView 
          workoutId={view.workoutId} 
          exerciseId={view.exerciseId} 
          workouts={workouts} 
          setView={setView} 
          setExerciseModal={setExerciseModal} 
          commitEntry={commitEntry}
          deleteEntry={deleteEntry}
          updateEntryField={(entryId: string, f: any, v: any) => updateEntryField(view.exerciseId, entryId, f, v)}
        />
      )}

      {isAddingWorkout && (
        <Modal title="New Workout" onClose={() => setIsAddingWorkout(false)} onAction={() => { if(newWorkoutName) { setWorkouts([...workouts, {id: Date.now().toString(), name: newWorkoutName, exercises: []}]); setNewWorkoutName(''); setIsAddingWorkout(false); } }} actionLabel="Create">
          <input autoFocus type="text" value={newWorkoutName} onChange={(e) => setNewWorkoutName(e.target.value)} placeholder="Workout Name" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3" />
        </Modal>
      )}

      {exerciseModal && (
        <Modal title="Exercise Info" onClose={() => setExerciseModal(null)} onAction={handleSaveExercise} actionLabel="Save">
          <div className="space-y-4">
            <input autoFocus type="text" value={exerciseModal.name} onChange={(e) => setExerciseModal({...exerciseModal, name: e.target.value})} placeholder="Name" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3" />
            <div className="flex gap-2">
              <label className="flex items-center gap-2 text-sm font-bold text-indigo-600">
                <input type="checkbox" checked={exerciseModal.tags.includes('anchor')} onChange={(e) => {
                  const tags = e.target.checked ? [...exerciseModal.tags, 'anchor'] : exerciseModal.tags.filter((t:string) => t !== 'anchor');
                  setExerciseModal({...exerciseModal, tags});
                }} /> Anchor Exercise
              </label>
            </div>
            <textarea value={exerciseModal.notes} onChange={(e) => setExerciseModal({...exerciseModal, notes: e.target.value})} placeholder="Notes/Cues" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 h-24 resize-none" />
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, memo } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  InfoIcon, 
  TagIcon, 
  MoreIcon, 
  XIcon, 
  TrendingUpIcon, 
  ActivityIcon 
} from './components/Icons';

/**
 * Shared UI Components
 */

const Modal = memo(({ title, onClose, onAction, actionLabel, children }: any) => (
  <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
    <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl flex flex-col max-h-[85vh]">
      <div className="flex justify-between items-center px-6 pt-6 pb-4 flex-shrink-0">
        <h3 className="text-xl font-bold text-slate-900">{title}</h3>
        <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full transition-colors">
          <XIcon />
        </button>
      </div>
      <div className="px-6 py-2 overflow-y-auto flex-grow space-y-4">
        {children}
      </div>
      <div className="px-6 pb-6 pt-4 flex gap-3 border-t border-slate-50 flex-shrink-0">
        <Button variant="secondary" className="flex-1" onClick={onClose}>Cancel</Button>
        <Button className="flex-1" onClick={onAction}>{actionLabel}</Button>
      </div>
    </div>
  </div>
));

const RowInputs = memo(({ entry, onChange }: { entry: Entry; onChange: (field: keyof Entry, val: any) => void }) => (
  <>
    <td className="py-2 pr-2">
      <input 
        type="date" 
        value={entry.date}
        onChange={(e) => onChange('date', e.target.value)}
        className="w-full bg-indigo-50 border-none rounded-xl p-1 text-[10px] font-bold text-indigo-900 outline-none h-10"
      />
    </td>
    <td className="py-2 px-1">
      <input 
        type="text" 
        inputMode="numeric"
        pattern="[0-9]*"
        autoComplete="off"
        value={entry.sets === 0 ? '' : entry.sets}
        onChange={(e) => onChange('sets', parseInt(e.target.value.replace(/\D/g, '')) || 0)}
        className="w-full bg-indigo-50 border-none rounded-xl p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-10"
      />
    </td>
    <td className="py-2 px-1">
      <input 
        type="text" 
        inputMode="numeric"
        pattern="[0-9]*"
        autoComplete="off"
        value={entry.reps === 0 ? '' : entry.reps}
        onChange={(e) => onChange('reps', parseInt(e.target.value.replace(/\D/g, '')) || 0)}
        className="w-full bg-indigo-50 border-none rounded-xl p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-10"
      />
    </td>
    <td className="py-2 px-1">
      <input 
        type="text" 
        inputMode="decimal"
        autoComplete="off"
        value={entry.weight === 0 ? '' : entry.weight}
        onChange={(e) => {
            const val = e.target.value.replace(/[^0-9.]/g, '');
            onChange('weight', parseFloat(val) || 0);
        }}
        className="w-full bg-indigo-50 border-none rounded-xl p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-10"
      />
    </td>
  </>
));

/**
 * Views
 */

const WorkoutsView = memo(({ workouts, setView, deleteWorkout, setIsAddingWorkout }: any) => (
  <div className="max-w-md mx-auto min-h-screen pb-24">
    <header className="px-6 pt-12 pb-8">
      {/* Brand Logo Section */}
      <div className="flex items-center gap-3 mb-8">
        <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-200 animate-pulse">
          <ActivityIcon />
        </div>
        <span className="text-xl font-black tracking-tighter italic">
          <span className="text-indigo-600">Track</span>
          <span className="text-slate-900">YoLifts</span>
        </span>
      </div>

      <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Workouts</h1>
      <p className="text-slate-500 mt-2">Manage your training routines</p>
    </header>
    <div className="px-6 space-y-4">
      {workouts.map((w: Workout) => (
        <div key={w.id} onClick={() => setView({ type: 'workout-detail', workoutId: w.id })} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between active:bg-slate-50 transition-colors cursor-pointer">
          <div>
            <h3 className="font-semibold text-lg text-slate-800">{w.name}</h3>
            <p className="text-sm text-slate-500">{w.exercises.length} exercises</p>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={(e) => { e.stopPropagation(); deleteWorkout(w.id); }} className="p-2 text-slate-400 hover:text-rose-500 transition-colors"><TrashIcon /></button>
            <div className="text-indigo-600"><ChevronRightIcon /></div>
          </div>
        </div>
      ))}
      <Button variant="secondary" fullWidth onClick={() => setIsAddingWorkout(true)} className="mt-6 border-dashed bg-transparent py-6 rounded-2xl">
        <PlusIcon /> <span className="ml-2">Create New Workout</span>
      </Button>
    </div>
  </div>
));

const WorkoutDetailView = memo(({ workoutId, workouts, setView, deleteExercise, setExerciseModal }: any) => {
  const workout = workouts.find((w: Workout) => w.id === workoutId);
  if (!workout) return null;
  return (
    <div className="max-w-md mx-auto min-h-screen pb-24">
      <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50 z-10">
        <button onClick={() => setView({ type: 'workouts' })} className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"><ChevronLeftIcon /></button>
        <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
      </header>
      <div className="px-6 space-y-3">
        {workout.exercises.map((ex: Exercise) => {
          const lastEntry = ex.entries[0];
          const isAnchor = ex.tags.includes('anchor');
          return (
            <div key={ex.id} onClick={() => setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id })} className={`bg-white p-5 rounded-2xl border transition-all active:bg-slate-50 cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50/50 shadow-md' : 'border-slate-100 shadow-sm'}`}>
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                    {isAnchor && <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>}
                  </div>
                  <div className="flex flex-wrap gap-2 mt-1.5">
                    {ex.tags.map(tag => tag !== 'anchor' && <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-lg">{tag}</span>)}
                  </div>
                </div>
                <button onClick={(e) => { e.stopPropagation(); deleteExercise(workoutId, ex.id); }} className="p-2 text-slate-300 hover:text-rose-500 transition-colors"><TrashIcon /></button>
              </div>
              {lastEntry && (
                <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2">
                  <span className="text-sm font-medium text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                  <span className="text-sm text-slate-500">at</span>
                  <span className="text-sm font-bold text-indigo-600">{lastEntry.weight}kg</span>
                </div>
              )}
            </div>
          );
        })}
        <Button variant="secondary" fullWidth onClick={() => setExerciseModal({ isOpen: true, workoutId, name: '', notes: '', tags: [] })} className="mt-6 border-dashed bg-transparent py-6 rounded-2xl">
          <PlusIcon /> <span className="ml-2">Add Exercise</span>
        </Button>
      </div>
    </div>
  );
});

const ExerciseDetailView = memo(({ workoutId, exerciseId, workouts, setView, setExerciseModal, commitEntry, deleteEntry, updateEntryField }: any) => {
  const workout = workouts.find((w: Workout) => w.id === workoutId);
  const exercise = workout?.exercises.find((e: Exercise) => e.id === exerciseId);

  const [draftEntry, setDraftEntry] = useState<Entry | null>(null);
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  if (!exercise) return null;
  const latestEntry = exercise.entries[0];

  const handleNewLog = () => {
    setDraftEntry({ 
      id: 'draft-' + Date.now(), 
      date: new Date().toISOString().split('T')[0], 
      sets: latestEntry?.sets || 0, 
      reps: latestEntry?.reps || 0, 
      weight: latestEntry?.weight || 0 
    });
    setEditingEntryId(null);
    setActiveMenuId(null);
  };

  const handleSaveDraft = () => {
    if (!draftEntry) return;
    commitEntry(workoutId, exerciseId, { ...draftEntry, id: Date.now().toString() });
    setDraftEntry(null);
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-white">
      <div className="bg-gradient-to-b from-slate-50 to-white px-6 pb-10 border-b border-slate-100">
        <header className="py-6 flex items-center justify-between -mx-2">
          <button onClick={() => setView({ type: 'workout-detail', workoutId })} className="p-2 text-slate-500 hover:bg-white hover:shadow-sm rounded-full transition-all"><ChevronLeftIcon /></button>
          <Button variant="ghost" size="sm" onClick={() => setExerciseModal({ isOpen: true, workoutId, exerciseId: exercise.id, name: exercise.name, notes: exercise.notes || '', tags: exercise.tags })}>
            <EditIcon /> <span className="ml-1.5 text-xs font-semibold">Edit</span>
          </Button>
        </header>
        <div className="space-y-6">
          <div>
            <h1 className="text-2xl font-bold text-slate-900 leading-tight tracking-tight">{exercise.name}</h1>
            <div className="flex flex-wrap gap-2 mt-3">
              {exercise.tags.map(tag => (
                <span key={tag} className={`px-2.5 py-1 text-[11px] font-bold rounded-lg flex items-center gap-1.5 shadow-sm ${tag === 'anchor' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-slate-600 uppercase tracking-tight'}`}><TagIcon /> {tag}</span>
              ))}
            </div>
          </div>
          {latestEntry ? (
            <div className="bg-white p-6 rounded-2xl border border-indigo-100 shadow-[0_8px_30px_rgb(0,0,0,0.04)] flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 shadow-inner"><TrendingUpIcon /></div>
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-black tracking-[0.1em] mb-1">Latest Performance</p>
                  <div className="flex items-baseline gap-2">
                    <span className="text-slate-900 font-extrabold text-2xl tracking-tighter">{latestEntry.sets}<span className="text-slate-300 text-lg mx-1 font-medium">×</span>{latestEntry.reps}</span>
                    <span className="text-indigo-600 font-black text-2xl tracking-tighter">{latestEntry.weight}<span className="text-[10px] uppercase ml-0.5 font-bold">kg</span></span>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="bg-slate-50 p-5 rounded-2xl border border-dashed border-slate-200 flex items-center gap-4 opacity-70">
              <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-slate-300"><ActivityIcon /></div>
              <div><p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">No Performance Yet</p><p className="text-slate-500 text-sm font-medium italic">Log your first session below</p></div>
            </div>
          )}
        </div>
      </div>

      <div className="px-6 py-10 pb-40 min-h-[60vh]">
        <div className="flex items-center justify-between mb-8">
          <h2 className="text-xl font-bold text-slate-900 tracking-tight">Activity Log</h2>
          <Button size="sm" onClick={handleNewLog} disabled={!!draftEntry} className="shadow-indigo-100 shadow-lg px-4"><PlusIcon /> <span className="ml-1.5 font-bold">Log Session</span></Button>
        </div>
        <table className="w-full text-left border-collapse table-fixed">
          <thead>
            <tr className="text-[11px] font-black text-slate-400 uppercase tracking-[0.1em] border-b border-slate-50">
              <th className="pb-4 pr-2 w-[75px]">Date</th>
              <th className="pb-4 px-1 text-center w-[45px]">Sets</th>
              <th className="pb-4 px-1 text-center w-[45px]">Reps</th>
              <th className="pb-4 px-1 text-center">Kg</th>
              <th className="pb-4 pl-2 text-right w-[85px]"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {draftEntry && (
              <tr key="draft-row" className="bg-indigo-50/40">
                <RowInputs entry={draftEntry} onChange={(field, val) => setDraftEntry({ ...draftEntry, [field]: val })} />
                <td className="py-3 pl-2 text-right">
                  <div className="flex gap-1 justify-end">
                    <button onClick={handleSaveDraft} className="p-2.5 bg-emerald-500 text-white rounded-xl shadow-lg"><CheckIcon /></button>
                    <button onClick={() => setDraftEntry(null)} className="p-2.5 bg-slate-100 text-slate-400 rounded-xl"><XIcon /></button>
                  </div>
                </td>
              </tr>
            )}
            {exercise.entries.map(ent => (
              <tr key={ent.id} className="group relative">
                {editingEntryId === ent.id ? (
                  <>
                    <RowInputs entry={ent} onChange={(field, val) => updateEntryField(ent.id, field, val)} />
                    <td className="py-3 pl-2 text-right"><button onClick={() => setEditingEntryId(null)} className="p-2.5 bg-indigo-600 text-white rounded-xl"><CheckIcon /></button></td>
                  </>
                ) : (
                  <>
                    <td className="py-6 pr-2"><div className="flex flex-col"><span className="text-[11px] font-bold text-slate-800">{new Date(ent.date).toLocaleDateString(undefined, { month: '2-digit', day: '2-digit' })}</span></div></td>
                    <td className="py-6 px-1 text-center text-slate-600 font-bold">{ent.sets}</td>
                    <td className="py-6 px-1 text-center text-slate-600 font-bold">{ent.reps}</td>
                    <td className="py-6 px-1 text-center text-indigo-600 font-black truncate">{ent.weight}</td>
                    <td className="py-6 pl-2 text-right relative">
                      <button onClick={(e) => { e.stopPropagation(); setActiveMenuId(activeMenuId === ent.id ? null : ent.id); }} className={`p-2 rounded-xl transition-all ${activeMenuId === ent.id ? 'bg-slate-200 text-slate-900' : 'text-slate-300'}`}><MoreIcon /></button>
                      {activeMenuId === ent.id && (
                        <><div className="fixed inset-0 z-[55]" onClick={() => setActiveMenuId(null)} /><div className="absolute right-0 top-14 z-[60] bg-white shadow-xl border border-slate-100 rounded-2xl overflow-hidden w-32"><button onClick={() => { setEditingEntryId(ent.id); setActiveMenuId(null); }} className="w-full px-4 py-3.5 text-left text-sm font-bold text-slate-700 hover:bg-slate-50 flex items-center gap-3"><EditIcon /> Edit</button><button onClick={() => { deleteEntry(workoutId, exerciseId, ent.id); setActiveMenuId(null); }} className="w-full px-4 py-3.5 text-left text-sm font-bold text-rose-600 hover:bg-rose-50 flex items-center gap-3"><TrashIcon /> Delete</button></div></>
                      )}
                    </td>
                  </>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
});

/**
 * Main Shell
 */

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    const saved = localStorage.getItem('workouts');
    return saved ? JSON.parse(saved) : INITIAL_WORKOUTS;
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [exerciseModal, setExerciseModal] = useState<any>(null);

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  const deleteWorkout = useCallback((id: string) => {
    if (!confirm('Delete this workout?')) return;
    setWorkouts(prev => prev.filter(w => w.id !== id));
  }, []);

  const deleteExercise = useCallback((workoutId: string, exerciseId: string) => {
    if (!confirm('Delete this exercise?')) return;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { ...w, exercises: w.exercises.filter(ex => ex.id !== exerciseId) } : w));
  }, []);

  const commitEntry = useCallback((workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => {
        if (ex.id !== exerciseId) return ex;
        const entries = [...ex.entries, entry].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
        return { ...ex, entries };
      })
    } : w));
  }, []);

  const updateEntryField = useCallback((exerciseId: string, entryId: string, field: keyof Entry, val: any) => {
    setWorkouts(prev => prev.map(w => ({
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? {
        ...ex, entries: ex.entries.map(e => e.id === entryId ? { ...e, [field]: val } : e)
      } : ex)
    })));
  }, []);

  const deleteEntry = useCallback((workoutId: string, exerciseId: string, entryId: string) => {
    if (!confirm('Delete this log?')) return;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: ex.entries.filter(e => e.id !== entryId) } : ex)
    } : w));
  }, []);

  const handleSaveExercise = () => {
    if (!exerciseModal.name.trim()) return;
    const { workoutId, exerciseId, name, notes, tags } = exerciseModal;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: exerciseId 
        ? w.exercises.map(ex => ex.id === exerciseId ? { ...ex, name, notes, tags } : ex)
        : [...w.exercises, { id: Date.now().toString(), name, notes, tags, entries: [] }]
    } : w));
    setExerciseModal(null);
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && (
        <WorkoutsView workouts={workouts} setView={setView} deleteWorkout={deleteWorkout} setIsAddingWorkout={setIsAddingWorkout} />
      )}
      {view.type === 'workout-detail' && (
        <WorkoutDetailView workoutId={view.workoutId} workouts={workouts} setView={setView} deleteExercise={deleteExercise} setExerciseModal={setExerciseModal} />
      )}
      {view.type === 'exercise-detail' && (
        <ExerciseDetailView 
          workoutId={view.workoutId} 
          exerciseId={view.exerciseId} 
          workouts={workouts} 
          setView={setView} 
          setExerciseModal={setExerciseModal} 
          commitEntry={commitEntry}
          deleteEntry={deleteEntry}
          updateEntryField={(entryId: string, f: any, v: any) => updateEntryField(view.exerciseId, entryId, f, v)}
        />
      )}

      {isAddingWorkout && (
        <Modal title="New Workout" onClose={() => setIsAddingWorkout(false)} onAction={() => { if(newWorkoutName) { setWorkouts([...workouts, {id: Date.now().toString(), name: newWorkoutName, exercises: []}]); setNewWorkoutName(''); setIsAddingWorkout(false); } }} actionLabel="Create">
          <input autoFocus type="text" value={newWorkoutName} onChange={(e) => setNewWorkoutName(e.target.value)} placeholder="Workout Name" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3" />
        </Modal>
      )}

      {exerciseModal && (
        <Modal title="Exercise Info" onClose={() => setExerciseModal(null)} onAction={handleSaveExercise} actionLabel="Save">
          <div className="space-y-4">
            <input autoFocus type="text" value={exerciseModal.name} onChange={(e) => setExerciseModal({...exerciseModal, name: e.target.value})} placeholder="Name" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3" />
            <div className="flex gap-2">
              <label className="flex items-center gap-2 text-sm font-bold text-indigo-600">
                <input type="checkbox" checked={exerciseModal.tags.includes('anchor')} onChange={(e) => {
                  const tags = e.target.checked ? [...exerciseModal.tags, 'anchor'] : exerciseModal.tags.filter((t:string) => t !== 'anchor');
                  setExerciseModal({...exerciseModal, tags});
                }} /> Anchor Exercise
              </label>
            </div>
            <textarea value={exerciseModal.notes} onChange={(e) => setExerciseModal({...exerciseModal, notes: e.target.value})} placeholder="Notes/Cues" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 h-24 resize-none" />
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, memo, useMemo } from 'react';
import { Workout, Exercise, ViewState, Entry } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  TagIcon, 
  MoreIcon, 
  XIcon, 
  TrendingUpIcon, 
  ActivityIcon 
} from './components/Icons';

/**
 * Shared UI Components
 */

const Modal = memo(({ title, onClose, onAction, actionLabel, children }: any) => (
  <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
    <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl flex flex-col max-h-[90vh]">
      <div className="flex justify-between items-center px-6 pt-6 pb-4 flex-shrink-0">
        <h3 className="text-xl font-bold text-slate-900">{title}</h3>
        <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-50 rounded-full transition-colors">
          <XIcon />
        </button>
      </div>
      <div className="px-6 py-2 overflow-y-auto flex-grow space-y-4">
        {children}
      </div>
      <div className="px-6 pb-6 pt-4 flex gap-3 border-t border-slate-50 flex-shrink-0">
        <Button variant="secondary" className="flex-1" onClick={onClose}>Cancel</Button>
        <Button className="flex-1" onClick={onAction}>{actionLabel}</Button>
      </div>
    </div>
  </div>
));

const RowInputs = memo(({ entry, onChange }: { entry: Entry; onChange: (field: keyof Entry, val: any) => void }) => (
  <>
    <td className="py-2 pr-2">
      <input 
        type="date" 
        value={entry.date}
        onChange={(e) => onChange('date', e.target.value)}
        className="w-full bg-indigo-50 border-none rounded-xl p-1 text-[10px] font-bold text-indigo-900 outline-none h-10"
      />
    </td>
    <td className="py-2 px-1">
      <input 
        type="text" 
        inputMode="numeric"
        pattern="[0-9]*"
        autoComplete="off"
        value={entry.sets === 0 ? '' : entry.sets}
        onChange={(e) => onChange('sets', parseInt(e.target.value.replace(/\D/g, '')) || 0)}
        className="w-full bg-indigo-50 border-none rounded-xl p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-10"
      />
    </td>
    <td className="py-2 px-1">
      <input 
        type="text" 
        inputMode="numeric"
        pattern="[0-9]*"
        autoComplete="off"
        value={entry.reps === 0 ? '' : entry.reps}
        onChange={(e) => onChange('reps', parseInt(e.target.value.replace(/\D/g, '')) || 0)}
        className="w-full bg-indigo-50 border-none rounded-xl p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-10"
      />
    </td>
    <td className="py-2 px-1">
      <input 
        type="text" 
        inputMode="decimal"
        autoComplete="off"
        value={entry.weight === 0 ? '' : entry.weight}
        onChange={(e) => {
            const val = e.target.value.replace(/[^0-9.]/g, '');
            onChange('weight', parseFloat(val) || 0);
        }}
        className="w-full bg-indigo-50 border-none rounded-xl p-1.5 text-center text-sm font-bold text-indigo-700 outline-none h-10"
      />
    </td>
  </>
));

/**
 * Views
 */

