        <Button variant="secondary" fullWidth onClick={() => setExerciseModal({ isOpen: true, workoutId, name: '', notes: '', tags: [] })} className="mt-6 border-dashed bg-transparent py-6 rounded-2xl">
          <PlusIcon /> <span className="ml-2">Add Exercise</span>
        </Button>
      </div>
