      >
        <PlusIcon /> <span className="ml-2">Create New Workout</span>
      </Button>
    </div>
  </div>
));

const WorkoutDetailView = memo(({ workoutId, workouts, setView, deleteExercise, setExerciseModal }: any) => {
  const workout = (workouts || []).find((w: Workout) => w.id === workoutId);
  if (!workout) return <div className="p-10 text-center">Workout not found. <Button onClick={() => setView({type: 'workouts'})}>Go Back</Button></div>;

  return (
    <div className="max-w-md mx-auto min-h-screen pb-24 view-transition">
      <header className="px-6 py-8 flex items-center gap-4 sticky top-0 bg-slate-50/80 backdrop-blur-md z-10 border-b border-slate-100">
        <button onClick={() => setView({ type: 'workouts' })} className="p-2 -ml-2 text-slate-600 hover:bg-white rounded-full transition-colors"><ChevronLeftIcon /></button>
        <h1 className="text-2xl font-bold text-slate-900 leading-tight">{workout.name}</h1>
      </header>
      <div className="px-6 py-4 space-y-3">
        {(workout.exercises || []).map((ex: Exercise) => {
          const lastEntry = (ex.entries || [])[0];
          const isAnchor = (ex.tags || []).includes('anchor');
          return (
            <div 
              key={ex.id} 
              onClick={() => setView({ type: 'exercise-detail', workoutId, exerciseId: ex.id })} 
              className={`bg-white p-5 rounded-2xl border transition-all active:scale-[0.98] cursor-pointer ${isAnchor ? 'border-indigo-100 shadow-indigo-50 shadow-md' : 'border-slate-100 shadow-sm'}`}
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-semibold text-slate-800 text-lg leading-tight">{ex.name}</h3>
                    {isAnchor && <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase rounded tracking-wider">Anchor</span>}
                  </div>
                  <div className="flex flex-wrap gap-1.5 mt-2">
                    {(ex.tags || []).filter(t => t !== 'anchor').map(tag => (
                      <span key={tag} className="px-2 py-0.5 bg-slate-100 text-slate-500 text-[10px] font-medium rounded-lg uppercase tracking-tight">{tag}</span>
                    ))}
                  </div>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); deleteExercise(workoutId, ex.id); }} 
                  className="p-2 text-slate-200 hover:text-rose-500 transition-colors"
                >
                  <TrashIcon />
                </button>
              </div>
              {lastEntry && (
                <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2 text-sm">
                  <span className="font-medium text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                  <span className="text-slate-400">at</span>
                  <span className="font-bold text-indigo-600">{lastEntry.weight}kg</span>
                </div>
              )}
            </div>
          );
        })}
        <Button 
          variant="secondary" 
          fullWidth 
          onClick={() => setExerciseModal({ isOpen: true, workoutId, name: '', notes: '', tags: [] })} 
          className="mt-6 border-dashed border-2 bg-transparent py-8 rounded-2xl text-slate-400 hover:text-indigo-600 hover:border-indigo-200"
        >
          <PlusIcon /> <span className="ml-2">Add Exercise</span>
        </Button>
      </div>
    </div>
  );
});

const ExerciseDetailView = memo(({ workoutId, exerciseId, workouts, setView, setExerciseModal, commitEntry, deleteEntry }: any) => {
  const workout = (workouts || []).find((w: Workout) => w.id === workoutId);
  const exercise = workout?.exercises?.find((e: Exercise) => e.id === exerciseId);

  const [draft, setDraft] = useState<any>(null);

  if (!exercise) return <div className="p-10 text-center">Exercise not found. <Button onClick={() => setView({type: 'workout-detail', workoutId})}>Go Back</Button></div>;
  const lastEntry = (exercise.entries || [])[0];

  const handleSaveLog = () => {
    if (!draft) return;
    commitEntry(workoutId, exerciseId, {
      ...draft,
      id: Date.now().toString()
    });
    setDraft(null);
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-white view-transition">
      <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
        <header className="py-6 flex items-center justify-between -mx-2">
          <button onClick={() => setView({ type: 'workout-detail', workoutId })} className="p-2 text-slate-500 hover:bg-white rounded-full transition-all"><ChevronLeftIcon /></button>
          <Button variant="ghost" size="sm" onClick={() => setExerciseModal({ isOpen: true, workoutId, exerciseId: exercise.id, name: exercise.name, notes: exercise.notes || '', tags: exercise.tags || [] })}>
            <EditIcon /> <span className="ml-1.5 text-xs font-semibold">Edit Info</span>
          </Button>
        </header>

        <h1 className="text-2xl font-bold text-slate-900 tracking-tight leading-tight">{exercise.name}</h1>
        <div className="flex flex-wrap gap-2 mt-4">
          {(exercise.tags || []).map(tag => (
            <span key={tag} className={`px-2.5 py-1 text-[10px] font-bold rounded-lg uppercase tracking-wider ${tag === 'anchor' ? 'bg-indigo-600 text-white shadow-md' : 'bg-white border border-slate-200 text-slate-500'}`}>{tag}</span>
          ))}
        </div>

        {lastEntry && (
          <div className="mt-8 bg-white p-6 rounded-2xl border border-indigo-50 shadow-sm flex items-center justify-between">
            <div>
              <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.1em] mb-1">Previous Best</p>
              <div className="flex items-baseline gap-2 text-2xl font-black">
                <span className="text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                <span className="text-indigo-600">{lastEntry.weight}kg</span>
              </div>
            </div>
            <div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
              <TrendingUpIcon />
            </div>
          </div>
        )}
      </div>

      <div className="px-6 py-8 pb-32">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold text-slate-900">History</h2>
          {!draft && (
            <Button size="sm" onClick={() => setDraft({ date: new Date().toISOString().split('T')[0], sets: lastEntry?.sets || 3, reps: lastEntry?.reps || 8, weight: lastEntry?.weight || 0 })}>
              <PlusIcon /> <span className="ml-1">Add Set</span>
            </Button>
          )}
        </div>

        {draft && (
          <div className="bg-indigo-50 p-4 rounded-2xl mb-6 border border-indigo-100 animate-in space-y-4">
            <div className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Sets</label>
                <input type="number" value={draft.sets} onChange={e => setDraft({...draft, sets: parseInt(e.target.value) || 0})} className="w-full bg-white rounded-xl px-3 py-2 text-sm font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Reps</label>
                <input type="number" value={draft.reps} onChange={e => setDraft({...draft, reps: parseInt(e.target.value) || 0})} className="w-full bg-white rounded-xl px-3 py-2 text-sm font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Weight</label>
                <input type="number" value={draft.weight} onChange={e => setDraft({...draft, weight: parseFloat(e.target.value) || 0})} className="w-full bg-white rounded-xl px-3 py-2 text-sm font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300" />
              </div>
            </div>
            <div className="flex gap-2">
              <Button fullWidth onClick={handleSaveLog}><CheckIcon /> <span className="ml-1">Save</span></Button>
              <Button variant="ghost" onClick={() => setDraft(null)} className="text-indigo-400"><XIcon /></Button>
            </div>
          </div>
        )}

        <div className="space-y-3">
          {(exercise.entries || []).map(ent => (
            <div key={ent.id} className="group flex items-center justify-between p-4 bg-slate-50 hover:bg-white hover:shadow-md border border-transparent hover:border-slate-100 rounded-2xl transition-all">
              <div className="flex items-center gap-4">
                <div className="text-xs font-bold text-slate-400 bg-white w-10 h-10 flex items-center justify-center rounded-xl border border-slate-100">
                  {new Date(ent.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                </div>
                <div className="flex items-center gap-2">
                  <span className="font-bold text-slate-700">{ent.sets}x{ent.reps}</span>
                  <span className="text-indigo-600 font-black">{ent.weight}kg</span>
                </div>
              </div>
              <button 
                onClick={() => { if(confirm('Delete log?')) deleteEntry(workoutId, exerciseId, ent.id); }} 
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 hover:text-rose-500 transition-all"
              >
                <TrashIcon />
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
});

/**
 * Main App
 */

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => {
    return safeParse('workouts', INITIAL_WORKOUTS);
  });

  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    const saved = safeParse('available_tags', null);
    if (Array.isArray(saved)) return saved;
    // Discover tags from state to bootstrap if storage is empty
    const initialTags = new Set(PREDEFINED_TAGS);
    (workouts || []).forEach(w => (w.exercises || []).forEach(ex => (ex.tags || []).forEach(t => {
      if(t && t !== 'anchor') initialTags.add(t.toLowerCase());
    })));
    return Array.from(initialTags);
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [exerciseModal, setExerciseModal] = useState<any>(null);
  const [customTagInput, setCustomTagInput] = useState('');

  useEffect(() => {
    localStorage.setItem('workouts', JSON.stringify(workouts));
  }, [workouts]);

  useEffect(() => {
    localStorage.setItem('available_tags', JSON.stringify(availableTags));
  }, [availableTags]);

  const downloadData = useCallback(() => {
    const data = {
      workouts,
      availableTags,
      exportDate: new Date().toISOString()
    };
    const json = JSON.stringify(data, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `trackyolifts_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, [workouts, availableTags]);

  const deleteWorkout = useCallback((id: string) => {
    setWorkouts(prev => prev.filter(w => w.id !== id));
  }, []);

  const deleteExercise = useCallback((workoutId: string, exerciseId: string) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { ...w, exercises: (w.exercises || []).filter(ex => ex.id !== exerciseId) } : w));
  }, []);

  const commitEntry = useCallback((workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: (w.exercises || []).map(ex => {
        if (ex.id !== exerciseId) return ex;
        return { ...ex, entries: [entry, ...(ex.entries || [])] };
      })
    } : w));
  }, []);

  const deleteEntry = useCallback((workoutId: string, exerciseId: string, entryId: string) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: (w.exercises || []).map(ex => ex.id === exerciseId ? { ...ex, entries: (ex.entries || []).filter(e => e.id !== entryId) } : ex)
    } : w));
  }, []);

  const handleSaveExercise = () => {
    if (!exerciseModal.name.trim()) return;
    const { workoutId, exerciseId, name, notes, tags } = exerciseModal;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: exerciseId 
        ? (w.exercises || []).map(ex => ex.id === exerciseId ? { ...ex, name, notes, tags } : ex)
        : [...(w.exercises || []), { id: Date.now().toString(), name, notes, tags, entries: [] }]
    } : w));
    setExerciseModal(null);
  };

  const toggleTag = (tag: string) => {
    const currentTags = Array.isArray(exerciseModal.tags) ? exerciseModal.tags : [];
    if (currentTags.includes(tag)) {
      setExerciseModal({ ...exerciseModal, tags: currentTags.filter((t: string) => t !== tag) });
    } else {
      setExerciseModal({ ...exerciseModal, tags: [...currentTags, tag] });
    }
  };

  const addCustomTag = (e: React.FormEvent) => {
    e.preventDefault();
    const tag = customTagInput.trim().toLowerCase();
    if (!tag) return;
    if (!availableTags.includes(tag)) {
      setAvailableTags(prev => [...prev, tag]);
    }
    toggleTag(tag);
    setCustomTagInput('');
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && (
        <WorkoutsView workouts={workouts} setView={setView} deleteWorkout={deleteWorkout} setIsAddingWorkout={setIsAddingWorkout} downloadData={downloadData} />
      )}
      {view.type === 'workout-detail' && (
        <WorkoutDetailView workoutId={view.workoutId} workouts={workouts} setView={setView} deleteExercise={deleteExercise} setExerciseModal={setExerciseModal} />
      )}
      {view.type === 'exercise-detail' && (
        <ExerciseDetailView workoutId={view.workoutId} exerciseId={view.exerciseId} workouts={workouts} setView={setView} setExerciseModal={setExerciseModal} commitEntry={commitEntry} deleteEntry={deleteEntry} />
      )}

      {isAddingWorkout && (
        <Modal title="New Workout" onClose={() => setIsAddingWorkout(false)} onAction={() => { if(newWorkoutName) { setWorkouts([...workouts, {id: Date.now().toString(), name: newWorkoutName, exercises: []}]); setNewWorkoutName(''); setIsAddingWorkout(false); } }} actionLabel="Create">
          <div className="space-y-4">
            <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest">Workout Name</label>
            <input autoFocus type="text" value={newWorkoutName} onChange={(e) => setNewWorkoutName(e.target.value)} placeholder="e.g. Upper Body Power" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-medium focus:bg-white focus:ring-2 focus:ring-indigo-100 outline-none" />
          </div>
        </Modal>
      )}

      {exerciseModal && (
        <Modal title={exerciseModal.exerciseId ? "Edit Exercise" : "Add Exercise"} onClose={() => setExerciseModal(null)} onAction={handleSaveExercise} actionLabel="Save">
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest">Exercise Name</label>
              <input autoFocus type="text" value={exerciseModal.name} onChange={(e) => setExerciseModal({...exerciseModal, name: e.target.value})} placeholder="e.g. Bench Press" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-medium focus:bg-white outline-none" />
            </div>

            <div className="space-y-3">
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest">Select Tags</label>
              <div className="flex flex-wrap gap-2">
                {availableTags.map(tag => (
                  <button
                    key={tag}
                    type="button"
                    onClick={() => toggleTag(tag)}
                    className={`px-3 py-1.5 rounded-full text-xs font-bold border transition-all ${
                      (exerciseModal.tags || []).includes(tag) 
                        ? 'bg-indigo-600 text-white border-indigo-600' 
                        : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'
                    }`}
                  >
                    {tag}
                  </button>
                ))}
              </div>
              <form onSubmit={addCustomTag} className="flex gap-2">
                <input type="text" value={customTagInput} onChange={e => setCustomTagInput(e.target.value)} placeholder="New custom tag..." className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-3 py-2 text-xs outline-none" />
                <button type="submit" className="p-2 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-100"><PlusIcon /></button>
              </form>
            </div>

            <div className="flex items-center gap-3 p-4 bg-indigo-50/50 rounded-2xl border border-indigo-100/50">
              <input 
                type="checkbox" 
                id="anchor-check"
                className="w-5 h-5 rounded-lg border-indigo-200 text-indigo-600 focus:ring-indigo-500"
                checked={(exerciseModal.tags || []).includes('anchor')} 
                onChange={(e) => {
                  const currentTags = Array.isArray(exerciseModal.tags) ? exerciseModal.tags : [];
                  const tags = e.target.checked ? [...currentTags, 'anchor'] : currentTags.filter((t:string) => t !== 'anchor');
                  setExerciseModal({...exerciseModal, tags});
                }} 
              /> 
              <label htmlFor="anchor-check" className="text-sm font-bold text-indigo-700 cursor-pointer select-none">Mark as Anchor Exercise</label>
            </div>

            <div className="space-y-2">
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest">Notes / Cues</label>
              <textarea value={exerciseModal.notes} onChange={(e) => setExerciseModal({...exerciseModal, notes: e.target.value})} placeholder="Focus on slow eccentric..." className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 h-24 resize-none focus:bg-white outline-none" />
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

export interface Entry {
  id: string;
  date: string;
  sets: number;
  reps: number;
  weight: number;
}

export interface Exercise {
  id: string;
  name: string;
  tags: string[];
  notes?: string;
  entries: Entry[];
}

export interface Workout {
  id: string;
  name: string;
  exercises: Exercise[];
}

export interface RepoExercise {
  id: string;
  name: string;
  tags: string[];
  notes?: string;
}

export type ViewState = 
  | { type: 'workouts' }
  | { type: 'workout-detail', workoutId: string }
  | { type: 'exercise-detail', workoutId: string, exerciseId: string }
  | { type: 'manage-exercises' };

