              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Reps</label>
                <input type="number" value={draft.reps} onChange={e => setDraft({...draft, reps: parseInt(e.target.value) || 0})} className="w-full bg-white rounded-xl px-3 py-2 text-sm font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Weight</label>
                <input type="number" value={draft.weight} onChange={e => setDraft({...draft, weight: parseFloat(e.target.value) || 0})} className="w-full bg-white rounded-xl px-3 py-2 text-sm font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300" />
              </div>
            </div>
            <div className="flex gap-2">
              <Button fullWidth onClick={handleSaveLog}><CheckIcon /> <span className="ml-1">Save</span></Button>
              <Button variant="ghost" onClick={() => setDraft(null)} className="text-indigo-400"><XIcon /></Button>
            </div>
          </div>
        )}

        <div className="space-y-3">
          {(exercise.entries || []).map(ent => (
            <div key={ent.id} className="group flex items-center justify-between p-4 bg-slate-50 hover:bg-white hover:shadow-md border border-transparent hover:border-slate-100 rounded-2xl transition-all">
              <div className="flex items-center gap-4">
                <div className="text-xs font-bold text-slate-400 bg-white w-10 h-10 flex items-center justify-center rounded-xl border border-slate-100">
                  {new Date(ent.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                </div>
                <div className="flex items-center gap-2">
                  <span className="font-bold text-slate-700">{ent.sets}x{ent.reps}</span>
                  <span className="text-indigo-600 font-black">{ent.weight}kg</span>
                </div>
              </div>
              <button 
                onClick={() => { if(confirm('Delete log?')) deleteEntry(workoutId, exerciseId, ent.id); }} 
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 hover:text-rose-500 transition-all"
              >
                <TrashIcon />
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
});

/**
 * Main App
 */

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => safeParse('workouts', INITIAL_WORKOUTS));

  const [exerciseRepository, setExerciseRepository] = useState<RepoExercise[]>(() => {
    const saved = safeParse('exercise_repository', null);
    if (saved) return saved;
    // Bootstrap repository from initial data
    const repoMap = new Map();
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => {
      if (!repoMap.has(ex.name)) {
        repoMap.set(ex.name, { id: ex.id, name: ex.name, tags: ex.tags, notes: ex.notes });
      }
    }));
    return Array.from(repoMap.values());
  });

  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    const saved = safeParse('available_tags', null);
    if (saved) return saved;
    const tags = new Set(PREDEFINED_TAGS);
    exerciseRepository.forEach(ex => ex.tags.forEach(t => { if(t !== 'anchor') tags.add(t.toLowerCase()); }));
    return Array.from(tags);
  });

  const [view, setView] = useState<ViewState>({ type: 'workouts' });
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [repoModal, setRepoModal] = useState<any>(null);
  const [addExerciseModal, setAddExerciseModal] = useState<any>(null);
  const [editInstanceModal, setEditInstanceModal] = useState<any>(null);
  const [customTagInput, setCustomTagInput] = useState('');

  useEffect(() => { localStorage.setItem('workouts', JSON.stringify(workouts)); }, [workouts]);
  useEffect(() => { localStorage.setItem('exercise_repository', JSON.stringify(exerciseRepository)); }, [exerciseRepository]);
  useEffect(() => { localStorage.setItem('available_tags', JSON.stringify(availableTags)); }, [availableTags]);

  const downloadData = useCallback(() => {
    const data = { workouts, exerciseRepository, availableTags, exportDate: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `trackyolifts_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [workouts, exerciseRepository, availableTags]);

  const deleteWorkout = (id: string) => setWorkouts(prev => prev.filter(w => w.id !== id));

  const deleteExercise = (workoutId: string, exerciseId: string) => {
    if(!confirm('Delete exercise from this workout?')) return;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { ...w, exercises: w.exercises.filter(ex => ex.id !== exerciseId) } : w));
  };

  const deleteFromRepo = (id: string) => setExerciseRepository(prev => prev.filter(e => e.id !== id));

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: [entry, ...ex.entries] } : ex)
    } : w));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: ex.entries.filter(e => e.id !== entryId) } : ex)
    } : w));
  };

  const handleSaveRepoExercise = () => {
    if (!repoModal.name.trim()) return;
    const { id, name, tags, notes } = repoModal;
    if (id) {
      setExerciseRepository(prev => prev.map(e => e.id === id ? { id, name, tags, notes } : e));
    } else {
      setExerciseRepository(prev => [...prev, { id: Date.now().toString(), name, tags, notes }]);
    }
    setRepoModal(null);
  };

  const handleSaveEditInstance = () => {
    if (!editInstanceModal.name.trim()) return;
    const { workoutId, exerciseId, name, tags, notes } = editInstanceModal;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
        ...w,
        exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, name, tags, notes } : ex)
    } : w));
    setEditInstanceModal(null);
  }

  const addExerciseToWorkout = (workoutId: string, repoEx: RepoExercise) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: [...w.exercises, { ...repoEx, id: Date.now().toString(), entries: [] }]
    } : w));
    setAddExerciseModal(null);
  };

  const toggleTag = (tag: string, targetModal: any, setModal: any) => {
    const currentTags = targetModal.tags || [];
    if (currentTags.includes(tag)) {
      setModal({ ...targetModal, tags: currentTags.filter((t: string) => t !== tag) });
    } else {
      setModal({ ...targetModal, tags: [...currentTags, tag] });
    }
  };

  const addCustomTag = (e: React.FormEvent, targetModal: any, setModal: any) => {
    e.preventDefault();
    const tag = customTagInput.trim().toLowerCase();
    if (!tag) return;
    if (!availableTags.includes(tag)) {
      setAvailableTags(prev => [...prev, tag]);
    }
    toggleTag(tag, targetModal, setModal);
    setCustomTagInput('');
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && (
        <WorkoutsView workouts={workouts} setView={setView} deleteWorkout={deleteWorkout} setIsAddingWorkout={setIsAddingWorkout} setMenuOpen={setIsMenuOpen} />
      )}
      {view.type === 'workout-detail' && (
        <WorkoutDetailView workoutId={view.workoutId} workouts={workouts} setView={setView} deleteExercise={deleteExercise} setAddExerciseModal={setAddExerciseModal} setEditInstanceModal={setEditInstanceModal} />
      )}
      {view.type === 'exercise-detail' && (
        <ExerciseDetailView workoutId={view.workoutId} exerciseId={view.exerciseId} workouts={workouts} setView={setView} commitEntry={commitEntry} deleteEntry={deleteEntry} />
      )}
      {view.type === 'manage-exercises' && (
        <ManageExercisesView repository={exerciseRepository} setView={setView} deleteFromRepo={deleteFromRepo} setRepoModal={setRepoModal} />
      )}

      <MenuDrawer isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onNavigate={setView} onDownload={downloadData} />

      {isAddingWorkout && (
        <Modal title="New Workout" onClose={() => setIsAddingWorkout(false)} onAction={() => { if(newWorkoutName) { setWorkouts([...workouts, {id: Date.now().toString(), name: newWorkoutName, exercises: []}]); setNewWorkoutName(''); setIsAddingWorkout(false); } }} actionLabel="Create">
          <input autoFocus type="text" value={newWorkoutName} onChange={(e) => setNewWorkoutName(e.target.value)} placeholder="e.g. Upper Body Power" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-medium focus:bg-white outline-none" />
        </Modal>
      )}

      {repoModal && (
        <Modal title={repoModal.id ? "Edit Global Move" : "New Global Move"} onClose={() => setRepoModal(null)} onAction={handleSaveRepoExercise} actionLabel="Save to Library">
          <div className="space-y-4">
            <input autoFocus type="text" value={repoModal.name} onChange={(e) => setRepoModal({...repoModal, name: e.target.value})} placeholder="Exercise Name" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-medium focus:bg-white outline-none" />
            <div className="flex flex-wrap gap-2">
              {availableTags.map(tag => (
                <button key={tag} onClick={() => toggleTag(tag, repoModal, setRepoModal)} className={`px-3 py-1.5 rounded-full text-xs font-bold border transition-all ${repoModal.tags.includes(tag) ? 'bg-indigo-600 text-white' : 'bg-white text-slate-500'}`}>{tag}</button>
              ))}
            </div>
            <div className="flex items-center gap-2 p-3 bg-indigo-50 rounded-xl border border-indigo-100">
               <input type="checkbox" checked={repoModal.tags.includes('anchor')} onChange={(e) => { const tags = e.target.checked ? [...repoModal.tags, 'anchor'] : repoModal.tags.filter((t:string) => t !== 'anchor'); setRepoModal({...repoModal, tags}); }} />
               <span className="text-sm font-bold text-indigo-700">Anchor Exercise</span>
            </div>
            <form onSubmit={(e) => addCustomTag(e, repoModal, setRepoModal)} className="flex gap-2">
                <input type="text" value={customTagInput} onChange={e => setCustomTagInput(e.target.value)} placeholder="New custom tag..." className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-3 py-2 text-xs outline-none" />
                <button type="submit" className="p-2 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-100"><PlusIcon /></button>
            </form>
            <textarea value={repoModal.notes} onChange={(e) => setRepoModal({...repoModal, notes: e.target.value})} placeholder="Notes/Cues" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 h-24 resize-none outline-none" />
          </div>
        </Modal>
      )}

      {editInstanceModal && (
        <Modal title="Edit Exercise Info" onClose={() => setEditInstanceModal(null)} onAction={handleSaveEditInstance} actionLabel="Update Move">
          <div className="space-y-4">
            <input autoFocus type="text" value={editInstanceModal.name} onChange={(e) => setEditInstanceModal({...editInstanceModal, name: e.target.value})} placeholder="Exercise Name" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-medium focus:bg-white outline-none" />
            <div className="flex flex-wrap gap-2">
              {availableTags.map(tag => (
                <button key={tag} onClick={() => toggleTag(tag, editInstanceModal, setEditInstanceModal)} className={`px-3 py-1.5 rounded-full text-xs font-bold border transition-all ${editInstanceModal.tags.includes(tag) ? 'bg-indigo-600 text-white' : 'bg-white text-slate-500'}`}>{tag}</button>
              ))}
            </div>
            <div className="flex items-center gap-2 p-3 bg-indigo-50 rounded-xl border border-indigo-100">
               <input type="checkbox" checked={editInstanceModal.tags.includes('anchor')} onChange={(e) => { const tags = e.target.checked ? [...editInstanceModal.tags, 'anchor'] : editInstanceModal.tags.filter((t:string) => t !== 'anchor'); setEditInstanceModal({...editInstanceModal, tags}); }} />
               <span className="text-sm font-bold text-indigo-700">Anchor Exercise</span>
            </div>
            <textarea value={editInstanceModal.notes} onChange={(e) => setEditInstanceModal({...editInstanceModal, notes: e.target.value})} placeholder="Notes/Cues" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 h-24 resize-none outline-none" />
          </div>
        </Modal>
      )}

      {addExerciseModal && (
        <Modal title="Add to Workout" onClose={() => setAddExerciseModal(null)} showAction={false}>
          <div className="space-y-4">
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Select from library</p>
            <div className="space-y-2 max-h-64 overflow-y-auto pr-1">
              {exerciseRepository.length === 0 && <p className="text-center text-slate-400 py-8 text-sm">Library is empty.</p>}
              {exerciseRepository.map(ex => (
                <button 
                  key={ex.id} 
                  onClick={() => addExerciseToWorkout(addExerciseModal.workoutId, ex)}
                  className="w-full text-left p-4 bg-slate-50 hover:bg-indigo-50 hover:border-indigo-100 border border-transparent rounded-2xl transition-all"
                >
                  <span className="font-bold text-slate-800">{ex.name}</span>
                  <div className="flex flex-wrap gap-1 mt-1">
                    {(ex.tags || []).map(t => <span key={t} className="text-[8px] uppercase font-bold text-slate-400">{t}</span>)}
                  </div>
                </button>
              ))}
            </div>
            <div className="pt-4 border-t border-slate-50">
               <Button fullWidth variant="secondary" onClick={() => { setRepoModal({ isOpen: true, name: '', tags: [], notes: '' }); setAddExerciseModal(null); }}>
                 <PlusIcon /> <span className="ml-2">Create New Exercise</span>
               </Button>
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, memo, useMemo } from 'react';
