/**
 * Constants & Utility
 */

const PREDEFINED_TAGS = ['chest', 'back', 'legs', 'shoulders', 'biceps', 'triceps', 'abs', 'warm-up'];

const safeParse = (key: string, fallback: any) => {
  try {
    const item = localStorage.getItem(key);
    if (!item || item === 'undefined' || item === '[object Object]') return fallback;
    const parsed = JSON.parse(item);
    if (key === 'workouts' && !Array.isArray(parsed)) return fallback;
    return parsed ?? fallback;
  } catch (e) {
    console.warn(`Local storage parsing failed for ${key}, using defaults.`);
    return fallback;
  }
};

/**
 * Shared UI Components
 */

const Modal = memo(({ title, onClose, onAction, actionLabel, children, showAction = true }: any) => (
  <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
