                             >
                                <EditIcon /> Edit Info
                             </button>
                             <button 
                                onClick={(e) => { e.stopPropagation(); setActiveMenu(null); deleteExercise(workoutId, ex.id); }}
                                className="w-full text-left px-4 py-2 text-xs font-semibold text-rose-500 hover:bg-rose-50 flex items-center gap-2"
                             >
                                <TrashIcon /> Delete
                             </button>
                        </div>
                    )}
                </div>
              </div>
              {lastEntry && (
                <div className="mt-4 pt-3 border-t border-slate-50 flex items-baseline gap-2 text-sm">
                  <span className="font-medium text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                  <span className="text-slate-400">at</span>
                  <span className="font-bold text-indigo-600">{lastEntry.weight}kg</span>
                </div>
              )}
            </div>
          );
        })}
        <Button 
          variant="secondary" 
          fullWidth 
          onClick={() => setAddExerciseModal({ isOpen: true, workoutId })} 
          className="mt-6 border-dashed border-2 bg-transparent py-8 rounded-2xl text-slate-400 hover:text-indigo-600 hover:border-indigo-200"
        >
          <PlusIcon /> <span className="ml-2">Add Exercise</span>
        </Button>
      </div>
      {activeMenu && <div className="fixed inset-0 z-10" onClick={() => setActiveMenu(null)} />}
    </div>
  );
});

const ExerciseDetailView = memo(({ workoutId, exerciseId, workouts, setView, commitEntry, deleteEntry, updateEntry, setEditInstanceModal }: any) => {
  const workout = (workouts || []).find((w: Workout) => w.id === workoutId);
  const exercise = workout?.exercises?.find((e: Exercise) => e.id === exerciseId);
