          <button 
            onClick={() => setEditInstanceModal({ isOpen: true, workoutId, exerciseId: exercise.id, name: exercise.name, tags: exercise.tags, notes: exercise.notes })}
            className="p-2 text-indigo-600 hover:bg-white rounded-full transition-all"
