const ExerciseDetailView = memo(({ workoutId, exerciseId, workouts, setView, commitEntry, deleteEntry, updateEntry, setEditInstanceModal }: any) => {
  const workout = (workouts || []).find((w: Workout) => w.id === workoutId);
  const exercise = workout?.exercises?.find((e: Exercise) => e.id === exerciseId);
  const [draft, setDraft] = useState<any>(null);
  const [editingEntry, setEditingEntry] = useState<any>(null);
  const [activeMenu, setActiveMenu] = useState<string | null>(null);

  if (!exercise) return <div className="p-10 text-center">Exercise not found. <Button onClick={() => setView({type: 'workout-detail', workoutId})}>Go Back</Button></div>;
  const lastEntry = (exercise.entries || [])[0];

  const handleSaveLog = () => {
    if (!draft) return;
    commitEntry(workoutId, exerciseId, { ...draft, id: Date.now().toString() });
    setDraft(null);
  };

  const handleUpdateLog = () => {
    if (!editingEntry) return;
    updateEntry(workoutId, exerciseId, editingEntry);
    setEditingEntry(null);
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-white view-transition">
      <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
        <header className="py-6 flex items-center justify-between -mx-2">
          <button onClick={() => setView({ type: 'workout-detail', workoutId })} className="p-2 text-slate-500 hover:bg-white rounded-full transition-all"><ChevronLeftIcon /></button>
          <button 
            onClick={() => setEditInstanceModal({ isOpen: true, workoutId, exerciseId: exercise.id, name: exercise.name, tags: exercise.tags, notes: exercise.notes })}
            className="p-2 text-indigo-600 hover:bg-white rounded-full transition-all"
          >
            <EditIcon />
          </button>
        </header>

        <h1 className="text-2xl font-bold text-slate-900 tracking-tight leading-tight">{exercise.name}</h1>
        <div className="flex flex-wrap gap-2 mt-4">
          {(exercise.tags || []).map(tag => (
            <span key={tag} className={`px-2.5 py-1 text-[10px] font-bold rounded-lg uppercase tracking-wider ${tag.toLowerCase() === 'anchor' ? 'bg-indigo-600 text-white shadow-md' : 'bg-white border border-slate-200 text-slate-500'}`}>{tag}</span>
          ))}
        </div>

        {exercise.notes && (
          <div className="mt-4 p-4 bg-amber-50 rounded-xl border border-amber-100 text-xs text-amber-900 leading-relaxed italic">
            {exercise.notes}
          </div>
        )}

        {lastEntry && (
          <div className="mt-8 bg-white p-6 rounded-2xl border border-indigo-50 shadow-sm flex items-center justify-between">
            <div>
              <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.1em] mb-1">LATEST PERFORMANCE</p>
              <div className="flex items-baseline gap-2 text-2xl font-black">
                <span className="text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                <span className="text-indigo-600">{lastEntry.weight}kg</span>
              </div>
            </div>
            <div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
              <TrendingUpIcon />
            </div>
          </div>
        )}
      </div>

      <div className="px-6 py-8 pb-32">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold text-slate-900">History</h2>
          {!draft && (
            <Button size="sm" onClick={() => setDraft({ date: new Date().toISOString().split('T')[0], sets: lastEntry?.sets || 3, reps: lastEntry?.reps || 8, weight: lastEntry?.weight || 0 })}>
              <PlusIcon /> <span className="ml-1">Add Set</span>
            </Button>
          )}
        </div>

        {draft && (
          <div className="bg-indigo-50 p-4 rounded-2xl mb-6 border border-indigo-100 animate-in space-y-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-indigo-400 uppercase">Date</label>
              <input type="date" value={draft.date} onChange={e => setDraft({...draft, date: e.target.value})} className="w-full bg-white rounded-xl px-3 py-2 text-sm font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300" />
            </div>
            <div className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Sets</label>
                <input type="number" value={draft.sets} onChange={e => setDraft({...draft, sets: parseInt(e.target.value) || 0})} className="w-full bg-white rounded-xl px-3 py-2 text-sm font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Reps</label>
                <input type="number" value={draft.reps} onChange={e => setDraft({...draft, reps: parseInt(e.target.value) || 0})} className="w-full bg-white rounded-xl px-3 py-2 text-sm font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Weight</label>
                <input type="number" value={draft.weight} onChange={e => setDraft({...draft, weight: parseFloat(e.target.value) || 0})} className="w-full bg-white rounded-xl px-3 py-2 text-sm font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300" />
              </div>
            </div>
            <div className="flex gap-2">
              <Button fullWidth onClick={handleSaveLog}><CheckIcon /> <span className="ml-1">Save</span></Button>
              <Button variant="ghost" onClick={() => setDraft(null)} className="text-indigo-400"><XIcon /></Button>
            </div>
          </div>
        )}

        <div className="space-y-3">
          {(exercise.entries || []).map(ent => (
            <div key={ent.id} className="group relative flex items-center justify-between p-4 bg-slate-50 hover:bg-white hover:shadow-md border border-transparent hover:border-slate-100 rounded-2xl transition-all">
              <div className="flex items-center gap-4">
                <div className="text-xs font-bold text-slate-400 bg-white w-10 h-10 flex items-center justify-center rounded-xl border border-slate-100 text-center leading-tight">
                  {new Date(ent.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                </div>
                <div className="flex items-center gap-2">
                  <span className="font-bold text-slate-700">{ent.sets}x{ent.reps}</span>
                  <span className="text-indigo-600 font-black">{ent.weight}kg</span>
                </div>
              </div>
              <div className="relative">
                <button 
                  onClick={() => setActiveMenu(activeMenu === ent.id ? null : ent.id)} 
                  className="p-2 text-slate-300 hover:text-indigo-600 transition-all"
                >
                  <MoreIcon />
                </button>
                {activeMenu === ent.id && (
                  <div className="absolute right-0 top-10 w-32 bg-white border border-slate-100 shadow-xl rounded-xl z-20 py-1 overflow-hidden animate-in">
                    <button 
                      onClick={() => { setActiveMenu(null); setEditingEntry(ent); }}
                      className="w-full text-left px-4 py-2 text-xs font-semibold text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                    >
                      <EditIcon /> Edit
                    </button>
                    <button 
                      onClick={() => { setActiveMenu(null); if(confirm('Delete log?')) deleteEntry(workoutId, exerciseId, ent.id); }}
                      className="w-full text-left px-4 py-2 text-xs font-semibold text-rose-500 hover:bg-rose-50 flex items-center gap-2"
                    >
                      <TrashIcon /> Delete
                    </button>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {editingEntry && (
        <Modal title="Edit Entry" onClose={() => setEditingEntry(null)} onAction={handleUpdateLog} actionLabel="Update">
          <div className="space-y-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-indigo-400 uppercase">Date</label>
              <input type="date" value={editingEntry.date} onChange={e => setEditingEntry({...editingEntry, date: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-medium focus:bg-white outline-none" />
            </div>
            <div className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Sets</label>
                <input type="number" value={editingEntry.sets} onChange={e => setEditingEntry({...editingEntry, sets: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-bold focus:bg-white outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Reps</label>
                <input type="number" value={editingEntry.reps} onChange={e => setEditingEntry({...editingEntry, reps: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-bold focus:bg-white outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase">Weight</label>
                <input type="number" value={editingEntry.weight} onChange={e => setEditingEntry({...editingEntry, weight: parseFloat(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-bold focus:bg-white outline-none" />
              </div>
            </div>
          </div>
        </Modal>
      )}

      {activeMenu && <div className="fixed inset-0 z-10" onClick={() => setActiveMenu(null)} />}
    </div>
  );
});

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => safeParse('workouts', INITIAL_WORKOUTS));
  const [exerciseRepository, setExerciseRepository] = useState<RepoExercise[]>(() => {
    const saved = safeParse('exercise_repository', null);
    if (saved) return saved;
    const repoMap = new Map();
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => {
      if (!repoMap.has(ex.name)) {
        repoMap.set(ex.name, { id: ex.id, name: ex.name, tags: ex.tags, notes: ex.notes });
      }
    }));
    return Array.from(repoMap.values());
  });
  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    const saved = safeParse('available_tags', null);
    if (saved) return saved;
    const tags = new Set(PREDEFINED_TAGS);
    exerciseRepository.forEach(ex => ex.tags.forEach(t => { if(t.toLowerCase() !== 'anchor') tags.add(t.toLowerCase()); }));
    return Array.from(tags);
  });
  const [view, setView] = useState<ViewState>({ type: 'workouts' });
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [repoModal, setRepoModal] = useState<any>(null);
  const [addExerciseModal, setAddExerciseModal] = useState<any>(null);
  const [editInstanceModal, setEditInstanceModal] = useState<any>(null);
  const [customTagInput, setCustomTagInput] = useState('');

  useEffect(() => { localStorage.setItem('workouts', JSON.stringify(workouts)); }, [workouts]);
  useEffect(() => { localStorage.setItem('exercise_repository', JSON.stringify(exerciseRepository)); }, [exerciseRepository]);
  useEffect(() => { localStorage.setItem('available_tags', JSON.stringify(availableTags)); }, [availableTags]);

  const downloadData = useCallback(() => {
    const data = { workouts, exerciseRepository, availableTags, exportDate: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `trackyolifts_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [workouts, exerciseRepository, availableTags]);

  const resetToPlan = useCallback(() => {
    localStorage.removeItem('workouts');
    localStorage.removeItem('exercise_repository');
    localStorage.removeItem('available_tags');
    setWorkouts(INITIAL_WORKOUTS);

    // Refresh repo from initial data
    const repoMap = new Map();
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => {
      if (!repoMap.has(ex.name)) {
        repoMap.set(ex.name, { id: ex.id, name: ex.name, tags: ex.tags, notes: ex.notes });
      }
    }));
    setExerciseRepository(Array.from(repoMap.values()));

    // Refresh tags
    const tags = new Set(PREDEFINED_TAGS);
    INITIAL_WORKOUTS.forEach(w => w.exercises.forEach(ex => ex.tags.forEach(t => { if(t.toLowerCase() !== 'anchor') tags.add(t.toLowerCase()); })));
    setAvailableTags(Array.from(tags));

    setView({ type: 'workouts' });
  }, []);

  const deleteWorkout = (id: string) => setWorkouts(prev => prev.filter(w => w.id !== id));
  const deleteExercise = (workoutId: string, exerciseId: string) => {
    if(!confirm('Delete exercise from this workout?')) return;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { ...w, exercises: w.exercises.filter(ex => ex.id !== exerciseId) } : w));
  };
  const deleteFromRepo = (id: string) => setExerciseRepository(prev => prev.filter(e => e.id !== id));

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: [entry, ...ex.entries] } : ex)
    } : w));
  };

  const updateEntry = (workoutId: string, exerciseId: string, updatedEntry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? {
        ...ex, entries: ex.entries.map(e => e.id === updatedEntry.id ? updatedEntry : e)
      } : ex)
    } : w));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: ex.entries.filter(e => e.id !== entryId) } : ex)
    } : w));
  };
  const handleSaveRepoExercise = () => {
    if (!repoModal.name.trim()) return;
    const { id, name, tags, notes } = repoModal;
    if (id) {
      setExerciseRepository(prev => prev.map(e => e.id === id ? { id, name, tags, notes } : e));
    } else {
      setExerciseRepository(prev => [{ id: Date.now().toString(), name, tags, notes }, ...prev]);
    }
    setRepoModal(null);
  };
  const handleSaveEditInstance = () => {
    if (!editInstanceModal.name.trim()) return;
    const { workoutId, exerciseId, name, tags, notes } = editInstanceModal;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, name, tags, notes } : ex) } : w));
    setEditInstanceModal(null);
  }
  const addExerciseToWorkout = (workoutId: string, repoEx: RepoExercise) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { ...w, exercises: [...w.exercises, { ...repoEx, id: Date.now().toString(), entries: [] }] } : w));
    setAddExerciseModal(null);
  };
  const toggleTag = (tag: string, targetModal: any, setModal: any) => {
    const currentTags = targetModal.tags || [];
    setModal({ ...targetModal, tags: currentTags.includes(tag) ? currentTags.filter((t: string) => t !== tag) : [...currentTags, tag] });
  };
  const addCustomTag = (e: React.FormEvent, targetModal: any, setModal: any) => {
    e.preventDefault();
    const tag = customTagInput.trim().toLowerCase();
    if (!tag) return;
    if (!availableTags.includes(tag)) setAvailableTags(prev => [...prev, tag]);
    toggleTag(tag, targetModal, setModal);
    setCustomTagInput('');
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && <WorkoutsView workouts={workouts} setView={setView} deleteWorkout={deleteWorkout} setIsAddingWorkout={setIsAddingWorkout} setMenuOpen={setIsMenuOpen} />}
      {view.type === 'workout-detail' && <WorkoutDetailView workoutId={view.workoutId} workouts={workouts} setView={setView} deleteExercise={deleteExercise} setAddExerciseModal={setAddExerciseModal} setEditInstanceModal={setEditInstanceModal} />}
      {view.type === 'exercise-detail' && <ExerciseDetailView workoutId={view.workoutId} exerciseId={view.exerciseId} workouts={workouts} setView={setView} commitEntry={commitEntry} updateEntry={updateEntry} deleteEntry={deleteEntry} setEditInstanceModal={setEditInstanceModal} />}
      {view.type === 'manage-exercises' && <ManageExercisesView repository={exerciseRepository} setView={setView} deleteFromRepo={deleteFromRepo} setRepoModal={setRepoModal} />}
      <MenuDrawer isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onNavigate={setView} onDownload={downloadData} onReset={resetToPlan} />
      {isAddingWorkout && <Modal title="New Workout" onClose={() => setIsAddingWorkout(false)} onAction={() => { if(newWorkoutName) { setWorkouts([...workouts, {id: Date.now().toString(), name: newWorkoutName, exercises: []}]); setNewWorkoutName(''); setIsAddingWorkout(false); } }} actionLabel="Create">
          <input autoFocus type="text" value={newWorkoutName} onChange={(e) => setNewWorkoutName(e.target.value)} placeholder="e.g. Upper Body Power" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-medium focus:bg-white outline-none" />
        </Modal>}
      {repoModal && <Modal title={repoModal.id ? "Edit Global Move" : "New Global Move"} onClose={() => setRepoModal(null)} onAction={handleSaveRepoExercise} actionLabel="Save to Library">
          <div className="space-y-4">
            <input autoFocus type="text" value={repoModal.name} onChange={(e) => setRepoModal({...repoModal, name: e.target.value})} placeholder="Exercise Name" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-medium focus:bg-white outline-none" />
            <div className="flex flex-wrap gap-2">
              {availableTags.map(tag => (
                <button key={tag} onClick={() => toggleTag(tag, repoModal, setRepoModal)} className={`px-3 py-1.5 rounded-full text-xs font-bold border transition-all ${repoModal.tags.includes(tag) ? 'bg-indigo-600 text-white' : 'bg-white text-slate-500'}`}>{tag}</button>
              ))}
            </div>
            <div className="flex items-center gap-2 p-3 bg-indigo-50 rounded-xl border border-indigo-100">
               <input type="checkbox" checked={repoModal.tags.includes('anchor')} onChange={(e) => { const tags = e.target.checked ? [...repoModal.tags, 'anchor'] : repoModal.tags.filter((t:string) => t !== 'anchor'); setRepoModal({...repoModal, tags}); }} />
               <span className="text-sm font-bold text-indigo-700">Anchor Exercise</span>
            </div>
            <form onSubmit={(e) => addCustomTag(e, repoModal, setRepoModal)} className="flex gap-2">
                <input type="text" value={customTagInput} onChange={e => setCustomTagInput(e.target.value)} placeholder="New custom tag..." className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-3 py-2 text-xs outline-none" />
                <button type="submit" className="p-2 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-100"><PlusIcon /></button>
            </form>
            <textarea value={repoModal.notes} onChange={(e) => setRepoModal({...repoModal, notes: e.target.value})} placeholder="Notes/Cues" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 h-24 resize-none outline-none" />
          </div>
        </Modal>}
      {editInstanceModal && <Modal title="Edit Exercise Info" onClose={() => setEditInstanceModal(null)} onAction={handleSaveEditInstance} actionLabel="Update Move">
          <div className="space-y-4">
            <input autoFocus type="text" value={editInstanceModal.name} onChange={(e) => setEditInstanceModal({...editInstanceModal, name: e.target.value})} placeholder="Exercise Name" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-medium focus:bg-white outline-none" />
            <div className="flex flex-wrap gap-2">
              {availableTags.map(tag => (
                <button key={tag} onClick={() => toggleTag(tag, editInstanceModal, setEditInstanceModal)} className={`px-3 py-1.5 rounded-full text-xs font-bold border transition-all ${editInstanceModal.tags.includes(tag) ? 'bg-indigo-600 text-white' : 'bg-white text-slate-500'}`}>{tag}</button>
              ))}
            </div>
            <div className="flex items-center gap-2 p-3 bg-indigo-50 rounded-xl border border-indigo-100">
               <input type="checkbox" checked={editInstanceModal.tags.includes('anchor')} onChange={(e) => { const tags = e.target.checked ? [...editInstanceModal.tags, 'anchor'] : editInstanceModal.tags.filter((t:string) => t !== 'anchor'); setEditInstanceModal({...editInstanceModal, tags}); }} />
               <span className="text-sm font-bold text-indigo-700">Anchor Exercise</span>
            </div>
            <textarea value={editInstanceModal.notes} onChange={(e) => setEditInstanceModal({...editInstanceModal, notes: e.target.value})} placeholder="Notes/Cues" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 h-24 resize-none outline-none" />
          </div>
        </Modal>}
      {addExerciseModal && <Modal title="Add to Workout" onClose={() => setAddExerciseModal(null)} showAction={false}>
          <div className="space-y-4">
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Select from library</p>
            <div className="space-y-2 max-h-64 overflow-y-auto pr-1">
              {exerciseRepository.map(ex => (
                <button key={ex.id} onClick={() => addExerciseToWorkout(addExerciseModal.workoutId, ex)} className="w-full text-left p-4 bg-slate-50 hover:bg-indigo-50 hover:border-indigo-100 border border-transparent rounded-2xl transition-all">
                  <span className="font-bold text-slate-800">{ex.name}</span>
                  <div className="flex flex-wrap gap-1 mt-1">
                    {(ex.tags || []).map(t => <span key={t} className="text-[8px] uppercase font-bold text-slate-400">{t}</span>)}
                  </div>
                </button>
              ))}
            </div>
            <div className="pt-4 border-t border-slate-50">
               <Button fullWidth variant="secondary" onClick={() => { setRepoModal({ isOpen: true, name: '', tags: [], notes: '' }); setAddExerciseModal(null); }}>
                 <PlusIcon /> <span className="ml-2">Create New Exercise</span>
               </Button>
            </div>
          </div>
        </Modal>}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, memo, useMemo } from 'react';
import { Workout, Exercise, ViewState, Entry, RepoExercise } from './types';
import { INITIAL_WORKOUTS } from './constants';
import { Button } from './components/Button';
import { 
  PlusIcon, 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  TrashIcon, 
  EditIcon, 
  CheckIcon, 
  XIcon, 
  TrendingUpIcon, 
  ActivityIcon, 
  DownloadIcon, 
  MenuIcon, 
  BookOpenIcon, 
  SearchIcon, 
  MoreIcon,
  CalendarIcon
} from './components/Icons';

/**
 * Constants & Utility
 */

const PREDEFINED_TAGS = ['chest', 'back', 'legs', 'shoulders', 'biceps', 'triceps', 'abs', 'warm-up'];

const safeParse = (key: string, fallback: any) => {
  try {
    const item = localStorage.getItem(key);
    if (!item || item === 'undefined' || item === '[object Object]') return fallback;
    const parsed = JSON.parse(item);
    if (key === 'workouts' && !Array.isArray(parsed)) return fallback;
    return parsed ?? fallback;
  } catch (e) {
    console.warn(`Local storage parsing failed for ${key}, using defaults.`);
    return fallback;
  }
};

const formatDateCompact = (dateStr: string) => {
  const d = new Date(dateStr);
  const day = String(d.getDate()).padStart(2, '0');
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const year = String(d.getFullYear()).slice(-2);
  return `${day}.${month}.${year}`;
};

const getLatestDate = (entries: Entry[]) => {
  if (!entries || entries.length === 0) return null;
  const dates = entries.map(e => new Date(e.date).getTime());
  return new Date(Math.max(...dates)).toISOString().split('T')[0];
};

/**
 * Shared UI Components
 */

