                  onChange={e => setEditingEntry({...editingEntry, feeling: e.target.value || undefined})} 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-xs font-bold focus:bg-white outline-none appearance-none"
                >
                  <option value="">- Select -</option>
