const FeelingSelector = ({ value, onChange }: { value?: Entry['feeling'], onChange: (v: Entry['feeling']) => void }) => {
  const options: { id: Entry['feeling'], label: string, color: string, activeClass: string }[] = [
    { id: 'heavy', label: 'Heavy', color: 'text-rose-500 border-rose-100 bg-rose-50', activeClass: 'bg-rose-500 text-white border-rose-500' },
    { id: 'easy', label: 'Easy', color: 'text-emerald-500 border-emerald-100 bg-emerald-50', activeClass: 'bg-emerald-500 text-white border-emerald-500' },
    { id: 'up', label: 'Go up', color: 'text-blue-500 border-blue-100 bg-blue-50', activeClass: 'bg-blue-600 text-white border-blue-600' },
  ];

  return (
    <div className="flex gap-2 w-full">
      {options.map((opt) => (
        <button
          key={opt.id}
          type="button"
          onClick={() => onChange(value === opt.id ? undefined : opt.id)}
          className={`flex-1 py-2 px-1 text-[10px] font-black uppercase tracking-tighter rounded-xl border transition-all duration-200 ${
