                <div className="text-[10px] font-bold text-slate-400 bg-white w-10 h-10 flex items-center justify-center rounded-xl border border-slate-100 text-center leading-tight uppercase">
                   {formatDateCompact(ent.date)}
                </div>
                <div className="flex items-center gap-3">
                  <div className="flex items-center gap-2">
                    <span className="font-bold text-slate-700">{ent.sets}x{ent.reps}</span>
                    <span className="text-indigo-600 font-black">{ent.weight}kg</span>
                  </div>
                  <FeelingIndicator feeling={ent.feeling} />
                </div>
              </div>
              <div className="relative">
                <button 
                  onClick={() => setActiveMenu(activeMenu === ent.id ? null : ent.id)} 
                  className="p-2 text-slate-300 hover:text-indigo-600 transition-all"
                >
                  <MoreIcon />
                </button>
                {activeMenu === ent.id && (
                  <div className="absolute right-0 top-10 w-32 bg-white border border-slate-100 shadow-xl rounded-xl z-20 py-1 overflow-hidden animate-in">
                    <button 
                      onClick={() => { setActiveMenu(null); setEditingEntry(ent); }}
                      className="w-full text-left px-4 py-2 text-xs font-semibold text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                    >
                      <EditIcon /> Edit
                    </button>
                    <button 
                      onClick={() => { setActiveMenu(null); if(confirm('Delete log?')) deleteEntry(workoutId, exerciseId, ent.id); }}
                      className="w-full text-left px-4 py-2 text-xs font-semibold text-rose-500 hover:bg-rose-50 flex items-center gap-2"
                    >
                      <TrashIcon /> Delete
                    </button>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {editingEntry && (
        <Modal title="Edit Entry" onClose={() => setEditingEntry(null)} onAction={handleUpdateLog} actionLabel="Update">
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter">Date</label>
                <input type="date" value={editingEntry.date} onChange={e => setEditingEntry({...editingEntry, date: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-xs font-medium focus:bg-white outline-none shadow-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter">Felt like</label>
                <FeelingSelector value={editingEntry.feeling} onChange={v => setEditingEntry({...editingEntry, feeling: v})} />
              </div>
            </div>
            <div className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter">Sets</label>
                <input type="number" value={editingEntry.sets} onChange={e => setEditingEntry({...editingEntry, sets: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-bold focus:bg-white outline-none shadow-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter">Reps</label>
                <input type="number" value={editingEntry.reps} onChange={e => setEditingEntry({...editingEntry, reps: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-bold focus:bg-white outline-none shadow-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter">Weight</label>
                <input type="number" value={editingEntry.weight} onChange={e => setEditingEntry({...editingEntry, weight: parseFloat(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-bold focus:bg-white outline-none shadow-sm" />
