/**
 * Constants & Utility
 */

const PREDEFINED_TAGS = ['chest', 'back', 'legs', 'shoulders', 'biceps', 'triceps', 'abs', 'warm-up'];

const safeParse = (key: string, fallback: any) => {
  try {
    const item = localStorage.getItem(key);
    if (!item || item === 'undefined' || item === '[object Object]') return fallback;
    const parsed = JSON.parse(item);
    if (key === 'workouts' && !Array.isArray(parsed)) return fallback;
    return parsed ?? fallback;
  } catch (e) {
    console.warn(`Local storage parsing failed for ${key}, using defaults.`);
    return fallback;
  }
};

const formatDateCompact = (dateStr: string) => {
  const d = new Date(dateStr);
  return d.toLocaleDateString(undefined, { day: 'numeric', month: 'short' }).toUpperCase();
};

const getLatestDate = (entries: Entry[]) => {
  if (!entries || entries.length === 0) return null;
  const dates = entries.map(e => new Date(e.date).getTime());
  return new Date(Math.max(...dates)).toISOString().split('T')[0];
};

const FeelingIndicator = ({ feeling }: { feeling?: Entry['feeling'] }) => {
  if (!feeling) return null;
  switch (feeling) {
    case 'heavy':
      return <div className="w-2.5 h-2.5 rounded-full bg-rose-500 shadow-sm shadow-rose-200" title="Felt heavy" />;
    case 'easy':
      return <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 shadow-sm shadow-emerald-200" title="Felt easy" />;
    case 'up':
      return (
        <div className="flex items-center justify-center w-5 h-5 rounded-full bg-blue-50 text-blue-600 border border-blue-100" title="Go up next">
          <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="12" y1="19" x2="12" y2="5"></line>
            <polyline points="5 12 12 5 19 12"></polyline>
          </svg>
        </div>
      );
    default:
      return null;
  }
};

/**
 * Custom components for forms
 */

const FeelingSelector = ({ value, onChange }: { value?: Entry['feeling'], onChange: (v: Entry['feeling']) => void }) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const options: { id: Entry['feeling'], label: string, colorClass: string, icon?: React.ReactNode }[] = [
    { id: 'heavy', label: 'Felt heavy', colorClass: 'text-rose-600' },
    { id: 'easy', label: 'Felt easy', colorClass: 'text-emerald-600' },
    { id: 'up', label: 'Go up next', colorClass: 'text-blue-600', icon: (
      <div className="w-5 h-5 rounded-full bg-blue-100 flex items-center justify-center text-blue-700 ml-1.5">
        <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
          <line x1="12" y1="19" x2="12" y2="5"></line>
          <polyline points="5 12 12 5 19 12"></polyline>
        </svg>
      </div>
    )},
  ];

  const selectedOption = options.find(o => o.id === value);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="relative w-full" ref={containerRef}>
      <button
        type="button"
        onClick={(e) => { e.stopPropagation(); setIsOpen(!isOpen); }}
        className="w-full flex items-center justify-between bg-white border border-slate-200 rounded-xl px-3 py-2.5 text-xs font-bold transition-all focus:ring-2 focus:ring-indigo-100 outline-none min-h-[44px] shadow-sm"
      >
        {selectedOption ? (
          <div className={`flex items-center ${selectedOption.colorClass}`}>
            {selectedOption.label}
            {selectedOption.icon}
          </div>
        ) : (
          <span className="text-slate-400 font-medium italic">Optional</span>
        )}
        <div className={`transition-transform duration-200 text-slate-300 ${isOpen ? 'rotate-180' : ''}`}>
          <ChevronRightIcon />
        </div>
      </button>

      {isOpen && (
        <div className="absolute z-[200] left-0 right-0 mt-2 bg-white border border-slate-100 shadow-2xl rounded-2xl py-1 overflow-hidden animate-in">
          <button
            type="button"
            onClick={(e) => { e.stopPropagation(); onChange(undefined); setIsOpen(false); }}
            className="w-full text-left px-4 py-3 text-xs font-bold text-slate-400 hover:bg-slate-50 transition-colors border-b border-slate-50"
          >
            - None -
          </button>
          {options.map((opt) => (
            <button
              key={opt.id}
              type="button"
              onClick={(e) => { e.stopPropagation(); onChange(opt.id); setIsOpen(false); }}
              className={`w-full text-left px-4 py-3.5 text-xs font-bold flex items-center justify-between transition-colors hover:bg-slate-50 ${opt.colorClass} ${value === opt.id ? 'bg-indigo-50/40' : ''}`}
            >
              <div className="flex items-center">
                {opt.label}
                {opt.icon}
              </div>
              {value === opt.id && <CheckIcon />}
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

