      </div>

      <div className="px-6 py-8 pb-32">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold text-slate-900">History</h2>
          {!draft && (
            <Button size="sm" onClick={() => setDraft({ date: new Date().toISOString().split('T')[0], sets: lastEntry?.sets || 3, reps: lastEntry?.reps || 8, weight: lastEntry?.weight || 0, feeling: undefined })}>
              <PlusIcon /> <span className="ml-1">Add Set</span>
            </Button>
          )}
        </div>

        {draft && (
          <div className="bg-indigo-50 p-4 rounded-2xl mb-6 border border-indigo-100 animate-in space-y-4 shadow-sm">
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter">Date</label>
                <input type="date" value={draft.date} onChange={e => setDraft({...draft, date: e.target.value})} className="w-full bg-white rounded-xl px-3 py-2 text-xs font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300 shadow-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter">Felt like</label>
                <FeelingSelector value={draft.feeling} onChange={v => setDraft({...draft, feeling: v})} />
              </div>
            </div>
            <div className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter">Sets</label>
                <input 
