            <div className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter">Sets</label>
                <input 
                  type="number" 
                  value={editingEntry.sets} 
                  onChange={e => setEditingEntry({...editingEntry, sets: e.target.value})} 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-bold focus:bg-white outline-none shadow-sm" 
                  inputMode="numeric"
