                                    setEditInstanceModal({ isOpen: true, workoutId, exerciseId: ex.id, name: ex.name, tags: ex.tags, notes: ex.notes }); 
                                }}
                                className="w-full text-left px-4 py-3.5 text-xs font-bold text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                             >
                                <EditIcon /> Edit Exercise Info
                             </button>
                             <button 
                                onClick={(e) => { 
                                    e.preventDefault();
                                    e.stopPropagation(); 
                                    setActiveMenu(null); 
                                    deleteExercise(workoutId, ex.id); 
                                }}
                                className="w-full text-left px-4 py-3.5 text-xs font-bold text-rose-500 hover:bg-rose-50 flex items-center gap-2 border-t border-slate-50"
                             >
                                <TrashIcon /> Remove from Day
                             </button>
                        </div>
                    )}
                </div>
              </div>

              <div className="mt-4 pt-3 border-t border-slate-50 flex items-end justify-between">
                <div className="flex items-center gap-3">
                  {lastEntry ? (
                    <div className="flex items-baseline gap-2 text-sm">
                      <span className="font-bold text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                      <span className="text-slate-400 font-medium">at</span>
                      <span className="font-black text-indigo-600">{lastEntry.weight}kg</span>
                    </div>
                  ) : (
                    <div className="text-xs text-slate-300 font-bold italic">No entries yet</div>
                  )}
                  <FeelingIndicator feeling={lastEntry?.feeling} />
                </div>

                {latestEntryDate && (
                  <div className="text-[9px] font-black text-slate-400 tracking-tight border border-slate-200 px-1.5 py-0.5 rounded-md bg-white uppercase">
                    LAST: {formatDateCompact(latestEntryDate)}
                  </div>
                )}
              </div>
            </div>
          );
        })}
        <Button 
          variant="secondary" 
          fullWidth 
          onClick={() => setAddExerciseModal({ isOpen: true, workoutId })} 
          className="mt-6 border-dashed border-2 bg-transparent py-8 rounded-2xl text-slate-400 hover:text-indigo-600 hover:border-indigo-200"
        >
          <PlusIcon /> <span className="ml-2 font-bold">Add Exercise</span>
        </Button>
      </div>
      {activeMenu && <div className="fixed inset-0 z-[190]" onClick={() => setActiveMenu(null)} />}
    </div>
  );
});

const ExerciseDetailView = memo(({ workoutId, exerciseId, workouts, setView, commitEntry, deleteEntry, updateEntry, setEditInstanceModal }: any) => {
  const workout = (workouts || []).find((w: Workout) => w.id === workoutId);
  const exercise = workout?.exercises?.find((e: Exercise) => e.id === exerciseId);
  const [draft, setDraft] = useState<any>(null);
  const [editingEntry, setEditingEntry] = useState<any>(null);
  const [activeMenu, setActiveMenu] = useState<string | null>(null);

  if (!exercise) return <div className="p-10 text-center">Exercise not found. <Button onClick={() => setView({type: 'workout-detail', workoutId})}>Go Back</Button></div>;
  const lastEntry = (exercise.entries || [])[0];

  const handleSaveLog = () => {
    if (!draft) return;
    // Allow empty string to default to 0 during final save
    const entryToCommit = {
        ...draft,
        sets: parseInt(draft.sets || '0') || 0,
        reps: parseInt(draft.reps || '0') || 0,
        weight: parseFloat(draft.weight || '0') || 0,
        id: Date.now().toString()
    };
    commitEntry(workoutId, exerciseId, entryToCommit);
    setDraft(null);
  };

  const handleUpdateLog = () => {
    if (!editingEntry) return;
    const entryToUpdate = {
        ...editingEntry,
        sets: parseInt(editingEntry.sets || '0') || 0,
        reps: parseInt(editingEntry.reps || '0') || 0,
        weight: parseFloat(editingEntry.weight || '0') || 0
    };
    updateEntry(workoutId, exerciseId, entryToUpdate);
    setEditingEntry(null);
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-white view-transition">
      <div className="bg-slate-50 px-6 pb-8 border-b border-slate-100">
        <header className="py-6 flex items-center justify-between -mx-2">
          <button onClick={() => setView({ type: 'workout-detail', workoutId })} className="p-2 text-slate-500 hover:bg-white rounded-full transition-all"><ChevronLeftIcon /></button>
          <button 
            onClick={() => setEditInstanceModal({ isOpen: true, workoutId, exerciseId: exercise.id, name: exercise.name, tags: exercise.tags, notes: exercise.notes })}
            className="p-2 text-indigo-600 hover:bg-white rounded-full transition-all"
          >
            <EditIcon />
          </button>
        </header>

        <h1 className="text-2xl font-bold text-slate-900 tracking-tight leading-tight">{exercise.name}</h1>
        <div className="flex flex-wrap gap-2 mt-4">
          {(exercise.tags || []).map(tag => (
            <span key={tag} className={`px-2.5 py-1 text-[10px] font-bold rounded-lg uppercase tracking-wider ${tag.toLowerCase() === 'anchor' ? 'bg-indigo-600 text-white shadow-md' : 'bg-white border border-slate-200 text-slate-500'}`}>{tag}</span>
          ))}
        </div>

        {exercise.notes && (
          <div className="mt-4 p-4 bg-amber-50 rounded-xl border border-amber-100 text-xs text-amber-900 leading-relaxed font-medium italic">
            {exercise.notes}
          </div>
        )}

        {lastEntry && (
          <div className="mt-8 bg-white p-6 rounded-2xl border border-indigo-50 shadow-sm flex items-center justify-between">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.1em]">LATEST PERFORMANCE</p>
                <FeelingIndicator feeling={lastEntry.feeling} />
              </div>
              <div className="flex items-baseline gap-2 text-2xl font-black">
                <span className="text-slate-900">{lastEntry.sets}x{lastEntry.reps}</span>
                <span className="text-indigo-600">{lastEntry.weight}kg</span>
              </div>
            </div>
            <div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
              <TrendingUpIcon />
            </div>
          </div>
        )}
      </div>

      <div className="px-6 py-8 pb-32">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold text-slate-900">History</h2>
          {!draft && (
            <Button size="sm" onClick={() => setDraft({ date: new Date().toISOString().split('T')[0], sets: (lastEntry?.sets ?? 3).toString(), reps: (lastEntry?.reps ?? 8).toString(), weight: (lastEntry?.weight ?? 0).toString(), feeling: undefined })}>
              <PlusIcon /> <span className="ml-1 font-bold">Add Set</span>
            </Button>
          )}
        </div>

        {draft && (
          <div className="bg-indigo-50 p-4 rounded-2xl mb-6 border border-indigo-100 animate-in space-y-4 shadow-sm">
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Date</label>
                <input type="date" value={draft.date} onChange={e => setDraft({...draft, date: e.target.value})} className="w-full bg-white rounded-xl px-3 py-2 text-xs font-bold border-none outline-none focus:ring-2 focus:ring-indigo-300 shadow-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Felt like</label>
                <FeelingSelector value={draft.feeling} onChange={v => setDraft({...draft, feeling: v})} />
              </div>
            </div>
            <div className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Sets</label>
                <input 
                  type="text" 
                  value={draft.sets} 
                  onChange={e => setDraft({...draft, sets: e.target.value})} 
                  className="w-full bg-white rounded-xl px-3 py-2 text-sm font-black border-none outline-none focus:ring-2 focus:ring-indigo-300 shadow-sm" 
                  placeholder="0"
                  inputMode="numeric"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Reps</label>
                <input 
                  type="text" 
                  value={draft.reps} 
                  onChange={e => setDraft({...draft, reps: e.target.value})} 
                  className="w-full bg-white rounded-xl px-3 py-2 text-sm font-black border-none outline-none focus:ring-2 focus:ring-indigo-300 shadow-sm" 
                  placeholder="0"
                  inputMode="numeric"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Weight</label>
                <input 
                  type="text" 
                  value={draft.weight} 
                  onChange={e => setDraft({...draft, weight: e.target.value})} 
                  className="w-full bg-white rounded-xl px-3 py-2 text-sm font-black border-none outline-none focus:ring-2 focus:ring-indigo-300 shadow-sm" 
                  placeholder="0.0"
                  inputMode="decimal"
                />
              </div>
            </div>
            <div className="flex gap-2 pt-1">
              <Button fullWidth onClick={handleSaveLog} className="font-bold"><CheckIcon /> <span className="ml-1">Save Log</span></Button>
              <Button variant="ghost" onClick={() => setDraft(null)} className="text-indigo-400"><XIcon /></Button>
            </div>
          </div>
        )}

        <div className="space-y-3">
          {(exercise.entries || []).map(ent => (
            <div key={ent.id} className="group relative flex items-center justify-between p-4 bg-slate-50 hover:bg-white hover:shadow-md border border-transparent hover:border-slate-100 rounded-2xl transition-all">
              <div className="flex items-center gap-4">
                <div className="text-[10px] font-black text-slate-400 bg-white w-10 h-10 flex items-center justify-center rounded-xl border border-slate-100 text-center leading-tight uppercase shadow-sm">
                   {formatDateCompact(ent.date)}
                </div>
                <div className="flex items-center gap-3">
                  <div className="flex items-center gap-2">
                    <span className="font-black text-slate-700">{ent.sets}x{ent.reps}</span>
                    <span className="text-indigo-600 font-black">{ent.weight}kg</span>
                  </div>
                  <FeelingIndicator feeling={ent.feeling} />
                </div>
              </div>
              <div className="relative">
                <button 
                  onClick={(e) => { e.stopPropagation(); setActiveMenu(activeMenu === ent.id ? null : ent.id); }} 
                  className="p-2 text-slate-300 hover:text-indigo-600 transition-all"
                >
                  <MoreIcon />
                </button>
                {activeMenu === ent.id && (
                  <div className="absolute right-0 top-10 w-36 bg-white border border-slate-100 shadow-2xl rounded-2xl z-[200] py-1 overflow-hidden animate-in">
                    <button 
                      onClick={(e) => { 
                        e.stopPropagation(); 
                        setActiveMenu(null); 
                        setEditingEntry({ ...ent, sets: ent.sets.toString(), reps: ent.reps.toString(), weight: ent.weight.toString() }); 
                      }}
                      className="w-full text-left px-4 py-3.5 text-xs font-bold text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                    >
                      <EditIcon /> Edit Entry
                    </button>
                    <button 
                      onClick={(e) => { 
                        e.stopPropagation(); 
                        setActiveMenu(null); 
                        if(window.confirm('Delete this log permanently?')) deleteEntry(workoutId, exerciseId, ent.id); 
                      }}
                      className="w-full text-left px-4 py-3.5 text-xs font-bold text-rose-500 hover:bg-rose-50 flex items-center gap-2 border-t border-slate-50"
                    >
                      <TrashIcon /> Delete Entry
                    </button>
                  </div>
                )}
              </div>
            </div>
          ))}
          {exercise.entries.length === 0 && !draft && (
            <div className="py-12 text-center">
              <p className="text-slate-400 italic text-sm">No sets logged yet. Let's get to work!</p>
            </div>
          )}
        </div>
      </div>

      {editingEntry && (
        <Modal title="Edit Entry" onClose={() => setEditingEntry(null)} onAction={handleUpdateLog} actionLabel="Update">
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Date</label>
                <input type="date" value={editingEntry.date} onChange={e => setEditingEntry({...editingEntry, date: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-xs font-bold focus:bg-white outline-none shadow-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Felt like</label>
                <FeelingSelector value={editingEntry.feeling} onChange={v => setEditingEntry({...editingEntry, feeling: v})} />
              </div>
            </div>
            <div className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Sets</label>
                <input 
                  type="text" 
                  value={editingEntry.sets} 
                  onChange={e => setEditingEntry({...editingEntry, sets: e.target.value})} 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-black focus:bg-white outline-none shadow-sm" 
                  inputMode="numeric"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Reps</label>
                <input 
                  type="text" 
                  value={editingEntry.reps} 
                  onChange={e => setEditingEntry({...editingEntry, reps: e.target.value})} 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-black focus:bg-white outline-none shadow-sm" 
                  inputMode="numeric"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Weight</label>
                <input 
                  type="text" 
                  value={editingEntry.weight} 
                  onChange={e => setEditingEntry({...editingEntry, weight: e.target.value})} 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-black focus:bg-white outline-none shadow-sm" 
                  inputMode="decimal"
                />
              </div>
            </div>
          </div>
        </Modal>
      )}

      {activeMenu && <div className="fixed inset-0 z-[190]" onClick={() => setActiveMenu(null)} />}
    </div>
  );
});

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => safeParse('workouts', INITIAL_WORKOUTS));
  const [exerciseRepository, setExerciseRepository] = useState<RepoExercise[]>(() => {
    // New users start with an empty library
    return safeParse('exercise_repository', []);
  });
  const [availableTags, setAvailableTags] = useState<string[]>(() => {
    return safeParse('available_tags', PREDEFINED_TAGS);
  });
  const [view, setView] = useState<ViewState>({ type: 'workouts' });
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [repoModal, setRepoModal] = useState<any>(null);
  const [addExerciseModal, setAddExerciseModal] = useState<any>(null);
  const [editInstanceModal, setEditInstanceModal] = useState<any>(null);
  const [customTagInput, setCustomTagInput] = useState('');

  useEffect(() => { localStorage.setItem('workouts', JSON.stringify(workouts)); }, [workouts]);
  useEffect(() => { localStorage.setItem('exercise_repository', JSON.stringify(exerciseRepository)); }, [exerciseRepository]);
  useEffect(() => { localStorage.setItem('available_tags', JSON.stringify(availableTags)); }, [availableTags]);

  const downloadData = useCallback(() => {
    const data = { workouts, exerciseRepository, availableTags, exportDate: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `trackyolifts_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [workouts, exerciseRepository, availableTags]);

  const resetToPlan = useCallback(() => {
    localStorage.removeItem('workouts');
    localStorage.removeItem('exercise_repository');
    localStorage.removeItem('available_tags');
    setWorkouts(INITIAL_WORKOUTS);
    setExerciseRepository([]);
    setAvailableTags(PREDEFINED_TAGS);
    setView({ type: 'workouts' });
  }, []);

  const deleteWorkout = (id: string) => setWorkouts(prev => prev.filter(w => w.id !== id));

  const deleteExercise = useCallback((workoutId: string, exerciseId: string) => {
    if(!window.confirm('Are you sure you want to remove this exercise from today?')) return;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { 
        ...w, 
        exercises: w.exercises.filter(ex => ex.id !== exerciseId) 
    } : w));
  }, []);

  const deleteFromRepo = (id: string) => setExerciseRepository(prev => prev.filter(e => e.id !== id));

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: [entry, ...ex.entries] } : ex)
    } : w));
  };

  const updateEntry = (workoutId: string, exerciseId: string, updatedEntry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => {
        if (ex.id === exerciseId) {
          return {
            ...ex,
            entries: ex.entries.map(e => (e.id === updatedEntry.id ? updatedEntry : e))
          };
        }
        return ex;
      })
    } : w));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: ex.entries.filter(e => e.id !== entryId) } : ex)
    } : w));
  };

  const handleSaveRepoExercise = () => {
    if (!repoModal.name.trim()) return;
    const { id, name, tags, notes } = repoModal;
    if (id) {
      setExerciseRepository(prev => prev.map(e => e.id === id ? { id, name, tags, notes } : e));
    } else {
      setExerciseRepository(prev => [{ id: Date.now().toString(), name, tags, notes }, ...prev]);
    }
    setRepoModal(null);
  };

  const handleSaveEditInstance = () => {
    if (!editInstanceModal.name.trim()) return;
    const { workoutId, exerciseId, name, tags, notes } = editInstanceModal;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, name, tags, notes } : ex) } : w));
    setEditInstanceModal(null);
  }

  const addExerciseToWorkout = (workoutId: string, repoEx: RepoExercise) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { ...w, exercises: [...w.exercises, { ...repoEx, id: Date.now().toString(), entries: [] }] } : w));
    setAddExerciseModal(null);
  };

  const toggleTag = (tag: string, targetModal: any, setModal: any) => {
    const currentTags = targetModal.tags || [];
    setModal({ ...targetModal, tags: currentTags.includes(tag) ? currentTags.filter((t: string) => t !== tag) : [...currentTags, tag] });
  };

  const addCustomTag = (e: React.FormEvent, targetModal: any, setModal: any) => {
    e.preventDefault();
    const tag = customTagInput.trim().toLowerCase();
    if (!tag) return;
    if (!availableTags.includes(tag)) setAvailableTags(prev => [...prev, tag]);
    toggleTag(tag, targetModal, setModal);
    setCustomTagInput('');
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && <WorkoutsView workouts={workouts} setView={setView} deleteWorkout={deleteWorkout} setIsAddingWorkout={setIsAddingWorkout} setMenuOpen={setIsMenuOpen} />}
      {view.type === 'workout-detail' && <WorkoutDetailView workoutId={view.workoutId} workouts={workouts} setView={setView} deleteExercise={deleteExercise} setAddExerciseModal={setAddExerciseModal} setEditInstanceModal={setEditInstanceModal} />}
      {view.type === 'exercise-detail' && <ExerciseDetailView workoutId={view.workoutId} exerciseId={view.exerciseId} workouts={workouts} setView={setView} commitEntry={commitEntry} updateEntry={updateEntry} deleteEntry={deleteEntry} setEditInstanceModal={setEditInstanceModal} />}
      {view.type === 'manage-exercises' && <ManageExercisesView repository={exerciseRepository} setView={setView} deleteFromRepo={deleteFromRepo} setRepoModal={setRepoModal} />}
      <MenuDrawer isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onNavigate={setView} onDownload={downloadData} onReset={resetToPlan} />

      {isAddingWorkout && (
        <Modal title="New Workout" onClose={() => setIsAddingWorkout(false)} onAction={() => { if(newWorkoutName) { setWorkouts([...workouts, {id: Date.now().toString(), name: newWorkoutName, exercises: []}]); setNewWorkoutName(''); setIsAddingWorkout(false); } }} actionLabel="Create">
          <input autoFocus type="text" value={newWorkoutName} onChange={(e) => setNewWorkoutName(e.target.value)} placeholder="e.g. Upper Body Power" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-bold focus:bg-white outline-none focus:ring-2 focus:ring-indigo-100" />
        </Modal>
      )}

      {repoModal && (
        <Modal title={repoModal.id ? "Edit Global Move" : "New Global Move"} onClose={() => setRepoModal(null)} onAction={handleSaveRepoExercise} actionLabel="Save to Library">
          <div className="space-y-4">
            <input autoFocus type="text" value={repoModal.name} onChange={(e) => setRepoModal({...repoModal, name: e.target.value})} placeholder="Exercise Name" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-bold focus:bg-white outline-none focus:ring-2 focus:ring-indigo-100" />
            <div className="flex flex-wrap gap-2">
              {availableTags.map(tag => (
                <button key={tag} onClick={() => toggleTag(tag, repoModal, setRepoModal)} className={`px-3 py-1.5 rounded-full text-xs font-bold border transition-all ${repoModal.tags.includes(tag) ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-slate-500 hover:bg-slate-50'}`}>{tag}</button>
              ))}
            </div>
            <div className="flex items-center gap-2 p-3 bg-indigo-50 rounded-xl border border-indigo-100">
               <input type="checkbox" className="w-4 h-4 rounded border-indigo-300 text-indigo-600 focus:ring-indigo-500" checked={repoModal.tags.includes('anchor')} onChange={(e) => { const tags = e.target.checked ? [...repoModal.tags, 'anchor'] : repoModal.tags.filter((t:string) => t !== 'anchor'); setRepoModal({...repoModal, tags}); }} />
               <span className="text-sm font-bold text-indigo-700">Anchor Exercise</span>
            </div>
            <form onSubmit={(e) => addCustomTag(e, repoModal, setRepoModal)} className="flex gap-2">
                <input type="text" value={customTagInput} onChange={e => setCustomTagInput(e.target.value)} placeholder="New custom tag..." className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-3 py-2 text-xs outline-none focus:bg-white focus:ring-1 focus:ring-indigo-100 font-bold" />
                <button type="submit" className="p-2 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-100 transition-colors shadow-sm"><PlusIcon /></button>
            </form>
            <textarea value={repoModal.notes} onChange={(e) => setRepoModal({...repoModal, notes: e.target.value})} placeholder="Notes/Cues" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 h-24 resize-none outline-none focus:bg-white focus:ring-1 focus:ring-indigo-100 font-bold" />
          </div>
        </Modal>
      )}

      {editInstanceModal && (
        <Modal title="Edit Exercise Info" onClose={() => setEditInstanceModal(null)} onAction={handleSaveEditInstance} actionLabel="Update Move">
          <div className="space-y-4">
