                  type="text" 
                  value={draft.weight} 
                  onChange={e => setDraft({...draft, weight: e.target.value})} 
                  className="w-full bg-white rounded-xl px-3 py-2 text-sm font-black border-none outline-none focus:ring-2 focus:ring-indigo-300 shadow-sm" 
                  placeholder="0.0"
                  inputMode="decimal"
                />
