                  type="text" 
                  value={draft.weight} 
                  onChange={e => setDraft({...draft, weight: e.target.value})} 
                  className="w-full bg-white rounded-xl px-3 py-2 text-sm font-black border-none outline-none focus:ring-2 focus:ring-indigo-300 shadow-sm" 
                  placeholder="0.0"
                  inputMode="decimal"
                />
              </div>
            </div>
            <div className="flex gap-2 pt-1">
              <Button fullWidth onClick={handleSaveLog} className="font-bold"><CheckIcon /> <span className="ml-1">Save Log</span></Button>
              <Button variant="ghost" onClick={() => setDraft(null)} className="text-indigo-400"><XIcon /></Button>
            </div>
          </div>
        )}

        <div className="space-y-3">
          {(exercise.entries || []).map(ent => (
            <div key={ent.id} className="group relative flex items-center justify-between p-4 bg-slate-50 hover:bg-white hover:shadow-md border border-transparent hover:border-slate-100 rounded-2xl transition-all">
              <div className="flex items-center gap-4">
                <div className="text-[10px] font-black text-slate-400 bg-white w-10 h-10 flex items-center justify-center rounded-xl border border-slate-100 text-center leading-tight uppercase shadow-sm">
                   {formatDateCompact(ent.date)}
                </div>
                <div className="flex items-center gap-3">
                  <div className="flex items-center gap-2">
                    <span className="font-black text-slate-700">{ent.sets}x{ent.reps}</span>
                    <span className="text-indigo-600 font-black">{ent.weight}kg</span>
                  </div>
                  <FeelingIndicator feeling={ent.feeling} />
                </div>
              </div>
              <div className="relative">
                <button 
                  onClick={(e) => { e.stopPropagation(); setActiveMenu(activeMenu === ent.id ? null : ent.id); }} 
                  className="p-3 -m-3 text-slate-300 hover:text-indigo-600 transition-all z-[10]"
                >
                  <MoreIcon />
                </button>
                {activeMenu === ent.id && (
                  <div className="absolute right-0 top-10 w-44 bg-white border border-slate-100 shadow-2xl rounded-2xl z-[500] py-1 overflow-hidden animate-in">
                    <button 
                      onClick={(e) => { 
                        e.stopPropagation(); 
                        setActiveMenu(null); 
                        setEditingEntry({ ...ent, sets: ent.sets.toString(), reps: ent.reps.toString(), weight: ent.weight.toString() }); 
                      }}
                      className="w-full text-left px-4 py-4 text-xs font-bold text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                    >
                      <EditIcon /> Edit Entry
                    </button>
                    <button 
                      onClick={(e) => { 
                        e.stopPropagation(); 
                        setActiveMenu(null); 
                        if(window.confirm('Delete log?')) deleteEntry(workoutId, exerciseId, ent.id); 
                      }}
                      className="w-full text-left px-4 py-4 text-xs font-bold text-rose-500 hover:bg-rose-50 flex items-center gap-2 border-t border-slate-50"
                    >
                      <TrashIcon /> Delete Entry
                    </button>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {editingEntry && (
        <Modal title="Edit Entry" onClose={() => setEditingEntry(null)} onAction={handleUpdateLog} actionLabel="Update">
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Date</label>
                <input type="date" value={editingEntry.date} onChange={e => setEditingEntry({...editingEntry, date: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-xs font-bold focus:bg-white outline-none shadow-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Felt like</label>
                <FeelingSelector value={editingEntry.feeling} onChange={v => setEditingEntry({...editingEntry, feeling: v})} />
              </div>
            </div>
            <div className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Sets</label>
                <input 
                  type="text" 
                  value={editingEntry.sets} 
                  onChange={e => setEditingEntry({...editingEntry, sets: e.target.value})} 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-black focus:bg-white outline-none shadow-sm" 
                  inputMode="numeric"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Reps</label>
                <input 
                  type="text" 
                  value={editingEntry.reps} 
                  onChange={e => setEditingEntry({...editingEntry, reps: e.target.value})} 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-black focus:bg-white outline-none shadow-sm" 
                  inputMode="numeric"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Weight</label>
                <input 
                  type="text" 
                  value={editingEntry.weight} 
                  onChange={e => setEditingEntry({...editingEntry, weight: e.target.value})} 
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-black focus:bg-white outline-none shadow-sm" 
                  inputMode="decimal"
                />
              </div>
            </div>
          </div>
        </Modal>
      )}

      {activeMenu && <div className="fixed inset-0 z-[450]" onClick={() => setActiveMenu(null)} />}
    </div>
  );
});

const App: React.FC = () => {
  const [workouts, setWorkouts] = useState<Workout[]>(() => safeParse('workouts', INITIAL_WORKOUTS));
  const [exerciseRepository, setExerciseRepository] = useState<RepoExercise[]>(() => safeParse('exercise_repository', []));
  const [availableTags, setAvailableTags] = useState<string[]>(() => safeParse('available_tags', PREDEFINED_TAGS));
  const [view, setView] = useState<ViewState>({ type: 'workouts' });
  const [isAddingWorkout, setIsAddingWorkout] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [newWorkoutName, setNewWorkoutName] = useState('');
  const [repoModal, setRepoModal] = useState<any>(null);
  const [customTagInput, setCustomTagInput] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  useEffect(() => { localStorage.setItem('workouts', JSON.stringify(workouts)); }, [workouts]);
  useEffect(() => { localStorage.setItem('exercise_repository', JSON.stringify(exerciseRepository)); }, [exerciseRepository]);
  useEffect(() => { localStorage.setItem('available_tags', JSON.stringify(availableTags)); }, [availableTags]);

  const downloadData = useCallback(() => {
    const data = { workouts, exerciseRepository, availableTags, exportDate: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `trackyolifts_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [workouts, exerciseRepository, availableTags]);

  const resetToPlan = useCallback(() => {
    localStorage.removeItem('workouts');
    localStorage.removeItem('exercise_repository');
    localStorage.removeItem('available_tags');
    setWorkouts(INITIAL_WORKOUTS);
    setExerciseRepository([]);
    setAvailableTags(PREDEFINED_TAGS);
    setView({ type: 'workouts' });
  }, []);

  const deleteWorkout = (id: string) => setWorkouts(prev => prev.filter(w => w.id !== id));

  const deleteExercise = useCallback((workoutId: string, exerciseId: string) => {
    if(!window.confirm('Remove from your workout?')) return;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? { 
        ...w, 
        exercises: w.exercises.filter(ex => ex.id !== exerciseId) 
    } : w));
  }, []);

  const deleteFromRepo = (id: string) => setExerciseRepository(prev => prev.filter(e => e.id !== id));

  const commitEntry = (workoutId: string, exerciseId: string, entry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: [entry, ...ex.entries] } : ex)
    } : w));
  };

  const updateEntry = (workoutId: string, exerciseId: string, updatedEntry: Entry) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => {
        if (ex.id === exerciseId) {
          return { ...ex, entries: ex.entries.map(e => (e.id === updatedEntry.id ? updatedEntry : e)) };
        }
        return ex;
      })
    } : w));
  };

  const deleteEntry = (workoutId: string, exerciseId: string, entryId: string) => {
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w, exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, entries: ex.entries.filter(e => e.id !== entryId) } : ex)
    } : w));
  };

  const handleSaveRepoExercise = () => {
    if (!repoModal.name.trim()) return;
    const { name, tags, notes, targetWorkoutId, isEditingInstance, workoutId, exerciseId } = repoModal;

    if (isEditingInstance && workoutId && exerciseId) {
        setWorkouts(prev => prev.map(w => w.id === workoutId ? { 
            ...w, 
            exercises: w.exercises.map(ex => ex.id === exerciseId ? { ...ex, name, tags, notes } : ex) 
        } : w));
        setRepoModal(null);
        return;
    }

    const newExId = Date.now().toString();
    const newRepoItem: RepoExercise = { id: newExId, name, tags, notes };
    setExerciseRepository(prev => [newRepoItem, ...prev]);

    if (targetWorkoutId) {
        setWorkouts(prev => prev.map(w => w.id === targetWorkoutId ? { 
            ...w, 
            exercises: [...w.exercises, { ...newRepoItem, entries: [] }] 
        } : w));
    }

    setRepoModal(null);
  };

  const addFromLibrary = (repoEx: RepoExercise) => {
    if (!repoModal?.targetWorkoutId) return;
    const workoutId = repoModal.targetWorkoutId;
    setWorkouts(prev => prev.map(w => w.id === workoutId ? {
      ...w,
      exercises: [...w.exercises, { ...repoEx, id: Date.now().toString(), entries: [] }]
    } : w));
    setRepoModal(null);
  };

  const toggleTag = (tag: string, targetModal: any, setModal: any) => {
    const currentTags = targetModal.tags || [];
    setModal({ ...targetModal, tags: currentTags.includes(tag) ? currentTags.filter((t: string) => t !== tag) : [...currentTags, tag] });
  };

  const addCustomTag = (e: React.FormEvent, targetModal: any, setModal: any) => {
    e.preventDefault();
    const tag = customTagInput.trim().toLowerCase();
    if (!tag || availableTags.includes(tag)) return;
    setAvailableTags(prev => [...prev, tag]);
    toggleTag(tag, targetModal, setModal);
    setCustomTagInput('');
  };

  const filteredLibrary = useMemo(() => {
    return exerciseRepository.filter(ex => ex.name.toLowerCase().includes(librarySearch.toLowerCase()));
  }, [exerciseRepository, librarySearch]);

  return (
    <div className="min-h-screen bg-slate-50">
      {view.type === 'workouts' && <WorkoutsView workouts={workouts} setView={setView} deleteWorkout={deleteWorkout} setIsAddingWorkout={setIsAddingWorkout} setMenuOpen={setIsMenuOpen} />}
      {view.type === 'workout-detail' && <WorkoutDetailView workoutId={view.workoutId} workouts={workouts} setView={setView} deleteExercise={deleteExercise} setRepoModal={setRepoModal} />}
      {view.type === 'exercise-detail' && <ExerciseDetailView workoutId={view.workoutId} exerciseId={view.exerciseId} workouts={workouts} setView={setView} commitEntry={commitEntry} updateEntry={updateEntry} deleteEntry={deleteEntry} setRepoModal={setRepoModal} />}
      {view.type === 'manage-exercises' && <ManageExercisesView repository={exerciseRepository} setView={setView} deleteFromRepo={deleteFromRepo} setRepoModal={setRepoModal} />}
      <MenuDrawer isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onNavigate={setView} onDownload={downloadData} onReset={resetToPlan} />

      {isAddingWorkout && (
        <Modal title="New Workout Day" onClose={() => setIsAddingWorkout(false)} onAction={() => { if(newWorkoutName) { setWorkouts([...workouts, {id: Date.now().toString(), name: newWorkoutName, exercises: []}]); setNewWorkoutName(''); setIsAddingWorkout(false); } }} actionLabel="Create">
          <input autoFocus type="text" value={newWorkoutName} onChange={(e) => setNewWorkoutName(e.target.value)} placeholder="e.g. Upper Body Power" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-bold focus:bg-white outline-none focus:ring-2 focus:ring-indigo-100" />
        </Modal>
      )}

      {repoModal && (
        <Modal 
            title={repoModal.isEditingInstance ? "Edit Exercise" : "Add Exercise"} 
            onClose={() => setRepoModal(null)} 
            onAction={handleSaveRepoExercise} 
            actionLabel={repoModal.isEditingInstance ? "Update" : "Add Move"}
            showAction={repoModal.activeTab === 'new'}
        >
          <div className="space-y-4">
            {/* Segmented Control */}
            {!repoModal.isEditingInstance && repoModal.targetWorkoutId && (
              <div className="flex bg-slate-100 p-1 rounded-2xl mb-2">
                <button 
                  onClick={() => setRepoModal({...repoModal, activeTab: 'new'})}
                  className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${repoModal.activeTab === 'new' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  New Movement
                </button>
                <button 
                  onClick={() => setRepoModal({...repoModal, activeTab: 'library'})}
                  className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${repoModal.activeTab === 'library' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  From Library
                </button>
              </div>
            )}

            {repoModal.activeTab === 'new' ? (
              <div className="space-y-4 animate-in">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Move Name</label>
                  <input autoFocus type="text" value={repoModal.name} onChange={(e) => setRepoModal({...repoModal, name: e.target.value})} placeholder="e.g. Bench Press" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-bold focus:bg-white outline-none focus:ring-2 focus:ring-indigo-100" />
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tags</label>
                  <div className="flex flex-wrap gap-2 pt-1">
                    {availableTags.map(tag => (
                      <button key={tag} onClick={() => toggleTag(tag, repoModal, setRepoModal)} className={`px-3 py-1.5 rounded-full text-xs font-bold border transition-all ${repoModal.tags.includes(tag) ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-slate-500 hover:bg-slate-50'}`}>{tag}</button>
                    ))}
                  </div>
                </div>

                <div className="flex items-center gap-2 p-3.5 bg-indigo-50 rounded-xl border border-indigo-100 shadow-sm">
                   <input type="checkbox" className="w-4 h-4 rounded border-indigo-300 text-indigo-600 focus:ring-indigo-500" checked={repoModal.tags.includes('anchor')} onChange={(e) => { const tags = e.target.checked ? [...repoModal.tags, 'anchor'] : repoModal.tags.filter((t:string) => t !== 'anchor'); setRepoModal({...repoModal, tags}); }} />
                   <span className="text-sm font-black text-indigo-700">Set as Anchor Exercise</span>
                </div>

                <form onSubmit={(e) => addCustomTag(e, repoModal, setRepoModal)} className="flex gap-2">
                    <input type="text" value={customTagInput} onChange={e => setCustomTagInput(e.target.value)} placeholder="Add custom tag..." className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5 text-xs outline-none focus:bg-white focus:ring-2 focus:ring-indigo-100 font-bold" />
                    <button type="submit" className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-100 transition-colors shadow-sm"><PlusIcon /></button>
                </form>

                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cues / Notes</label>
                  <textarea value={repoModal.notes} onChange={(e) => setRepoModal({...repoModal, notes: e.target.value})} placeholder="Optional tips for form..." className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 h-24 resize-none outline-none focus:bg-white focus:ring-2 focus:ring-indigo-100 font-bold" />
                </div>
              </div>
            ) : (
              <div className="space-y-4 animate-in">
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                        <SearchIcon />
                    </div>
                    <input 
                        type="text" 
                        placeholder="Search your library..." 
                        value={librarySearch}
                        onChange={(e) => setLibrarySearch(e.target.value)}
                        className="w-full pl-9 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-100 outline-none transition-all font-medium"
                    />
                </div>

                <div className="space-y-2 max-h-72 overflow-y-auto pr-1">
                  {filteredLibrary.map(ex => (
                    <button key={ex.id} onClick={() => addFromLibrary(ex)} className="w-full text-left p-4 bg-white border border-slate-100 hover:border-indigo-200 hover:bg-indigo-50/30 rounded-2xl transition-all group flex items-center justify-between">
                      <div>
                        <span className="font-bold text-slate-800 group-hover:text-indigo-700 transition-colors">{ex.name}</span>
                        <div className="flex flex-wrap gap-1 mt-1">
                          {(ex.tags || []).map(t => <span key={t} className="text-[8px] uppercase font-black text-slate-400">{t}</span>)}
                        </div>
                      </div>
                      <ChevronRightIcon />
                    </button>
                  ))}
                  {filteredLibrary.length === 0 && (
                    <div className="py-12 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                      <p className="text-xs text-slate-400 font-bold italic px-6">Empty library matches.</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </Modal>
      )}
    </div>
  );
};

export default App;
